    setAttributes,
    // Form data
    formData,
    setFormData,
    // UI states
    categoriesExpanded,
    setCategoriesExpanded,
    brandsExpanded,
    setBrandsExpanded,
    attributesDropdownOpen,
    setAttributesDropdownOpen,
    // Refs
    fileInputRef,
    variantImageInputRefs,
    attributesDropdownRef,
    // Image states
    colorImageTarget,
    setColorImageTarget,
    imageUploadLoading,
    setImageUploadLoading,
    imageUploadError,
    setImageUploadError,
    // New entity states
    newBrandName,
    setNewBrandName,
    newCategoryName,
    setNewCategoryName,
    useNewBrand,
    setUseNewBrand,
    useNewCategory,
    setUseNewCategory,
    // Color/Size management
    newColorName,
    setNewColorName,
    newSizeName,
    setNewSizeName,
    addingColor,
    setAddingColor,
    addingSize,
    setAddingSize,
    colorMessage,
    setColorMessage,
    sizeMessage,
    setSizeMessage,
    // Currency and product type
    defaultCurrency,
    setDefaultCurrency,
    productType,
    setProductType,
    simpleProductData,
    setSimpleProductData,
    // Variant builder states
    selectedAttributesForVariants,
    setSelectedAttributesForVariants,
    selectedAttributeValueIds,
    setSelectedAttributeValueIds,
    openValueModal,
    setOpenValueModal,
    generatedVariants,
    setGeneratedVariants,
    hasVariantsToLoad,
