'use client';

import { Card, Button, Input } from '@shop/ui';
import { useTranslation } from '../../../../lib/i18n-client';

interface GlobalDiscountCardProps {
  globalDiscount: number;
  setGlobalDiscount: (value: number) => void;
  discountLoading: boolean;
  discountSaving: boolean;
  handleDiscountSave: () => void;
}

export function GlobalDiscountCard({
  globalDiscount,
  setGlobalDiscount,
  discountLoading,
  discountSaving,
  handleDiscountSave,
}: GlobalDiscountCardProps) {
  const { t } = useTranslation();

  return (
    <div className="bg-white rounded-lg p-4 border border-gray-200">
      <div className="flex items-center gap-2 mb-3">
        <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center">
          <svg className="w-5 h-5 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
        </div>
        <div>
          <h3 className="text-lg font-semibold text-gray-900">{t('admin.quickSettings.globalDiscount')}</h3>
          <p className="text-xs text-gray-500">{t('admin.quickSettings.forAllProducts')}</p>
        </div>
      </div>

      {discountLoading ? (
        <div className="animate-pulse">
          <div className="h-10 bg-gray-200 rounded"></div>
        </div>
      ) : (
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <Input
              type="number"
              min="0"
              max="100"
              step="0.1"
              value={globalDiscount}
              onChange={(e) => {
                const value = e.target.value;
                setGlobalDiscount(value === '' ? 0 : parseFloat(value) || 0);
              }}
              className="flex-1"
              placeholder="0"
            />
            <span className="text-sm font-medium text-gray-700 w-8">%</span>
            <Button
              variant="primary"
              onClick={handleDiscountSave}
              disabled={discountSaving}
              className="px-6"
            >
              {discountSaving ? (
                <div className="flex items-center gap-2">
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                  <span>{t('admin.quickSettings.saving')}</span>
                </div>
              ) : (
                t('admin.quickSettings.save')
              )}
            </Button>
          </div>

          {globalDiscount > 0 ? (
            <div className="p-3 bg-green-50 border border-green-200 rounded-md">
              <p className="text-sm text-green-800">
                <strong>{t('admin.quickSettings.active')}</strong> {t('admin.quickSettings.discountApplied').replace('{percent}', globalDiscount.toString())}
              </p>
            </div>
          ) : (
            <div className="p-3 bg-gray-50 border border-gray-200 rounded-md">
              <p className="text-sm text-gray-600">
                {t('admin.quickSettings.noGlobalDiscount')}
              </p>
            </div>
          )}

          <div className="flex gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={() => setGlobalDiscount(10)}
              className="flex-1"
            >
              10%
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setGlobalDiscount(20)}
              className="flex-1"
            >
              20%
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setGlobalDiscount(30)}
              className="flex-1"
            >
              30%
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setGlobalDiscount(50)}
              className="flex-1"
            >
              50%
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setGlobalDiscount(0)}
              className="px-3"
            >
              {t('admin.quickSettings.cancel')}
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { Card, Button, Input } from '@shop/ui';
import { useTranslation } from '../../../../lib/i18n-client';

interface Product {
  id: string;
  title: string;
  image?: string;
  price?: number;
  discountPercent?: number;
}

interface ProductDiscountsCardProps {
  products: Product[];
  productsLoading: boolean;
  productDiscounts: Record<string, number>;
  setProductDiscounts: React.Dispatch<React.SetStateAction<Record<string, number>>>;
  handleProductDiscountSave: (productId: string) => void;
  savingProductId: string | null;
}

export function ProductDiscountsCard({
  products,
  productsLoading,
  productDiscounts,
  setProductDiscounts,
  handleProductDiscountSave,
  savingProductId,
}: ProductDiscountsCardProps) {
  const { t } = useTranslation();

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 0,
    }).format(price);
  };

  return (
    <Card className="p-6 bg-white border-gray-200">
      <div className="mb-6">
        <h2 className="text-xl font-semibold text-gray-900 mb-2">{t('admin.quickSettings.productDiscounts')}</h2>
        <p className="text-sm text-gray-600">{t('admin.quickSettings.productDiscountsSubtitle')}</p>
      </div>

      {productsLoading ? (
        <div className="text-center py-8">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto mb-4"></div>
          <p className="text-gray-600">{t('admin.quickSettings.loadingProducts')}</p>
        </div>
      ) : products.length === 0 ? (
        <div className="text-center py-8">
          <p className="text-gray-600">{t('admin.quickSettings.noProducts')}</p>
        </div>
      ) : (
        <div className="space-y-4">
          {products.map((product) => {
            const currentDiscount = Number(productDiscounts[product.id] ?? product.discountPercent ?? 0);
            const originalPrice = product.price || 0;
            const discountedPrice = currentDiscount > 0 && originalPrice > 0
              ? Math.round(originalPrice * (1 - currentDiscount / 100))
              : originalPrice;

            return (
              <div
                key={product.id}
                className="flex items-center gap-4 p-4 border-2 border-blue-300 rounded-lg hover:bg-blue-50 transition-colors bg-blue-50/30"
              >
                {product.image && (
                  <div className="flex-shrink-0">
                    <img
                      src={product.image}
                      alt={product.title}
                      className="w-16 h-16 object-cover rounded"
                    />
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <h3 className="text-sm font-medium text-gray-900 truncate">{product.title}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    {currentDiscount > 0 && originalPrice > 0 ? (
                      <>
                        <span className="text-xs font-semibold text-blue-600 select-none">
                          {formatPrice(discountedPrice)}
                        </span>
                        <span className="text-xs text-gray-400 line-through select-none">
                          {formatPrice(originalPrice)}
                        </span>
                        <span className="text-xs text-red-600 font-medium">
                          -{currentDiscount}%
                        </span>
                      </>
                    ) : (
                      <span className="text-xs text-gray-500 select-none">
                        {originalPrice > 0 ? formatPrice(originalPrice) : 'N/A'}
                      </span>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Input
                    type="number"
                    min="0"
                    max="100"
                    step="0.1"
                    value={productDiscounts[product.id] ?? product.discountPercent ?? 0}
                    onChange={(e) => {
                      const value = e.target.value;
                      const discountValue = value === '' ? 0 : parseFloat(value) || 0;
                      console.log(`🔄 [QUICK SETTINGS] Updating discount for product ${product.id}: ${discountValue}%`);
                      setProductDiscounts((prev) => {
                        const updated = {
                          ...prev,
                          [product.id]: discountValue,
                        };
                        console.log(`✅ [QUICK SETTINGS] Updated productDiscounts:`, updated);
                        return updated;
                      });
                    }}
                    className="w-20"
                    placeholder="0"
                  />
                  <span className="text-sm font-medium text-gray-700 w-6">%</span>
                  <Button
                    variant="primary"
                    size="sm"
                    onClick={() => handleProductDiscountSave(product.id)}
                    disabled={savingProductId === product.id}
                    className="px-4"
                  >
                    {savingProductId === product.id ? (
                      <div className="flex items-center gap-2">
                        <div className="animate-spin rounded-full h-3 w-3 border-b-2 border-white"></div>
                      </div>
                    ) : (
                      t('admin.quickSettings.save')
                    )}
                  </Button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </Card>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { useAuth } from '../../../lib/auth/AuthContext';
import { apiClient } from '../../../lib/api-client';
import { useTranslation } from '../../../lib/i18n-client';
import { QuickSettingsContent } from './QuickSettingsContent';
import { getClientErrorMessage } from '../../../lib/types/errors';

interface AdminSettingsResponse {
  globalDiscount: number;
  categoryDiscounts?: Record<string, number>;
  brandDiscounts?: Record<string, number>;
}

interface AdminCategory {
  id: string;
  title: string;
  parentId: string | null;
}

interface AdminBrand {
  id: string;
  name: string;
  logoUrl?: string;
}

/** Minimal product row from admin list API (quick-settings discount UI). */
interface AdminProductListItem {
  id: string;
  title: string;
  image?: string;
  price?: number;
  discountPercent?: number;
}

interface AdminProductsPageResponse {
  data: AdminProductListItem[];
  meta?: { totalPages: number; total: number };
}

export default function QuickSettingsPage() {
  const { t } = useTranslation();
  const { isLoggedIn, isAdmin, isLoading } = useAuth();
  const router = useRouter();
  const pathname = usePathname();
  const [globalDiscount, setGlobalDiscount] = useState<number>(0);
  const [discountLoading, setDiscountLoading] = useState(false);
  const [discountSaving, setDiscountSaving] = useState(false);
  const [products, setProducts] = useState<AdminProductListItem[]>([]);
  const [productsLoading, setProductsLoading] = useState(false);
  const [productDiscounts, setProductDiscounts] = useState<Record<string, number>>({});
  const [savingProductId, setSavingProductId] = useState<string | null>(null);
  const [categoryDiscounts, setCategoryDiscounts] = useState<Record<string, number>>({});
  const [brandDiscounts, setBrandDiscounts] = useState<Record<string, number>>({});
  const [categories, setCategories] = useState<AdminCategory[]>([]);
  const [brands, setBrands] = useState<AdminBrand[]>([]);
  const [categoriesLoading, setCategoriesLoading] = useState(false);
  const [brandsLoading, setBrandsLoading] = useState(false);
  const [categorySaving, setCategorySaving] = useState(false);
  const [brandSaving, setBrandSaving] = useState(false);

  const fetchSettings = useCallback(async () => {
    try {
      console.log('⚙️ [QUICK SETTINGS] Fetching settings...');
      setDiscountLoading(true);
      const settings = await apiClient.get<AdminSettingsResponse>('/api/v1/supersudo/settings');
      setGlobalDiscount(settings.globalDiscount || 0);
      setCategoryDiscounts(settings.categoryDiscounts || {});
      setBrandDiscounts(settings.brandDiscounts || {});
      console.log('✅ [QUICK SETTINGS] Settings loaded:', settings);
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error fetching settings:', err);
      setGlobalDiscount(0);
    } finally {
      setDiscountLoading(false);
    }
  }, []);

  const fetchProducts = useCallback(async () => {
    try {
      console.log('📦 [QUICK SETTINGS] Fetching products...');
      setProductsLoading(true);
      
      // Սկզբում բեռնում ենք առաջին էջը limit=100-ով (առավելագույն արժեք)
      const firstPageResponse = await apiClient.get<AdminProductsPageResponse>('/api/v1/supersudo/products', {
        params: { page: '1', limit: '100' },
      });
      
      let allProducts: AdminProductListItem[] = [];
      
      if (firstPageResponse?.data && Array.isArray(firstPageResponse.data)) {
        allProducts = [...firstPageResponse.data];
        console.log('📦 [QUICK SETTINGS] First page loaded:', firstPageResponse.data.length);
        
        // Եթե կան ավելի շատ էջեր, բեռնում ենք մնացածները
        const totalPages = firstPageResponse.meta?.totalPages || 1;
        if (totalPages > 1) {
          console.log(`📦 [QUICK SETTINGS] Loading ${totalPages - 1} more pages...`);
          
          // Ստեղծում ենք բոլոր էջերի հարցումները
          const pagePromises: Promise<AdminProductsPageResponse>[] = [];
          for (let page = 2; page <= totalPages; page++) {
            pagePromises.push(
              apiClient.get<AdminProductsPageResponse>('/api/v1/supersudo/products', {
                params: { page: page.toString(), limit: '100' },
              })
            );
          }
          
          // Բեռնում ենք բոլոր էջերը զուգահեռ
          const remainingPages = await Promise.all(pagePromises);
          remainingPages.forEach((pageResponse, index) => {
            if (pageResponse?.data && Array.isArray(pageResponse.data)) {
              allProducts = [...allProducts, ...pageResponse.data];
              console.log(`📦 [QUICK SETTINGS] Page ${index + 2} loaded:`, pageResponse.data.length);
            }
          });
        }
        
        // Սահմանում ենք բոլոր ապրանքները
        setProducts(allProducts);
        
        // Նախաձեռնում ենք ապրանքների զեղչերը API տվյալներից
        const discounts: Record<string, number> = {};
        allProducts.forEach((product) => {
          discounts[product.id] = product.discountPercent || 0;
        });
        setProductDiscounts(discounts);
        
        console.log('✅ [QUICK SETTINGS] All products loaded:', allProducts.length);
      } else {
        setProducts([]);
        console.warn('⚠️ [QUICK SETTINGS] No products data received');
      }
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error fetching products:', err);
      setProducts([]);
    } finally {
      setProductsLoading(false);
    }
  }, []);

  const fetchCategories = useCallback(async () => {
    try {
      console.log('📂 [QUICK SETTINGS] Fetching categories...');
      setCategoriesLoading(true);
      const response = await apiClient.get<{ data: AdminCategory[] }>('/api/v1/supersudo/categories');
      if (response?.data && Array.isArray(response.data)) {
        setCategories(response.data);
        console.log('✅ [QUICK SETTINGS] Categories loaded:', response.data.length);
      } else {
        setCategories([]);
      }
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error fetching categories:', err);
      setCategories([]);
    } finally {
      setCategoriesLoading(false);
    }
  }, []);

  const fetchBrands = useCallback(async () => {
    try {
      console.log('🏷️ [QUICK SETTINGS] Fetching brands...');
      setBrandsLoading(true);
      const response = await apiClient.get<{ data: AdminBrand[] }>('/api/v1/supersudo/brands');
      if (response?.data && Array.isArray(response.data)) {
        setBrands(response.data);
        console.log('✅ [QUICK SETTINGS] Brands loaded:', response.data.length);
      } else {
        setBrands([]);
      }
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error fetching brands:', err);
      setBrands([]);
    } finally {
      setBrandsLoading(false);
    }
  }, []);

  const clampDiscountValue = (value: number) => {
    if (isNaN(value)) {
      return 0;
    }
    return Math.min(100, Math.max(0, Math.round(value * 100) / 100));
  };

  const updateCategoryDiscountValue = (categoryId: string, value: string) => {
    if (value === '') {
      setCategoryDiscounts((prev) => {
        const updated = { ...prev };
        delete updated[categoryId];
        return updated;
      });
      return;
    }
    const numericValue = clampDiscountValue(parseFloat(value));
    setCategoryDiscounts((prev) => ({
      ...prev,
      [categoryId]: numericValue,
    }));
  };

  const updateBrandDiscountValue = (brandId: string, value: string) => {
    if (value === '') {
      setBrandDiscounts((prev) => {
        const updated = { ...prev };
        delete updated[brandId];
        return updated;
      });
      return;
    }
    const numericValue = clampDiscountValue(parseFloat(value));
    setBrandDiscounts((prev) => ({
      ...prev,
      [brandId]: numericValue,
    }));
  };

  const clearCategoryDiscount = (categoryId: string) => {
    setCategoryDiscounts((prev) => {
      const updated = { ...prev };
      delete updated[categoryId];
      return updated;
    });
  };

  const clearBrandDiscount = (brandId: string) => {
    setBrandDiscounts((prev) => {
      const updated = { ...prev };
      delete updated[brandId];
      return updated;
    });
  };

  const buildDiscountPayload = () => {
    const filterMap = (map: Record<string, number>) =>
      Object.entries(map || {}).reduce<Record<string, number>>((acc, [id, value]) => {
        if (typeof value === 'number' && value > 0) {
          acc[id] = clampDiscountValue(value);
        }
        return acc;
      }, {});

    return {
      categoryDiscounts: filterMap(categoryDiscounts),
      brandDiscounts: filterMap(brandDiscounts),
    };
  };

  const handleDiscountSave = async () => {
    const discountValue = parseFloat(globalDiscount.toString());
    if (isNaN(discountValue) || discountValue < 0 || discountValue > 100) {
      alert(t('admin.quickSettings.discountMustBeValid'));
      return;
    }

    setDiscountSaving(true);
    try {
      console.log('⚙️ [QUICK SETTINGS] Saving global discount...', discountValue);
      await apiClient.put('/api/v1/supersudo/settings', {
        globalDiscount: discountValue,
        ...buildDiscountPayload(),
      });
      
      // Refresh products to get updated labels with new discount percentage
      await fetchProducts();
      
      alert(t('admin.quickSettings.savedSuccess'));
      console.log('✅ [QUICK SETTINGS] Global discount saved');
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error saving discount:', err);
      const errorMessage = getClientErrorMessage(err) || 'Failed to save';
      alert(t('admin.quickSettings.errorSaving').replace('{message}', errorMessage));
    } finally {
      setDiscountSaving(false);
    }
  };

  const handleCategoryDiscountSave = async () => {
    setCategorySaving(true);
    try {
      console.log('⚙️ [QUICK SETTINGS] Saving category discounts...');
      await apiClient.put('/api/v1/supersudo/settings', {
        globalDiscount,
        ...buildDiscountPayload(),
      });
      await fetchProducts();
      alert(t('admin.quickSettings.savedSuccess'));
      console.log('✅ [QUICK SETTINGS] Category discounts saved');
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error saving category discounts:', err);
      const errorMessage = getClientErrorMessage(err) || 'Failed to save';
      alert(t('admin.quickSettings.errorSaving').replace('{message}', errorMessage));
    } finally {
      setCategorySaving(false);
    }
  };

  const handleBrandDiscountSave = async () => {
    setBrandSaving(true);
    try {
      console.log('⚙️ [QUICK SETTINGS] Saving brand discounts...');
      await apiClient.put('/api/v1/supersudo/settings', {
        globalDiscount,
        ...buildDiscountPayload(),
      });
      await fetchProducts();
      alert(t('admin.quickSettings.savedSuccess'));
      console.log('✅ [QUICK SETTINGS] Brand discounts saved');
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error saving brand discounts:', err);
      const errorMessage = getClientErrorMessage(err) || 'Failed to save';
      alert(t('admin.quickSettings.errorSaving').replace('{message}', errorMessage));
    } finally {
      setBrandSaving(false);
    }
  };

  const handleProductDiscountSave = async (productId: string) => {
    const discountValue = productDiscounts[productId] || 0;
    if (isNaN(discountValue) || discountValue < 0 || discountValue > 100) {
      alert(t('admin.quickSettings.discountMustBeValid'));
      return;
    }

    setSavingProductId(productId);
    try {
      console.log('⚙️ [QUICK SETTINGS] Saving product discount only...', productId, discountValue);
      
      // Используем специальный endpoint, который обновляет только discountPercent
      // Это гарантирует, что все остальные поля (media, variants, price и т.д.) останутся без изменений
      const updateData = {
        discountPercent: discountValue,
      };
      
      console.log('📤 [QUICK SETTINGS] Sending update data to discount endpoint:', updateData);
      
      await apiClient.patch(`/api/v1/supersudo/products/${productId}/discount`, updateData);
      
      // Refresh products to get updated labels with new discount percentage
      await fetchProducts();
      
      alert(t('admin.quickSettings.productDiscountSaved'));
      console.log('✅ [QUICK SETTINGS] Product discount saved');
    } catch (err: unknown) {
      console.error('❌ [QUICK SETTINGS] Error saving product discount:', err);
      const errorMessage = getClientErrorMessage(err) || 'Failed to save';
      alert(t('admin.quickSettings.errorSavingProduct').replace('{message}', errorMessage));
    } finally {
      setSavingProductId(null);
    }
  };

  useEffect(() => {
    if (!isLoading && isLoggedIn && isAdmin) {
      fetchSettings();
      fetchProducts();
      fetchCategories();
      fetchBrands();
    }
  }, [isLoading, isLoggedIn, isAdmin, fetchSettings, fetchProducts, fetchCategories, fetchBrands]);

  useEffect(() => {
    if (!isLoading) {
      if (!isLoggedIn) {
        console.log('❌ [QUICK SETTINGS] User not logged in, redirecting to login...');
        router.push('/login');
        return;
      }
      if (!isAdmin) {
        console.log('❌ [QUICK SETTINGS] User is not admin, redirecting to home...');
        router.push('/');
        return;
      }
    }
  }, [isLoggedIn, isAdmin, isLoading, router]);

  // Get current path to highlight active tab
  const [currentPath, setCurrentPath] = useState(pathname || '/supersudo/quick-settings');
  
  useEffect(() => {
    if (pathname) {
      setCurrentPath(pathname);
    }
  }, [pathname]);

  if (isLoading) {
  return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-900 mx-auto mb-4"></div>
          <p className="text-gray-600">{t('admin.common.loading')}</p>
        </div>
      </div>
    );
  }

  if (!isLoggedIn || !isAdmin) {
    return null; // Will redirect
  }

  return (
    <QuickSettingsContent
      currentPath={currentPath}
      router={router}
      t={t}
      globalDiscount={globalDiscount}
      setGlobalDiscount={setGlobalDiscount}
      discountLoading={discountLoading}
      discountSaving={discountSaving}
      handleDiscountSave={handleDiscountSave}
      categories={categories}
      categoriesLoading={categoriesLoading}
      categoryDiscounts={categoryDiscounts}
      updateCategoryDiscountValue={updateCategoryDiscountValue}
      clearCategoryDiscount={clearCategoryDiscount}
      handleCategoryDiscountSave={handleCategoryDiscountSave}
      categorySaving={categorySaving}
      brands={brands}
      brandsLoading={brandsLoading}
      brandDiscounts={brandDiscounts}
      updateBrandDiscountValue={updateBrandDiscountValue}
      clearBrandDiscount={clearBrandDiscount}
      handleBrandDiscountSave={handleBrandDiscountSave}
      brandSaving={brandSaving}
      products={products}
      productsLoading={productsLoading}
      productDiscounts={productDiscounts}
      setProductDiscounts={setProductDiscounts}
      handleProductDiscountSave={handleProductDiscountSave}
      savingProductId={savingProductId}
    />
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../../lib/auth/AuthContext';
import { Card, Button } from '@shop/ui';
import { apiClient } from '../../../lib/api-client';
import { useTranslation } from '../../../lib/i18n-client';
import { clearCurrencyRatesCache } from '../../../lib/currency';
import { getClientErrorMessage } from '../../../lib/types/errors';

interface Settings {
  defaultCurrency?: string;
  globalDiscount?: number;
  categoryDiscounts?: Record<string, number>;
  brandDiscounts?: Record<string, number>;
  /** Values may be undefined while the user clears an input before blur applies a default. */
  currencyRates?: Record<string, number | undefined>;
}

export default function SettingsPage() {
  const { t } = useTranslation();
  const { isLoggedIn, isAdmin, isLoading } = useAuth();
  const router = useRouter();
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [settings, setSettings] = useState<Settings>({
    defaultCurrency: 'AMD',
    currencyRates: {
      USD: 1,
      AMD: 400,
      EUR: 0.92,
      RUB: 90,
      GEL: 2.7,
    },
  });

  useEffect(() => {
    if (!isLoading) {
      if (!isLoggedIn || !isAdmin) {
        router.push('/supersudo');
        return;
      }
    }
  }, [isLoggedIn, isAdmin, isLoading, router]);

  useEffect(() => {
    if (isLoggedIn && isAdmin) {
      fetchSettings();
    }
  }, [isLoggedIn, isAdmin]);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      console.log('⚙️ [ADMIN] Fetching settings...');
      const data = await apiClient.get<Settings>('/api/v1/supersudo/settings');
      setSettings({
        defaultCurrency: data.defaultCurrency || 'AMD',
        globalDiscount: data.globalDiscount,
        categoryDiscounts: data.categoryDiscounts,
        brandDiscounts: data.brandDiscounts,
        currencyRates: data.currencyRates || {
          USD: 1,
          AMD: 400,
          EUR: 0.92,
          RUB: 90,
          GEL: 2.7,
        },
      });
      console.log('✅ [ADMIN] Settings loaded:', data);
    } catch (err: unknown) {
      console.error('❌ [ADMIN] Error fetching settings:', err);
      // Use defaults if error
      setSettings({
        defaultCurrency: 'AMD',
        currencyRates: {
          USD: 1,
          AMD: 400,
          EUR: 0.92,
          RUB: 90,
          GEL: 2.7,
        },
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      console.log('⚙️ [ADMIN] Saving settings...', settings);

      // Ensure all currency rates have valid values before saving
      const currencyRatesToSave = {
        USD: 1,
        AMD: settings.currencyRates?.AMD ?? 400,
        EUR: settings.currencyRates?.EUR ?? 0.92,
        RUB: settings.currencyRates?.RUB ?? 90,
        GEL: settings.currencyRates?.GEL ?? 2.7,
      };

      await apiClient.put('/api/v1/supersudo/settings', {
        defaultCurrency: settings.defaultCurrency,
        currencyRates: currencyRatesToSave,
      });
      
      // Clear currency rates cache to force reload
      console.log('🔄 [ADMIN] Clearing currency rates cache...');
      clearCurrencyRatesCache();
      
      // Wait a bit to ensure cache is cleared, then dispatch event again
      setTimeout(() => {
        if (typeof window !== 'undefined') {
          console.log('🔄 [ADMIN] Dispatching currency-rates-updated event...');
          window.dispatchEvent(new Event('currency-rates-updated'));
        }
      }, 100);
      
      alert(t('admin.settings.savedSuccess'));
      console.log('✅ [ADMIN] Settings saved, currency rates:', currencyRatesToSave);
    } catch (err: unknown) {
      console.error('❌ [ADMIN] Error saving settings:', err);
      const errorMessage = getClientErrorMessage(err) || 'Failed to save settings';
      alert(t('admin.settings.errorSaving').replace('{message}', errorMessage));
    } finally {
      setSaving(false);
    }
  };

  if (isLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-900 mx-auto mb-4"></div>
          <p className="text-gray-600">{t('admin.common.loading')}</p>
        </div>
      </div>
    );
  }

  if (!isLoggedIn || !isAdmin) {
    return null;
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8">
          <button
            onClick={() => router.push('/supersudo')}
            className="text-gray-600 hover:text-gray-900 mb-4 flex items-center"
          >
            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            {t('admin.settings.backToAdmin')}
          </button>
          <h1 className="text-3xl font-bold text-gray-900">{t('admin.settings.title')}</h1>
        </div>

        {/* General Settings */}
        <Card className="p-6 mb-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('admin.settings.generalSettings')}</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                {t('admin.settings.siteName')}
              </label>
              <input
                type="text"
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                defaultValue={t('admin.settings.siteNamePlaceholder')}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                {t('admin.settings.siteDescription')}
              </label>
              <textarea
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                rows={3}
                defaultValue={t('admin.settings.siteDescriptionPlaceholder')}
              />
            </div>
          </div>
        </Card>

        {/* Payment Settings */}
        <Card className="p-6 mb-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('admin.settings.paymentSettings')}</h2>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                {t('admin.settings.defaultCurrency')}
              </label>
              <select 
                value={settings.defaultCurrency || 'AMD'}
                onChange={(e) => setSettings({ ...settings, defaultCurrency: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="AMD">{t('admin.settings.amd')}</option>
                <option value="USD">{t('admin.settings.usd')}</option>
                <option value="EUR">{t('admin.settings.eur')}</option>
              </select>
            </div>
            <div>
              <label className="flex items-center">
                <input
                  type="checkbox"
                  defaultChecked
                  className="mr-2"
                />
                <span className="text-sm font-medium text-gray-700">{t('admin.settings.enableOnlinePayments')}</span>
              </label>
            </div>
          </div>
        </Card>

        {/* Currency Exchange Rates */}
        <Card className="p-6 mb-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{t('admin.settings.currencyRates')}</h2>
          <p className="text-sm text-gray-600 mb-4">{t('admin.settings.currencyRatesDescription')}</p>
          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  USD (US Dollar)
                </label>
                <input
                  type="number"
                  step="0.01"
                  value={settings.currencyRates?.USD || 1}
                  onChange={(e) => setSettings({
                    ...settings,
                    currencyRates: {
                      ...settings.currencyRates,
                      USD: parseFloat(e.target.value) || 1,
                    },
                  })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  disabled
                />
                <p className="text-xs text-gray-500 mt-1">{t('admin.settings.baseCurrency')}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  AMD (Armenian Dram)
                </label>
                <input
                  type="number"
                  step="0.01"
                  value={settings.currencyRates?.AMD ?? ''}
                  onChange={(e) => {
                    const inputValue = e.target.value;
                    if (inputValue === '') {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          AMD: undefined,
                        },
                      });
                    } else {
                      const numValue = parseFloat(inputValue);
                      if (!isNaN(numValue) && numValue > 0) {
                        setSettings({
                          ...settings,
                          currencyRates: {
                            ...settings.currencyRates,
                            AMD: numValue,
                          },
                        });
                      }
                    }
                  }}
                  onBlur={(e) => {
                    if (e.target.value === '' && settings.currencyRates?.AMD === undefined) {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          AMD: 400,
                        },
                      });
                    }
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="400"
                />
                <p className="text-xs text-gray-500 mt-1">{t('admin.settings.rateToUSD')}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  EUR (Euro)
                </label>
                <input
                  type="number"
                  step="0.01"
                  value={settings.currencyRates?.EUR ?? ''}
                  onChange={(e) => {
                    const inputValue = e.target.value;
                    if (inputValue === '') {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          EUR: undefined,
                        },
                      });
                    } else {
                      const numValue = parseFloat(inputValue);
                      if (!isNaN(numValue) && numValue > 0) {
                        setSettings({
                          ...settings,
                          currencyRates: {
                            ...settings.currencyRates,
                            EUR: numValue,
                          },
                        });
                      }
                    }
                  }}
                  onBlur={(e) => {
                    if (e.target.value === '' && settings.currencyRates?.EUR === undefined) {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          EUR: 0.92,
                        },
                      });
                    }
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="0.92"
                />
                <p className="text-xs text-gray-500 mt-1">{t('admin.settings.rateToUSD')}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  RUB (Russian Ruble)
                </label>
                <input
                  type="number"
                  step="0.01"
                  value={settings.currencyRates?.RUB ?? ''}
                  onChange={(e) => {
                    const inputValue = e.target.value;
                    if (inputValue === '') {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          RUB: undefined,
                        },
                      });
                    } else {
                      const numValue = parseFloat(inputValue);
                      if (!isNaN(numValue) && numValue > 0) {
                        setSettings({
                          ...settings,
                          currencyRates: {
                            ...settings.currencyRates,
                            RUB: numValue,
                          },
                        });
                      }
                    }
                  }}
                  onBlur={(e) => {
                    if (e.target.value === '' && settings.currencyRates?.RUB === undefined) {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          RUB: 90,
                        },
                      });
                    }
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="90"
                />
                <p className="text-xs text-gray-500 mt-1">{t('admin.settings.rateToUSD')}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  GEL (Georgian Lari)
                </label>
                <input
                  type="number"
                  step="0.01"
                  value={settings.currencyRates?.GEL ?? ''}
                  onChange={(e) => {
                    const inputValue = e.target.value;
                    if (inputValue === '') {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          GEL: undefined,
                        },
                      });
                    } else {
                      const numValue = parseFloat(inputValue);
                      if (!isNaN(numValue) && numValue > 0) {
                        setSettings({
                          ...settings,
                          currencyRates: {
                            ...settings.currencyRates,
                            GEL: numValue,
                          },
                        });
                      }
                    }
                  }}
                  onBlur={(e) => {
                    if (e.target.value === '' && settings.currencyRates?.GEL === undefined) {
                      setSettings({
                        ...settings,
                        currencyRates: {
                          ...settings.currencyRates,
                          GEL: 2.7,
                        },
                      });
                    }
                  }}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="2.7"
                />
                <p className="text-xs text-gray-500 mt-1">{t('admin.settings.rateToUSD')}</p>
              </div>
            </div>
          </div>
        </Card>

        {/* Actions */}
        <div className="flex gap-4">
          <Button
            variant="primary"
            onClick={handleSave}
            disabled={saving}
          >
            {saving ? t('admin.settings.saving') : t('admin.settings.saveSettings')}
          </Button>
          <Button
            variant="ghost"
            onClick={() => router.push('/supersudo')}
            disabled={saving}
          >
            {t('admin.settings.cancel')}
          </Button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../../lib/auth/AuthContext';
import { Card, Button, Input } from '@shop/ui';
import { apiClient } from '../../../lib/api-client';
import { useTranslation } from '../../../lib/i18n-client';
import { getErrorMessage } from '../../../lib/types/errors';

interface User {
  id: string;
  email: string;
  phone: string;
  firstName: string;
  lastName: string;
  roles: string[];
  blocked: boolean;
  ordersCount?: number;
  createdAt: string;
}

interface UsersResponse {
  data: User[];
  meta: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  };
}

export default function UsersPage() {
  const { t } = useTranslation();
  const { isLoggedIn, isAdmin, isLoading } = useAuth();
  const router = useRouter();
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [meta, setMeta] = useState<UsersResponse['meta'] | null>(null);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [bulkDeleting, setBulkDeleting] = useState(false);
  const [roleFilter, setRoleFilter] = useState<'all' | 'admin' | 'customer'>('all');

  useEffect(() => {
    if (!isLoading) {
      if (!isLoggedIn || !isAdmin) {
        router.push('/supersudo');
        return;
      }
    }
  }, [isLoggedIn, isAdmin, isLoading, router]);

  const fetchUsers = useCallback(async () => {
    try {
      setLoading(true);
      console.log('👥 [ADMIN] Fetching users...', { page, search, roleFilter });
      
      const response = await apiClient.get<UsersResponse>('/api/v1/supersudo/users', {
        params: {
          page: page.toString(),
          limit: '20',
          search: search || '',
          role: roleFilter === 'all' ? '' : roleFilter,
        },
      });

      console.log('✅ [ADMIN] Users fetched:', response);
      setUsers(response.data || []);
      setMeta(response.meta || null);
    } catch (err) {
      console.error('❌ [ADMIN] Error fetching users:', err);
    } finally {
      setLoading(false);
    }
  }, [page, search, roleFilter]);

  useEffect(() => {
    if (isLoggedIn && isAdmin) {
      fetchUsers();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoggedIn, isAdmin, page, search, roleFilter]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setPage(1);
    fetchUsers();
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleSelectAll = () => {
    // Ընտրում ենք միայն այն օգտատերերին, որոնք տեսանելի են ընթացիկ ֆիլտրով
    const visibleUsers =
      roleFilter === 'all'
        ? users
        : users.filter((u) =>
            roleFilter === 'admin'
              ? u.roles?.includes('admin')
              : u.roles?.includes('customer')
          );

    if (visibleUsers.length === 0) return;

    setSelectedIds((prev) => {
      const allIds = visibleUsers.map((u) => u.id);
      const hasAll = allIds.every((id) => prev.has(id));
      return hasAll ? new Set() : new Set(allIds);
    });
  };

  const handleBulkDelete = async () => {
    if (selectedIds.size === 0) return;
    if (!confirm(t('admin.users.deleteConfirm').replace('{count}', selectedIds.size.toString()))) return;
    setBulkDeleting(true);
    try {
      const ids = Array.from(selectedIds);
      const results = await Promise.allSettled(
        ids.map(id => apiClient.delete(`/api/v1/supersudo/users/${id}`))
      );
      const failed = results.filter(r => r.status === 'rejected');
      setSelectedIds(new Set());
      await fetchUsers();
      alert(t('admin.users.bulkDeleteFinished').replace('{success}', (ids.length - failed.length).toString()).replace('{total}', ids.length.toString()));
    } catch (err) {
      console.error('❌ [ADMIN] Bulk delete users error:', err);
      alert(t('admin.users.failedToDelete'));
    } finally {
      setBulkDeleting(false);
    }
  };

  const handleToggleBlocked = async (userId: string, currentStatus: boolean, userName: string) => {
    try {
      const newStatus = !currentStatus;
      await apiClient.put(`/api/v1/supersudo/users/${userId}`, {
        blocked: newStatus,
      });
      
      console.log(`✅ [ADMIN] User ${newStatus ? 'blocked' : 'unblocked'} successfully`);
      
      // Refresh users list
      fetchUsers();
      
      if (newStatus) {
        alert(t('admin.users.userBlocked').replace('{name}', userName));
      } else {
        alert(t('admin.users.userActive').replace('{name}', userName));
      }
    } catch (err: unknown) {
      console.error('❌ [ADMIN] Error updating user status:', err);
      alert(t('admin.users.errorUpdatingStatus').replace('{message}', getErrorMessage(err) || t('admin.common.unknownErrorFallback')));
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-900 mx-auto mb-4"></div>
          <p className="text-gray-600">{t('admin.common.loading')}</p>
        </div>
      </div>
    );
  }

  if (!isLoggedIn || !isAdmin) {
    return null;
  }

  // Տեսանելի օգտատերերի filter Admin / Customer ֆիլտրով
  const filteredUsers =
    roleFilter === 'all'
      ? users
      : users.filter((user) =>
          roleFilter === 'admin'
            ? user.roles?.includes('admin')
            : user.roles?.includes('customer')
        );

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8">
          <button
            onClick={() => router.push('/supersudo')}
            className="text-gray-600 hover:text-gray-900 mb-4 flex items-center"
          >
            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            {t('admin.users.backToAdmin')}
          </button>
          <h1 className="text-3xl font-bold text-gray-900">{t('admin.users.title')}</h1>
        </div>

        {/* Search */}
        <Card className="p-4 mb-6">
          <form onSubmit={handleSearch} className="flex flex-col gap-4">
            <div className="flex gap-4">
              <Input
                type="text"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder={t('admin.users.searchPlaceholder')}
                className="flex-1"
              />
              <Button type="submit" variant="primary">
                {t('admin.users.search')}
              </Button>
            </div>

            {/* Admin / Customer filter */}
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                {t('admin.users.adminCustomer')}
              </span>
              <div className="inline-flex rounded-full bg-gray-100 p-1 text-xs">
                <button
                  type="button"
                  onClick={() => {
                    setRoleFilter('all');
                    setPage(1);
                    console.log('👥 [ADMIN] Role filter changed to: all');
                  }}
                  className={`px-3 py-1 rounded-full transition-all ${
                    roleFilter === 'all'
                      ? 'bg-white text-gray-900 shadow-sm'
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  {t('admin.users.all')}
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setRoleFilter('admin');
                    setPage(1);
                    console.log('👥 [ADMIN] Role filter changed to: admin');
                  }}
                  className={`px-3 py-1 rounded-full transition-all ${
                    roleFilter === 'admin'
                      ? 'bg-white text-gray-900 shadow-sm'
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  {t('admin.users.admins')}
                </button>
                <button
                  type="button"
                  onClick={() => {
                    setRoleFilter('customer');
                    setPage(1);
                    console.log('👥 [ADMIN] Role filter changed to: customer');
                  }}
                  className={`px-3 py-1 rounded-full transition-all ${
                    roleFilter === 'customer'
                      ? 'bg-white text-gray-900 shadow-sm'
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  {t('admin.users.customers')}
                </button>
              </div>
            </div>
          </form>
        </Card>

        {/* Users Table */}
        <Card className="p-6">
          {loading ? (
            <div className="text-center py-8">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto mb-4"></div>
              <p className="text-gray-600">{t('admin.users.loadingUsers')}</p>
            </div>
          ) : filteredUsers.length === 0 ? (
            <div className="text-center py-8">
              <p className="text-gray-600">{t('admin.users.noUsers')}</p>
            </div>
          ) : (
            <>
              <div className="overflow-x-auto">
