                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.user')}
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.contact')}
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.orders')}
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.roles')}
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.status')}
                      </th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                        {t('admin.users.created')}
                      </th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {filteredUsers.map((user) => (
                      <tr key={user.id} className="hover:bg-gray-50">
                        <td className="px-4 py-4">
                          <input
                            type="checkbox"
                            aria-label={t('admin.users.selectUser').replace('{email}', user.email)}
                            checked={selectedIds.has(user.id)}
                            onChange={() => toggleSelect(user.id)}
                          />
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm font-medium text-gray-900">
                            {user.firstName} {user.lastName}
                          </div>
                          <div className="text-sm text-gray-500">{user.id}</div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm text-gray-900">{user.email}</div>
                          {user.phone && (
                            <div className="text-sm text-gray-500">{user.phone}</div>
                          )}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {user.ordersCount ?? 0}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex gap-2">
                            {user.roles?.map((role) => (
                              <span
                                key={role}
                                className="px-2 py-1 text-xs font-medium bg-blue-100 text-blue-800 rounded-full"
                              >
                                {role}
                              </span>
                            ))}
                          </div>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <button
                            type="button"
                            onClick={() =>
                              handleToggleBlocked(
                                user.id,
                                user.blocked,
                                `${user.firstName} ${user.lastName}`,
                              )
                            }
                            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 ${
                              user.blocked
                                ? 'bg-gray-300 focus:ring-gray-400'
                                : 'bg-green-500 focus:ring-green-500'
                            }`}
                            title={user.blocked ? t('admin.users.clickToActivate') : t('admin.users.clickToBlock')}
                            role="switch"
                            aria-checked={!user.blocked}
                          >
                            <span
                              className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform duration-200 ${
                                user.blocked ? 'translate-x-1' : 'translate-x-6'
                              }`}
                            />
                          </button>
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                          {new Date(user.createdAt).toLocaleDateString()}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Pagination */}
              {meta && meta.totalPages > 1 && (
                <div className="mt-6 flex items-center justify-between">
                  <div className="text-sm text-gray-700">
                    {t('admin.users.showingPage').replace('{page}', meta.page.toString()).replace('{totalPages}', meta.totalPages.toString()).replace('{total}', meta.total.toString())}
                  </div>
                  <div className="flex gap-2">
                    <Button
                      variant="ghost"
                      onClick={() => setPage((p) => Math.max(1, p - 1))}
                      disabled={page === 1}
                    >
                      {t('admin.users.previous')}
                    </Button>
                    <Button
                      variant="ghost"
                      onClick={() => setPage((p) => Math.min(meta.totalPages, p + 1))}
                      disabled={page === meta.totalPages}
                    >
                      {t('admin.users.next')}
                    </Button>
                  </div>
                </div>
              )}
              <div className="mt-4 flex items-center justify-between">
                <div className="text-sm text-gray-700">{t('admin.users.selectedUsers').replace('{count}', selectedIds.size.toString())}</div>
                <Button
                  variant="outline"
                  onClick={handleBulkDelete}
                  disabled={selectedIds.size === 0 || bulkDeleting}
                >
                  {bulkDeleting ? t('admin.users.deleting') : t('admin.users.deleteSelected')}
                </Button>
              </div>
            </>
          )}
        </Card>
      </div>
    </div>
  );
}

import { NextRequest, NextResponse } from 'next/server';
import { Prisma } from '@prisma/client';
import { db } from '@white-shop/db';
import { extractMediaUrl } from '@/lib/utils/extractMediaUrl';
import { processImageUrl } from '@/lib/utils/image-utils';

const DEFAULT_LIMIT = 8;
const MAX_LIMIT = 20;

export interface InstantSearchResult {
  id: string;
  slug: string;
  title: string;
  price: number;
  compareAtPrice: number | null;
  image: string | null;
  category: string | null;
}

/**
 * Build search filter for instant search (same logic as products-find-query).
 */
function buildSearchWhere(search: string): Prisma.ProductWhereInput {
  const term = search.trim();
  if (!term) return {};
  return {
    OR: [
      {
        translations: {
          some: {
            title: { contains: term, mode: 'insensitive' },
          },
        },
      },
      {
        translations: {
          some: {
            subtitle: { contains: term, mode: 'insensitive' },
          },
        },
      },
      {
        variants: {
          some: {
            sku: { contains: term, mode: 'insensitive' },
          },
        },
      },
    ],
  };
}

/**
 * GET /api/search/instant
 * Query params: q (required), limit (default 8), lang (default en)
 * Returns { results: InstantSearchResult[] }
 */
export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url);
    const q = searchParams.get('q')?.trim();
    const lang = searchParams.get('lang') || 'en';
    const limit = Math.min(
      parseInt(searchParams.get('limit') || String(DEFAULT_LIMIT), 10) || DEFAULT_LIMIT,
      MAX_LIMIT
    );

    if (!q || q.length === 0) {
      return NextResponse.json(
        { results: [] },
        { headers: { 'Cache-Control': 'no-store, must-revalidate' } }
      );
    }

    const where: Prisma.ProductWhereInput = {
      published: true,
      deletedAt: null,
      ...buildSearchWhere(q),
    };

    const products = await db.product.findMany({
      where,
      take: limit,
      include: {
        translations: true,
        variants: {
          where: { published: true },
          take: 1,
          orderBy: { price: 'asc' },
        },
        categories: {
          include: {
            translations: true,
          },
        },
      },
    });

    const results: InstantSearchResult[] = products.map((product) => {
      const translations = Array.isArray(product.translations) ? product.translations : [];
      const translation =
        translations.find((t: { locale: string }) => t.locale === lang) || translations[0];
      const slug = translation?.slug ?? '';
      const title = translation?.title ?? '';

      const variants = Array.isArray(product.variants) ? product.variants : [];
      const firstVariant = variants[0];
      const price = firstVariant?.price ?? 0;
      const compareAtPrice = firstVariant?.compareAtPrice ?? null;

      let image: string | null = extractMediaUrl(product.media);
      if (!image && firstVariant?.imageUrl) {
        image = processImageUrl(firstVariant.imageUrl);
      }

      const categories = Array.isArray(product.categories) ? product.categories : [];
      const primaryCategory =
        product.primaryCategoryId &&
        categories.find((c: { id: string }) => c.id === product.primaryCategoryId);
      const categoryDoc = primaryCategory || categories[0];
      const categoryTranslations = categoryDoc?.translations
        ? Array.isArray(categoryDoc.translations)
          ? categoryDoc.translations
          : []
        : [];
      const categoryTranslation =
        categoryTranslations.find((t: { locale: string }) => t.locale === lang) ||
        categoryTranslations[0];
      const category = categoryTranslation?.title ?? null;

      return {
        id: product.id,
        slug,
        title,
        price,
        compareAtPrice,
        image,
        category,
      };
    });

    return NextResponse.json(
      { results },
      { headers: { 'Cache-Control': 'no-store, must-revalidate' } }
    );
  } catch (error) {
    console.error('[search/instant] Error:', error);
    return NextResponse.json(
      {
        error: 'Search failed',
        results: [],
        details: error instanceof Error ? error.message : String(error),
      },
      { status: 500, headers: { 'Cache-Control': 'no-store, must-revalidate' } }
    );
  }
}

