import { NextRequest, NextResponse } from "next/server";
import { db } from "@white-shop/db";
import { cacheService } from "@/lib/services/cache.service";
import { processImageUrl } from "@/lib/utils/image-utils";

const CACHE_TTL = 300; // 5 minutes

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url);
    const lang = searchParams.get("lang") || "en";
    const limitParam = parseInt(searchParams.get("limit") || "5", 10);
    const limit = Math.min(limitParam, 20);

    const cacheKey = `categories:top:${lang}:${limit}`;
    const cached = await cacheService.get(cacheKey);
    if (cached !== null && cached !== undefined) {
      const data = typeof cached === "string" ? JSON.parse(cached) : cached;
      return NextResponse.json(data, {
        headers: { "X-Cache": "HIT" },
      });
    }

    const categories = await db.category.findMany({
      where: { parentId: null },
      include: {
        translations: true,
        children: {
          include: { translations: true },
        },
      },
    });

    const allCategoryIds = categories.flatMap((cat) => [
      cat.id,
      ...cat.children.map((child) => child.id),
    ]);

    const counts = await db.product.groupBy({
      by: ["primaryCategoryId"],
      where: {
        published: true,
        deletedAt: null,
        primaryCategoryId: { in: allCategoryIds },
      },
      _count: { id: true },
    });

    const countMap = new Map<string, number>();
    for (const row of counts) {
      if (row.primaryCategoryId) {
        countMap.set(row.primaryCategoryId, row._count.id);
      }
    }

    const allCats = categories.flatMap((cat) => {
      const t =
        cat.translations.find((tr) => tr.locale === lang) ||
        cat.translations[0];
      const parentCount = countMap.get(cat.id) || 0;
      const childrenCount = cat.children.reduce(
        (sum, child) => sum + (countMap.get(child.id) || 0),
        0
      );
      return [
        {
          id: cat.id,
          slug: t?.slug || "",
          title: t?.title || "",
          productCount: parentCount + childrenCount,
        },
        ...cat.children.map((child) => {
          const ct =
            child.translations.find((tr) => tr.locale === lang) ||
            child.translations[0];
          return {
            id: child.id,
            slug: ct?.slug || "",
            title: ct?.title || "",
            productCount: countMap.get(child.id) || 0,
          };
        }),
      ];
    });

    const topCats = allCats
      .filter((c) => c.productCount > 0)
      .sort((a, b) => b.productCount - a.productCount)
      .slice(0, limit);

    const topCatIds = topCats.map((c) => c.id);
    const sampleProducts = await db.product.findMany({
      where: {
        published: true,
        deletedAt: null,
        primaryCategoryId: { in: topCatIds },
      },
      select: {
        primaryCategoryId: true,
        media: true,
      },
      take: topCatIds.length * 3,
    });

    const imageMap = new Map<string, string | null>();
    for (const p of sampleProducts) {
      if (!p.primaryCategoryId || imageMap.has(p.primaryCategoryId)) continue;
      const img = Array.isArray(p.media) && p.media.length > 0
        ? processImageUrl(p.media[0] as string | null | undefined | { url?: string; src?: string; value?: string })
        : null;
      if (img) imageMap.set(p.primaryCategoryId, img);
    }

    const result = {
      data: topCats.map((c) => ({
        id: c.id,
        slug: c.slug,
        title: c.title,
        productCount: c.productCount,
        image: imageMap.get(c.id) || null,
      })),
    };

    await cacheService.setex(cacheKey, CACHE_TTL, JSON.stringify(result));

    return NextResponse.json(result, {
      headers: { "X-Cache": "MISS" },
    });
  } catch (error: unknown) {
    const err = error as { type?: string; title?: string; status?: number; detail?: string; message?: string };
    console.error("❌ [TOP CATEGORIES] Error:", error);
    return NextResponse.json(
      {
        type: err.type || "https://api.shop.am/problems/internal-error",
        title: err.title || "Internal Server Error",
        status: err.status || 500,
        detail: err.detail || err.message || "An error occurred",
        instance: req.url,
      },
      { status: err.status || 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@white-shop/db";
import { logger } from "@/lib/utils/logger";
import { isValidEmail } from "@/lib/utils/email";

/**
 * POST /api/v1/contact
 * Submit contact form
 */
export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { name, email, subject, message } = body;

    // Validation
    if (!name || typeof name !== 'string' || name.trim().length === 0) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Field 'name' is required",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    if (!email || typeof email !== 'string' || email.trim().length === 0) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Field 'email' is required",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    if (!subject || typeof subject !== 'string' || subject.trim().length === 0) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Field 'subject' is required",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    if (!message || typeof message !== 'string' || message.trim().length === 0) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Field 'message' is required",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    // Email validation (no regex on user input to avoid ReDoS)
    if (!isValidEmail(email)) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Invalid email format",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    // Create contact message
    const contactMessage = await db.contactMessage.create({
      data: {
        name: name.trim(),
        email: email.trim(),
        subject: subject.trim(),
        message: message.trim(),
      },
    });

    logger.info("Contact message created", { id: contactMessage.id });

    return NextResponse.json(
      {
        data: {
          id: contactMessage.id,
          name: contactMessage.name,
          email: contactMessage.email,
          subject: contactMessage.subject,
          message: contactMessage.message,
          createdAt: contactMessage.createdAt,
        },
      },
      { status: 201 }
    );
  } catch (error: unknown) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error("Contact form error", { error });
    return NextResponse.json(
      {
        type: "https://api.shop.am/problems/internal-error",
        title: "Internal Server Error",
        status: 500,
        detail: errorMessage || "An error occurred while submitting the contact form",
        instance: req.url,
      },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { toApiErrorResponse } from "@/lib/api/next-route-error";
import { reviewsService } from "@/lib/services/reviews.service";
import { authenticateToken } from "@/lib/middleware/auth";
import { productsService } from "@/lib/services/products.service";

export const dynamic = "force-dynamic";

/**
 * GET /api/v1/products/[slug]/reviews
 * Get all reviews for a product (by slug)
 * Query params:
 *   - my=true: Get current user's review (requires authentication)
 */
export async function GET(
  req: NextRequest,
  { params }: { params: Promise<{ slug: string }> }
) {
  try {
    const { slug } = await params;
    const { searchParams } = new URL(req.url);
    const lang = searchParams.get("lang") || "en";
    const myReview = searchParams.get("my") === "true";
    
    console.log('📝 [REVIEWS API] GET request for product slug:', slug, { myReview });

    // First, get the product by slug to get the productId
    const product = await productsService.findBySlug(slug, lang);
    if (!product || !product.id) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/not-found",
          title: "Product not found",
          status: 404,
          detail: `Product with slug '${slug}' does not exist`,
          instance: req.url,
        },
        { status: 404 }
      );
    }

    // If my=true, return user's review
    if (myReview) {
      const user = await authenticateToken(req);
      if (!user) {
        return NextResponse.json(
          {
            type: "https://api.shop.am/problems/unauthorized",
            title: "Unauthorized",
            status: 401,
            detail: "Authentication required",
            instance: req.url,
          },
          { status: 401 }
        );
      }

      const review = await reviewsService.getUserReview(product.id, user.id, true);
      return NextResponse.json(review);
    }

    // Otherwise, return all published reviews
    const reviews = await reviewsService.getProductReviews(product.id, {
      publishedOnly: true,
    });

    return NextResponse.json(reviews);
  } catch (error: unknown) {
    console.error("❌ [REVIEWS API] GET Error:", error);
    return toApiErrorResponse(error, req.url);
  }
}

/**
 * POST /api/v1/products/[slug]/reviews
 * Create a new review for a product (by slug)
 */
export async function POST(
  req: NextRequest,
  { params }: { params: Promise<{ slug: string }> }
) {
  try {
    // Authenticate user
    const user = await authenticateToken(req);
    if (!user) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/unauthorized",
          title: "Unauthorized",
          status: 401,
          detail: "Authentication required",
          instance: req.url,
        },
        { status: 401 }
      );
    }

    const { slug } = await params;
    const { searchParams } = new URL(req.url);
    const lang = searchParams.get("lang") || "en";
    const body = await req.json();

    console.log('📝 [REVIEWS API] POST request:', { slug, userId: user.id, rating: body.rating });

    // First, get the product by slug to get the productId
    const product = await productsService.findBySlug(slug, lang);
    if (!product || !product.id) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/not-found",
          title: "Product not found",
          status: 404,
          detail: `Product with slug '${slug}' does not exist`,
          instance: req.url,
        },
        { status: 404 }
      );
    }

    // Validate request body
    if (!body.rating || typeof body.rating !== 'number') {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Rating is required and must be a number",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    if (body.rating < 1 || body.rating > 5) {
      return NextResponse.json(
        {
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          status: 400,
          detail: "Rating must be between 1 and 5",
          instance: req.url,
        },
        { status: 400 }
      );
    }

    // Create review
    const review = await reviewsService.createReview(product.id, user.id, {
      rating: body.rating,
      comment: body.comment,
    });

    console.log('✅ [REVIEWS API] Review created:', review.id);

    return NextResponse.json(review, { status: 201 });
  } catch (error: unknown) {
    console.error("❌ [REVIEWS API] POST Error:", error);
    return toApiErrorResponse(error, req.url);
  }
}

