import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { getStoredCurrency } from '../../lib/currency';
import { getStoredLanguage } from '../../lib/language';
import { useAuth } from '../../lib/auth/AuthContext';
import { useTranslation } from '../../lib/i18n-client';
import { usePaymentMethods } from './utils/payment-methods';
import { useCheckoutSchema } from './utils/validation-schema';
import { useDeliveryPrice } from './hooks/useDeliveryPrice';
import { useCart } from './hooks/useCart';
import { useUserProfile } from './hooks/useUserProfile';
import { useOrderSubmission } from './hooks/useOrderSubmission';
import { useOrderSummary } from './hooks/useOrderSummary';
import type { CheckoutFormData } from './types';

export function useCheckout() {
  const router = useRouter();
  const { isLoggedIn, isLoading } = useAuth();
  const { t } = useTranslation();
  const [error, setError] = useState<string | null>(null);
  const [currency, setCurrency] = useState(getStoredCurrency());
  const [language, setLanguage] = useState(getStoredLanguage());
  const [logoErrors, setLogoErrors] = useState<Record<string, boolean>>({});
  const [showShippingModal, setShowShippingModal] = useState(false);
  const [showCardModal, setShowCardModal] = useState(false);

  const paymentMethods = usePaymentMethods();
  const checkoutSchema = useCheckoutSchema();

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
    setValue,
    watch,
  } = useForm<CheckoutFormData>({
    resolver: zodResolver(checkoutSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      phone: '',
      shippingMethod: 'pickup',
      paymentMethod: 'cash_on_delivery',
      shippingAddress: '',
      shippingCity: '',
      cardNumber: '',
      cardExpiry: '',
      cardCvv: '',
      cardHolderName: '',
    },
  });

  const paymentMethod = watch('paymentMethod');
  const shippingMethod = watch('shippingMethod');
  const shippingCity = watch('shippingCity');

  const { deliveryPrice, loadingDeliveryPrice } = useDeliveryPrice(shippingMethod, shippingCity);
  const { cart, loading, fetchCart } = useCart(isLoggedIn);
  useUserProfile(isLoggedIn, isLoading, setValue);

  const { submitOrder } = useOrderSubmission({
    cart,
    isLoggedIn,
    deliveryPrice,
    setError,
  });

  const { orderSummary } = useOrderSummary({
    cart,
    shippingMethod,
    deliveryPrice,
    currency,
  });

  useEffect(() => {
    if (isLoading) {
      return;
    }

    fetchCart();

    const handleCurrencyUpdate = () => {
      setCurrency(getStoredCurrency());
    };

    const handleLanguageUpdate = () => {
      setLanguage(getStoredLanguage());
    };

    const handleCurrencyRatesUpdate = () => {
      setCurrency(getStoredCurrency());
    };

    window.addEventListener('currency-updated', handleCurrencyUpdate);
    window.addEventListener('language-updated', handleLanguageUpdate);
    window.addEventListener('currency-rates-updated', handleCurrencyRatesUpdate);

    return () => {
      window.removeEventListener('currency-updated', handleCurrencyUpdate);
      window.removeEventListener('language-updated', handleLanguageUpdate);
      window.removeEventListener('currency-rates-updated', handleCurrencyRatesUpdate);
    };
  }, [isLoggedIn, isLoading, fetchCart]);

  const handlePlaceOrder = (e: React.FormEvent) => {
    e.preventDefault();
    
    if (shippingMethod === 'delivery') {
      const formData = watch();
      const hasShippingAddress = formData.shippingAddress && formData.shippingAddress.trim().length > 0;
      const hasShippingCity = formData.shippingCity && formData.shippingCity.trim().length > 0;
      
      if (!hasShippingAddress || !hasShippingCity) {
        setError(t('checkout.errors.fillShippingAddress'));
        const shippingSection = document.querySelector('[data-shipping-section]');
        if (shippingSection) {
          shippingSection.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
        return;
      }
    }
    
    if (paymentMethod === 'arca' || paymentMethod === 'idram') {
      setShowCardModal(true);
      return;
    }
    
    if (!isLoggedIn) {
      setShowShippingModal(true);
      return;
    }
    
    handleSubmit(submitOrder)(e);
  };

  const onSubmit = (data: CheckoutFormData) => {
    submitOrder(data);
  };

  return {
    // State
    cart,
    loading,
    error,
    setError,
    currency,
    logoErrors,
    setLogoErrors,
    showShippingModal,
    setShowShippingModal,
    showCardModal,
    setShowCardModal,
    deliveryPrice,
    loadingDeliveryPrice,
    // Form
    register,
    handleSubmit,
    errors,
    isSubmitting,
    setValue,
    watch,
    // Computed
    paymentMethod,
    shippingMethod,
    shippingCity,
    paymentMethods,
    orderSummary,
    // Actions
    handlePlaceOrder,
    onSubmit,
    // Auth
    isLoggedIn,
  };
}

import { z } from 'zod';
import { useTranslation } from '../../../lib/i18n-client';
import type { CheckoutFormData } from '../types';

export function useCheckoutSchema() {
  const { t } = useTranslation();

  return z.object({
    firstName: z.string().min(1, t('checkout.errors.firstNameRequired')),
    lastName: z.string().min(1, t('checkout.errors.lastNameRequired')),
    email: z.string().email(t('checkout.errors.invalidEmail')).min(1, t('checkout.errors.emailRequired')),
    phone: z.string().min(1, t('checkout.errors.phoneRequired')).regex(/^\+?[0-9]{8,15}$/, t('checkout.errors.invalidPhone')),
    shippingMethod: z.enum(['pickup', 'delivery'], {
      message: t('checkout.errors.selectShippingMethod'),
    }),
    paymentMethod: z.enum(['idram', 'arca', 'cash_on_delivery'], {
      message: t('checkout.errors.selectPaymentMethod'),
    }),
    shippingAddress: z.string().optional(),
    shippingCity: z.string().optional(),
    cardNumber: z.string().optional(),
    cardExpiry: z.string().optional(),
    cardCvv: z.string().optional(),
    cardHolderName: z.string().optional(),
  }).refine((data) => {
    if (data.shippingMethod === 'delivery') {
      return data.shippingAddress && data.shippingAddress.trim().length > 0;
    }
    return true;
  }, {
    message: t('checkout.errors.addressRequired'),
    path: ['shippingAddress'],
  }).refine((data) => {
    if (data.shippingMethod === 'delivery') {
      return data.shippingCity && data.shippingCity.trim().length > 0;
    }
    return true;
  }, {
    message: t('checkout.errors.cityRequired'),
    path: ['shippingCity'],
  }).refine((data) => {
    if (data.paymentMethod === 'arca' || data.paymentMethod === 'idram') {
      return data.cardNumber && data.cardNumber.replace(/\s/g, '').length >= 13;
    }
    return true;
  }, {
    message: t('checkout.errors.cardNumberRequired'),
    path: ['cardNumber'],
  }).refine((data) => {
    if (data.paymentMethod === 'arca' || data.paymentMethod === 'idram') {
      return data.cardExpiry && /^\d{2}\/\d{2}$/.test(data.cardExpiry);
    }
    return true;
  }, {
    message: t('checkout.errors.cardExpiryRequired'),
    path: ['cardExpiry'],
  }).refine((data) => {
    if (data.paymentMethod === 'arca' || data.paymentMethod === 'idram') {
      return data.cardCvv && data.cardCvv.length >= 3;
    }
    return true;
  }, {
    message: t('checkout.errors.cvvRequired'),
    path: ['cardCvv'],
  }).refine((data) => {
    if (data.paymentMethod === 'arca' || data.paymentMethod === 'idram') {
      return data.cardHolderName && data.cardHolderName.trim().length > 0;
    }
    return true;
  }, {
    message: t('checkout.errors.cardHolderNameRequired'),
    path: ['cardHolderName'],
  });
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import type { MouseEvent } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';
import { Button } from '@shop/ui';
import { apiClient } from '../../lib/api-client';
import { formatPrice, getStoredCurrency } from '../../lib/currency';
import { getStoredLanguage } from '../../lib/language';
import { useTranslation } from '../../lib/i18n-client';
import { useAuth } from '../../lib/auth/AuthContext';
import { getErrorMessage } from '../../lib/types/errors';

interface Product {
  id: string;
  slug: string;
  title: string;
  price: number;
  originalPrice: number | null;
  compareAtPrice: number | null;
  discountPercent: number | null;
  image: string | null;
  inStock: boolean;
  brand: {
    id: string;
    name: string;
  } | null;
  description?: string;
}

const COMPARE_KEY = 'shop_compare';

function getCompare(): string[] {
  if (typeof window === 'undefined') return [];
  try {
    const stored = localStorage.getItem(COMPARE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch {
    return [];
  }
}


/**
 * Compare page renders up to four products side-by-side with quick actions.
 */
export default function ComparePage() {
  const router = useRouter();
  const { isLoggedIn } = useAuth();
  const { t } = useTranslation();
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [compareIds, setCompareIds] = useState<string[]>([]);
  const [currency, setCurrency] = useState(getStoredCurrency());
  const [addingToCart, setAddingToCart] = useState<Set<string>>(new Set());
  // Track if we updated locally to prevent unnecessary re-fetch
  const isLocalUpdateRef = useRef(false);

  /**
   * Fetch compare products for provided ids and update UI state.
   */
  const fetchCompareProducts = useCallback(async (idsToLoad: string[]) => {
    if (idsToLoad.length === 0) {
      console.info('[Compare] Skip fetch because ids array is empty');
      setProducts([]);
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      console.info(`[Compare] Fetching ${idsToLoad.length} products for render`);
      const languagePreference = getStoredLanguage();
      const response = await apiClient.get<{
        data: Product[];
        meta: {
          total: number;
          page: number;
          limit: number;
          totalPages: number;
        };
      }>('/api/v1/products', {
        params: {
          limit: '1000',
          lang: languagePreference,
        },
      });

      const compareProducts = response.data.filter((product) =>
        idsToLoad.includes(product.id)
      );
      setProducts(compareProducts);
    } catch (error) {
      console.error('[Compare] Error fetching compare products:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    // Get compare IDs from localStorage
    const ids = getCompare();
    setCompareIds(ids);
    fetchCompareProducts(ids);

    // Listen for compare updates from other components (header, etc.)
    // But don't re-fetch if we already updated locally
    const handleCompareUpdate = () => {
      // If we just updated locally, skip re-fetch to avoid page reload
      if (isLocalUpdateRef.current) {
        isLocalUpdateRef.current = false;
        return;
      }
      
      // Only re-fetch if update came from external source (another component)
      const updatedIds = getCompare();
      setCompareIds(updatedIds);
      fetchCompareProducts(updatedIds);
    };

    window.addEventListener('compare-updated', handleCompareUpdate);
    return () => {
      window.removeEventListener('compare-updated', handleCompareUpdate);
    };
  }, [fetchCompareProducts]);

  // Listen for currency and language updates
  useEffect(() => {
    const handleCurrencyUpdate = () => {
      setCurrency(getStoredCurrency());
    };

    const handleLanguageUpdate = () => {
      // Reload products with new language preference
      // Get current IDs from localStorage to avoid dependency on state
      const currentIds = getCompare();
      fetchCompareProducts(currentIds);
    };

    window.addEventListener('currency-updated', handleCurrencyUpdate);
    window.addEventListener('language-updated', handleLanguageUpdate);
    return () => {
      window.removeEventListener('currency-updated', handleCurrencyUpdate);
      window.removeEventListener('language-updated', handleLanguageUpdate);
    };
  }, [fetchCompareProducts]);

  const handleRemove = (e: MouseEvent, productId: string) => {
    e.preventDefault();
    e.stopPropagation();
    
    console.info(`[Compare] Removing product ${productId} from compare UI`);
    
    // Mark as local update to prevent re-fetch in event handler
    isLocalUpdateRef.current = true;
    
    // Optimistic update: remove from UI immediately (no loading state, no page reload)
    const updatedIds = compareIds.filter((id) => id !== productId);
    const updatedProducts = products.filter((p) => p.id !== productId);
    
    // Update localStorage first
    localStorage.setItem(COMPARE_KEY, JSON.stringify(updatedIds));
    
    // Update state immediately (no page reload, no loading spinner)
    setCompareIds(updatedIds);
    setProducts(updatedProducts);
    
    // Dispatch event for other components (header, etc.) - but our handler won't re-fetch
    // because isLocalUpdateRef.current is true
    window.dispatchEvent(new Event('compare-updated'));
  };

  const handleAddToCart = async (e: MouseEvent, product: Product) => {
    e.preventDefault();
    e.stopPropagation();
    
    if (!product.inStock) {
      return;
    }

    if (!isLoggedIn) {
      router.push(`/login?redirect=/compare`);
      return;
    }

    setAddingToCart(prev => new Set(prev).add(product.id));

    try {
      // Get product details to get variant ID
      interface ProductDetails {
        id: string;
        variants?: Array<{
          id: string;
          sku: string;
          price: number;
          stock: number;
          available: boolean;
        }>;
      }

      const productDetails = await apiClient.get<ProductDetails>(`/api/v1/products/${product.slug}`);

      if (!productDetails.variants || productDetails.variants.length === 0) {
        alert(t('common.alerts.noVariantsAvailable'));
        return;
      }

      const variantId = productDetails.variants[0].id;
      
      await apiClient.post(
        '/api/v1/cart/items',
        {
          productId: product.id,
          variantId: variantId,
          quantity: 1,
        }
      );

      // Trigger cart update event
      window.dispatchEvent(new Event('cart-updated'));
    } catch (error: unknown) {
      console.error('Error adding to cart:', error);
      const msg = getErrorMessage(error);
      if (msg.includes('401') || msg.includes('Unauthorized')) {
        router.push(`/login?redirect=/compare`);
      }
    } finally {
      setAddingToCart(prev => {
        const next = new Set(prev);
        next.delete(product.id);
        return next;
      });
    }
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div className="text-center py-6">
          <div className="animate-pulse space-y-4">
            <div className="h-6 bg-gray-200 rounded w-1/4 mx-auto"></div>
            <div className="mt-4 bg-gray-200 rounded-lg h-48"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold text-gray-900">{t('common.compare.title')}</h1>
        {products.length > 0 && (
          <p className="text-sm text-gray-600">
            {products.length} of 4 {products.length === 1 ? t('common.compare.product') : t('common.compare.products')}
          </p>
        )}
      </div>

      {products.length > 0 ? (
        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-200">
                  <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700 min-w-[150px] sticky left-0 bg-gray-50 z-10">
                    {t('common.compare.characteristic')}
                  </th>
                  {products.map((product) => (
                    <th
                      key={product.id}
                      className="px-4 py-3 text-center text-sm font-semibold text-gray-700 min-w-[220px] relative"
                    >
                      <button
                        onClick={(e) => handleRemove(e, product.id)}
                        className="absolute top-2 right-2 w-6 h-6 flex items-center justify-center text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all"
                        title={t('common.buttons.remove')}
                        aria-label={t('common.buttons.remove')}
                      >
                        <svg
                          className="w-4 h-4"
                          fill="none"
                          viewBox="0 0 24 24"
                          stroke="currentColor"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M6 18L18 6M6 6l12 12"
                          />
                        </svg>
                      </button>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {/* Изображение */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.image')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4 text-center">
                      <Link href={`/products/${product.slug}`} className="inline-block">
                        <div className="w-32 h-32 mx-auto bg-gray-100 rounded-lg overflow-hidden relative">
                          {product.image ? (
                            <Image
                              src={product.image}
                              alt={product.title}
                              fill
                              className="object-cover"
                              sizes="128px"
                              unoptimized
                            />
                          ) : (
                            <div className="w-full h-full bg-gray-200 flex items-center justify-center">
                              <span className="text-gray-400 text-xs">{t('common.messages.noImage')}</span>
                            </div>
                          )}
                        </div>
                      </Link>
                    </td>
                  ))}
                </tr>

                {/* Название */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.name')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4">
                      <Link
                        href={`/products/${product.slug}`}
                        className="text-base font-semibold text-gray-900 hover:text-blue-600 transition-colors block text-center"
                      >
                        {product.title}
                      </Link>
                    </td>
                  ))}
                </tr>

                {/* Бренд */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.brand')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4 text-center text-sm text-gray-600">
                      {product.brand ? product.brand.name : '-'}
                    </td>
                  ))}
                </tr>

                {/* Цена */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.price')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4 text-center">
                      <div className="flex items-center justify-center gap-3">
                        <p className="text-lg font-bold text-gray-900 select-none">
                          {formatPrice(product.price, currency)}
                        </p>
                        {(product.originalPrice && product.originalPrice > product.price) && (
                          <p className="text-sm text-gray-500 line-through select-none">
                            {formatPrice(product.originalPrice, currency)}
                          </p>
                        )}
                        {!product.originalPrice && product.compareAtPrice && product.compareAtPrice > product.price && (
                          <p className="text-sm text-gray-500 line-through select-none">
                            {formatPrice(product.compareAtPrice, currency)}
                          </p>
                        )}
                      </div>
                    </td>
                  ))}
                </tr>

                {/* Наличие */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.availability')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4 text-center">
                      <span
                        className={`inline-block px-3 py-1 rounded-full text-xs font-medium ${
                          product.inStock
                            ? 'bg-green-100 text-green-800'
                            : 'bg-red-100 text-red-800'
                        }`}
                      >
                        {product.inStock
                          ? t('common.stock.inStock')
                          : t('common.stock.outOfStock')}
                      </span>
                    </td>
                  ))}
                </tr>

                {/* Действия */}
                <tr className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-4 text-sm font-medium text-gray-700 bg-gray-50 sticky left-0 z-10">
                    {t('common.compare.actions')}
                  </td>
                  {products.map((product) => (
                    <td key={product.id} className="px-4 py-4 text-center">
                      <div className="flex flex-col gap-2 items-center">
                        <Link
                          href={`/products/${product.slug}`}
                          className="text-sm text-blue-600 hover:text-blue-800 font-medium"
                        >
                          {t('common.compare.viewDetails')}
                        </Link>
                        {product.inStock && (
                          <button
                            onClick={(e) => handleAddToCart(e, product)}
                            disabled={addingToCart.has(product.id)}
                            className="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                          >
                            {addingToCart.has(product.id)
                              ? t('common.messages.adding')
                              : t('common.buttons.addToCart')}
                          </button>
                        )}
                      </div>
                    </td>
                  ))}
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="text-center py-8">
          <div className="max-w-md mx-auto">
            <svg
              className="mx-auto h-16 w-16 text-gray-400 mb-3"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={1.5}
                d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2"
              />
            </svg>
            <h2 className="text-xl font-bold text-gray-900 mb-2">
              {t('common.compare.empty')}
            </h2>
            <p className="text-sm text-gray-600 mb-4">
              {t('common.compare.emptyDescription')}
            </p>
            <Link href="/products">
              <Button variant="primary" size="md">
                {t('common.compare.browseProducts')}
              </Button>
            </Link>
          </div>
        </div>
      )}
    </div>
  );
}

