        name: formData.name,
        email: formData.email,
        subject: formData.subject,
        message: formData.message,
      }, {
        skipAuth: true, // Contact form doesn't require authentication
      });
      
      // Reset form
      setFormData({
        name: '',
        email: '',
        subject: '',
        message: '',
      });
      
      alert(t('contact.form.submitSuccess') || 'Ձեր հաղորդագրությունը հաջողությամբ ուղարկվեց');
    } catch (error: unknown) {
      console.error('Error submitting contact form:', error);
      alert(t('contact.form.submitError') || 'Սխալ: ' + (getErrorMessage(error) || 'Չհաջողվեց ուղարկել հաղորդագրությունը'));
    } finally {
      setSubmitting(false);
    }
  };

  const handleChange = (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  return (
    <div className="bg-white">
      {/* Top Section: Contact Info and Form */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          {/* Left Side: Contact Information */}
          <div className="space-y-8">
            {/* Call to Us */}
            <div>
              <div className="flex items-center gap-3 mb-3">
                <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center text-gray-700">
                  <PhoneIcon />
                </div>
                <h3 className="text-xl font-semibold text-gray-900">{t('contact.callToUs.title')}</h3>
              </div>
              <p className="text-gray-600 mb-2">{t('contact.callToUs.description')}</p>
              <a href={`tel:${t('contact.phone')}`} className="text-orange-500 hover:text-orange-600 font-medium">
                {t('contact.phone')}
              </a>
            </div>

            {/* Write to Us */}
            <div>
              <div className="flex items-center gap-3 mb-3">
                <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center text-gray-700">
                  <EnvelopeIcon />
                </div>
                <h3 className="text-xl font-semibold text-gray-900">{t('contact.writeToUs.title')}</h3>
              </div>
              <p className="text-gray-600 mb-2">{t('contact.writeToUs.description')}</p>
              <a href={`mailto:${t('contact.email')}`} className="text-orange-500 hover:text-orange-600 font-medium">
                {t('contact.writeToUs.emailLabel')} {t('contact.email')}
              </a>
            </div>

            {/* Headquarter */}
            <div>
              <div className="flex items-center gap-3 mb-3">
                <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center text-gray-700">
                  <MapPinIcon />
                </div>
                <h3 className="text-xl font-semibold text-gray-900">{t('contact.headquarter.title')}</h3>
              </div>
              <div className="text-gray-600 mb-2 space-y-1">
                <p>{t('contact.headquarter.hours.weekdays')}</p>
                <p>{t('contact.headquarter.hours.saturday')}</p>
              </div>
              <p className="text-orange-500 hover:text-orange-600 font-medium">
                {t('contact.address')}
              </p>
            </div>
          </div>

          {/* Right Side: Contact Form */}
          <div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label htmlFor="name" className="block text-sm font-medium text-gray-900 mb-2">
                  {t('contact.form.name')}
                </label>
                <Input
                  id="name"
                  name="name"
                  type="text"
                  required
                  value={formData.name}
                  onChange={handleChange}
                  className="w-full"
                  placeholder={t('contact.form.namePlaceholder')}
                />
              </div>
              <div>
                <label htmlFor="email" className="block text-sm font-medium text-gray-900 mb-2">
                  {t('contact.form.email')}
                </label>
                <Input
                  id="email"
                  name="email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={handleChange}
                  className="w-full"
                  placeholder={t('contact.form.emailPlaceholder')}
                />
              </div>
              <div>
                <label htmlFor="subject" className="block text-sm font-medium text-gray-900 mb-2">
                  {t('contact.form.subject')}
                </label>
                <Input
                  id="subject"
                  name="subject"
                  type="text"
                  required
                  value={formData.subject}
                  onChange={handleChange}
                  className="w-full"
                  placeholder={t('contact.form.subjectPlaceholder')}
                />
              </div>
              <div>
                <label htmlFor="message" className="block text-sm font-medium text-gray-900 mb-2">
                  {t('contact.form.message')}
                </label>
                <textarea
                  id="message"
                  name="message"
                  rows={6}
                  value={formData.message}
                  onChange={handleChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-gray-900 focus:border-transparent"
                  placeholder={t('contact.form.messagePlaceholder')}
                />
              </div>
              <Button
                type="submit"
                variant="primary"
                className="w-full bg-gray-900 text-white hover:bg-gray-800 rounded-md py-3 font-semibold uppercase tracking-wide"
                disabled={submitting}
              >
                {submitting ? (t('contact.form.submitting') || 'Ուղարկվում է...') : t('contact.form.submit')}
              </Button>
            </form>
          </div>
        </div>
      </div>

      {/* Bottom Section: Map */}
      <div className="w-full h-[500px] bg-gray-100">
        <iframe
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.1234567890123!2d44.5150!3d40.1812!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa2dab8fc8b5b%3A0x3d1479ab4e9b8c5e!2sAbovyan%20St%2C%20Yerevan%2C%20Armenia!5e0!3m2!1sen!2sam!4v1234567890123!5m2!1sen!2sam"
          width="100%"
          height="100%"
          style={{ border: 0 }}
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
          className="w-full h-full"
        />
      </div>
    </div>
  );
}

'use client';

import { Card } from '@shop/ui';
import { useEffect, useState } from 'react';
import { useTranslation } from '../../lib/i18n-client';
import { getStoredLanguage } from '../../lib/language';
import { loadTranslation } from '../../lib/i18n';
import enDelivery from '../../locales/en/delivery.json';

type DeliveryJson = typeof enDelivery;

export default function DeliveryPage() {
  const { t } = useTranslation();
  const [methods, setMethods] = useState<Array<{
    id: string;
    enabled: boolean;
    name: string;
    price: number;
    freeAbove: number | null;
    estimatedDays: number;
    locations: Array<{ name: string; address: string; workingHours?: string }>;
  }>>([]);

  useEffect(() => {
    const loadMethods = () => {
      const lang = getStoredLanguage();
      const deliveryData = loadTranslation(lang, 'delivery') as DeliveryJson | null;
      setMethods(deliveryData?.methods ?? []);
    };
    loadMethods();
    window.addEventListener('language-updated', loadMethods);
    return () => window.removeEventListener('language-updated', loadMethods);
  }, []);
  
  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <h1 className="text-3xl font-bold text-gray-900 mb-8">{t('delivery.title')}</h1>
      
      <div className="space-y-6">
        {/* Delivery Information */}
        <Card className="p-6">
          <h2 className="text-2xl font-semibold text-gray-900 mb-4">{t('delivery.deliveryInformation.title')}</h2>
          <div className="space-y-4 text-gray-700">
            {methods.map((method) => {
              if (!method.enabled) return null;
              const freeAbove = method.freeAbove ? new Intl.NumberFormat('hy-AM', {
                style: 'currency',
                currency: 'AMD',
                minimumFractionDigits: 0,
              }).format(method.freeAbove) : null;
              
              return (
                <div key={method.id}>
                  <h3 className="font-semibold text-gray-900 mb-2">{method.name}</h3>
                  <p className="text-gray-600">
                    {method.price === 0 ? (
                      t('delivery.deliveryInformation.freeDelivery')
                    ) : (
                      <>
                        {t('delivery.deliveryInformation.deliveryCost').replace('{price}', new Intl.NumberFormat('hy-AM', {
                          style: 'currency',
                          currency: 'AMD',
                          minimumFractionDigits: 0,
                        }).format(method.price))}
                        {freeAbove && ` (${t('delivery.deliveryInformation.freeForOrdersAbove').replace('{amount}', freeAbove)})`}
                      </>
                    )}
                  </p>
                  {method.estimatedDays > 0 && (
                    <p className="text-sm text-gray-500 mt-1">
                      {t('delivery.deliveryInformation.estimatedDelivery')
                        .replace('{days}', method.estimatedDays.toString())
                        .replace('{daysText}', method.estimatedDays === 1 ? t('delivery.deliveryInformation.day') : t('delivery.deliveryInformation.days'))}
                    </p>
                  )}
                  {method.locations && method.locations.length > 0 && (
                    <div className="mt-2 text-sm text-gray-600">
                      <p className="font-medium mb-1">{t('delivery.deliveryInformation.pickupLocations')}</p>
                      <ul className="list-disc list-inside space-y-1">
                        {method.locations.map((location, idx) => (
                          <li key={idx}>
                            {location.name} - {location.address}
                            {location.workingHours && (
                              <span className="text-gray-500">
                                {' '}({location.workingHours})
                              </span>
                            )}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </Card>

        {/* Return Policy */}
        <Card className="p-6">
          <h2 className="text-2xl font-semibold text-gray-900 mb-4">{t('delivery.returnPolicy.title')}</h2>
          <div className="space-y-4 text-gray-700">
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">{t('delivery.returnPolicy.thirtyDayPolicy.title')}</h3>
              <p className="text-gray-600">
                {t('delivery.returnPolicy.thirtyDayPolicy.description')}
              </p>
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">{t('delivery.returnPolicy.returnConditions.title')}</h3>
              <ul className="list-disc list-inside text-gray-600 space-y-1">
                {(() => {
                  const lang = getStoredLanguage();
                  const deliveryData = loadTranslation(lang, 'delivery') as DeliveryJson | null;
                  const items = deliveryData?.returnPolicy?.returnConditions?.items || [];
                  return Array.isArray(items) ? items.map((item: string, idx: number) => (
                    <li key={idx}>{item}</li>
                  )) : null;
                })()}
              </ul>
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">{t('delivery.returnPolicy.howToReturn.title')}</h3>
              <ol className="list-decimal list-inside text-gray-600 space-y-1">
                {(() => {
                  const lang = getStoredLanguage();
                  const deliveryData = loadTranslation(lang, 'delivery') as DeliveryJson | null;
                  const steps = deliveryData?.returnPolicy?.howToReturn?.steps || [];
                  return Array.isArray(steps) ? steps.map((step: string, idx: number) => (
                    <li key={idx}>{step}</li>
                  )) : null;
                })()}
              </ol>
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">{t('delivery.returnPolicy.refundProcess.title')}</h3>
              <p className="text-gray-600">
                {t('delivery.returnPolicy.refundProcess.description')}
              </p>
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 mb-2">{t('delivery.returnPolicy.nonReturnableItems.title')}</h3>
              <ul className="list-disc list-inside text-gray-600 space-y-1">
                {(() => {
                  const lang = getStoredLanguage();
                  const deliveryData = loadTranslation(lang, 'delivery') as DeliveryJson | null;
                  const items = deliveryData?.returnPolicy?.nonReturnableItems?.items || [];
                  return Array.isArray(items) ? items.map((item: string, idx: number) => (
                    <li key={idx}>{item}</li>
                  )) : null;
                })()}
              </ul>
            </div>
          </div>
        </Card>

        {/* Contact Information */}
        <Card className="p-6">
          <h2 className="text-2xl font-semibold text-gray-900 mb-4">{t('delivery.contact.title')}</h2>
          <p className="text-gray-600 mb-4">
            {t('delivery.contact.description')}
          </p>
          <div className="space-y-2 text-gray-700">
            <p>
              <span className="font-semibold">{t('delivery.contact.email')}</span>{' '}
              <a href="mailto:support@whiteshop.com" className="text-blue-600 hover:underline">
                support@whiteshop.com
              </a>
            </p>
            <p>
              <span className="font-semibold">{t('delivery.contact.phone')}</span>{' '}
              <a href="tel:+1234567890" className="text-blue-600 hover:underline">
                +1 (234) 567-890
              </a>
            </p>
            <p>
              <span className="font-semibold">{t('delivery.contact.hours')}</span> {t('delivery.contact.hoursValue')}
            </p>
          </div>
        </Card>
      </div>
    </div>
  );
}

