'use client';

import { useTranslation } from '../../../../lib/i18n-client';
import { formatPriceInCurrency, convertPrice } from '../../../../lib/currency';
import { getColorValue } from '../utils/color-helpers';
import type { OrderItem as OrderItemType } from '../types';

interface OrderItemProps {
  item: OrderItemType;
  currency: 'USD' | 'AMD' | 'EUR' | 'RUB' | 'GEL';
}

export function OrderItem({ item, currency }: OrderItemProps) {
  const { t } = useTranslation();

  const allOptions = item.variantOptions || [];

  const getAttributeLabel = (key: string): string => {
    if (key === 'color' || key === 'colour') return t('orders.itemDetails.color');
    if (key === 'size') return t('orders.itemDetails.size');
    return key.charAt(0).toUpperCase() + key.slice(1);
  };

  const getColorsArray = (colors: unknown): string[] => {
    if (!colors) return [];
    if (Array.isArray(colors)) return colors;
    if (typeof colors === 'string') {
      try {
        const parsed = JSON.parse(colors);
        return Array.isArray(parsed) ? parsed : [];
      } catch {
        return [];
      }
    }
    return [];
  };

  const itemPriceDisplay = (() => {
    const priceAMD = convertPrice(item.price, 'USD', 'AMD');
    const priceDisplay = currency === 'AMD' ? priceAMD : convertPrice(priceAMD, 'AMD', currency);
    return formatPriceInCurrency(priceDisplay, currency);
  })();

  const itemTotalDisplay = (() => {
    const totalAMD = convertPrice(item.total, 'USD', 'AMD');
    const totalDisplay = currency === 'AMD' ? totalAMD : convertPrice(totalAMD, 'AMD', currency);
    return formatPriceInCurrency(totalDisplay, currency);
  })();

  return (
    <div className="flex gap-4 pb-4 border-b border-gray-200 last:border-0">
      {item.imageUrl && (
        <div className="w-20 h-20 flex-shrink-0 rounded-lg overflow-hidden bg-gray-100">
          <img 
            src={item.imageUrl} 
            alt={item.productTitle}
            className="w-full h-full object-cover"
          />
        </div>
      )}
      <div className="flex-1">
        <h3 className="text-lg font-semibold text-gray-900 mb-1">{item.productTitle}</h3>
        
        {allOptions.length > 0 && (
          <div className="flex flex-wrap gap-3 mt-2 mb-2">
            {allOptions.map((opt, optIndex) => {
              if (!opt.attributeKey || !opt.value) return null;
              
              const attributeKey = opt.attributeKey.toLowerCase().trim();
              const isColor = attributeKey === 'color' || attributeKey === 'colour';
              const displayLabel = opt.label || opt.value;
              const hasImage = opt.imageUrl && opt.imageUrl.trim() !== '';
              const colors = getColorsArray(opt.colors);
              const colorHex = colors.length > 0 ? colors[0] : (isColor ? getColorValue(opt.value) : null);
              
              return (
                <div key={optIndex} className="flex items-center gap-2">
                  <span className="text-sm font-medium text-gray-700">
                    {getAttributeLabel(opt.attributeKey)}:
                  </span>
                  <div className="flex items-center gap-2">
                    {hasImage ? (
                      <img 
                        src={opt.imageUrl!} 
                        alt={displayLabel}
                        className="w-6 h-6 rounded border border-gray-300 object-cover"
                        onError={(e) => {
                          (e.target as HTMLImageElement).style.display = 'none';
                        }}
                      />
                    ) : isColor && colorHex ? (
                      <div 
                        className="w-5 h-5 rounded-full border border-gray-300"
                        style={{ backgroundColor: colorHex }}
                        title={displayLabel}
                      />
                    ) : null}
                    <span className="text-sm text-gray-900 capitalize">
                      {displayLabel}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}
        
        <p className="text-sm text-gray-600">{t('orders.itemDetails.sku').replace('{sku}', item.sku)}</p>
        <p className="text-sm text-gray-600 mt-2">
          {t('orders.itemDetails.quantity')
            .replace('{qty}', item.quantity.toString())
            .replace('{price}', itemPriceDisplay)
            .replace('{total}', itemTotalDisplay)}
        </p>
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { Card, Button } from '@shop/ui';
import { useTranslation } from '../../../../lib/i18n-client';
import { formatPriceInCurrency, convertPrice } from '../../../../lib/currency';
import type { Order } from '../types';

interface OrderSummaryProps {
  order: Order;
  currency: 'USD' | 'AMD' | 'EUR' | 'RUB' | 'GEL';
  calculatedShipping: number | null;
  loadingShipping: boolean;
}

export function OrderSummary({
  order,
  currency,
  calculatedShipping,
  loadingShipping,
}: OrderSummaryProps) {
  const { t } = useTranslation();

  const subtotalDisplay = (() => {
    const subtotalAMD = convertPrice(order.totals.subtotal, 'USD', 'AMD');
    return currency === 'AMD' ? subtotalAMD : convertPrice(subtotalAMD, 'AMD', currency);
  })();

  const discountDisplay = order.totals.discount > 0 ? (() => {
    const discountAMD = convertPrice(order.totals.discount, 'USD', 'AMD');
    return currency === 'AMD' ? discountAMD : convertPrice(discountAMD, 'AMD', currency);
  })() : null;

  const shippingDisplay = order.shippingMethod === 'pickup' 
    ? t('checkout.shipping.freePickup')
    : loadingShipping
      ? t('checkout.shipping.loading')
      : (() => {
          const shippingAMD = calculatedShipping !== null ? calculatedShipping : order.totals.shipping;
          const shippingDisplayValue = currency === 'AMD' 
            ? shippingAMD 
            : convertPrice(shippingAMD, 'AMD', currency);
          return formatPriceInCurrency(shippingDisplayValue, currency) + 
            (order.shippingAddress?.city ? ` (${order.shippingAddress.city})` : '');
        })();

  const taxDisplay = (() => {
    const taxAMD = convertPrice(order.totals.tax, 'USD', 'AMD');
    return currency === 'AMD' ? taxAMD : convertPrice(taxAMD, 'AMD', currency);
  })();

  const totalDisplay = (() => {
    const subtotalAMD = convertPrice(order.totals.subtotal, 'USD', 'AMD');
    const discountAMD = convertPrice(order.totals.discount, 'USD', 'AMD');
    const shippingAMD = calculatedShipping !== null ? calculatedShipping : order.totals.shipping;
    const taxAMD = convertPrice(order.totals.tax, 'USD', 'AMD');
    const totalAMD = subtotalAMD - discountAMD + shippingAMD + taxAMD;
    return currency === 'AMD' ? totalAMD : convertPrice(totalAMD, 'AMD', currency);
  })();

  return (
    <Card className="p-6 sticky top-4">
      <h2 className="text-xl font-semibold text-gray-900 mb-6">{t('orders.orderSummary.title')}</h2>
      <div className="space-y-4 mb-6">
        {order.totals ? (
          <>
            <div className="flex justify-between text-gray-600">
              <span>{t('orders.orderSummary.subtotal')}</span>
              <span>{formatPriceInCurrency(subtotalDisplay, currency)}</span>
            </div>
            {order.totals.discount > 0 && (
              <div className="flex justify-between text-gray-600">
                <span>{t('orders.orderSummary.discount')}</span>
                <span>-{formatPriceInCurrency(discountDisplay!, currency)}</span>
              </div>
            )}
            <div className="flex justify-between text-gray-600">
              <span>{t('orders.orderSummary.shipping')}</span>
              <span>{shippingDisplay}</span>
            </div>
            <div className="flex justify-between text-gray-600">
              <span>{t('orders.orderSummary.tax')}</span>
              <span>{formatPriceInCurrency(taxDisplay, currency)}</span>
            </div>
            <div className="border-t border-gray-200 pt-4">
              <div className="flex justify-between text-lg font-bold text-gray-900">
                <span>{t('orders.orderSummary.total')}</span>
                <span>{formatPriceInCurrency(totalDisplay, currency)}</span>
              </div>
            </div>
          </>
        ) : (
          <div className="text-gray-600">{t('orders.orderSummary.loadingTotals')}</div>
        )}
      </div>

      <div className="space-y-3">
        <Link href="/products">
          <Button variant="primary" className="w-full">
            {t('orders.buttons.continueShopping')}
          </Button>
        </Link>
        <Link href="/cart">
          <Button variant="ghost" className="w-full">
            {t('orders.buttons.viewCart')}
          </Button>
        </Link>
      </div>
    </Card>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { apiClient } from '../../../lib/api-client';
import { getStoredCurrency } from '../../../lib/currency';
import { useAuth } from '../../../lib/auth/AuthContext';
import { useTranslation } from '../../../lib/i18n-client';
import { LoadingState } from './components/LoadingState';
import { ErrorState } from './components/ErrorState';
import { OrderStatus } from './components/OrderStatus';
import { OrderItems } from './components/OrderItems';
import { ShippingAddress } from './components/ShippingAddress';
import { OrderSummary } from './components/OrderSummary';
import type { Order } from './types';

export default function OrderPage() {
  const params = useParams();
  const router = useRouter();
  const { isLoggedIn } = useAuth();
  const { t } = useTranslation();
  const [order, setOrder] = useState<Order | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currency, setCurrency] = useState(getStoredCurrency());
  const [calculatedShipping, setCalculatedShipping] = useState<number | null>(null);
  const [loadingShipping, setLoadingShipping] = useState(false);

  useEffect(() => {
    if (!isLoggedIn) {
      router.push('/login');
      return;
    }

    fetchOrder();

    const handleCurrencyUpdate = () => {
      setCurrency(getStoredCurrency());
    };

    window.addEventListener('currency-updated', handleCurrencyUpdate);

    return () => {
      window.removeEventListener('currency-updated', handleCurrencyUpdate);
    };
  }, [isLoggedIn, params.number, router]);

  async function fetchOrder() {
    try {
      setLoading(true);
      const response = await apiClient.get<Order>(`/api/v1/orders/${params.number}`);
      setOrder(response);
      
      if (response.shippingMethod === 'delivery' && response.shippingAddress?.city) {
        fetchShippingPrice(response.shippingAddress.city);
      } else {
        setCalculatedShipping(null);
      }
    } catch (err: unknown) {
      const errorMessage = err instanceof Error ? err.message : t('orders.notFound.description');
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  }

  async function fetchShippingPrice(city: string) {
    if (!city || city.trim().length === 0) {
      setCalculatedShipping(0);
      return;
    }

    setLoadingShipping(true);
    try {
      const response = await apiClient.get<{ price: number }>('/api/v1/delivery/price', {
        params: {
          city: city.trim(),
          country: 'Armenia',
        },
      });
      setCalculatedShipping(response.price);
    } catch {
      setCalculatedShipping(0);
    } finally {
      setLoadingShipping(false);
    }
  }

  if (loading) {
    return <LoadingState />;
  }

  if (error || !order) {
    return <ErrorState error={error} />;
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          {t('orders.title').replace('{number}', order.number)}
        </h1>
        <p className="text-gray-600">
          {t('orders.placedOn').replace('{date}', new Date(order.createdAt).toLocaleDateString())}
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <OrderStatus
            status={order.status}
            paymentStatus={order.paymentStatus}
            fulfillmentStatus={order.fulfillmentStatus}
          />
          <OrderItems items={order.items} currency={currency} />
          {order.shippingAddress && (
            <ShippingAddress shippingAddress={order.shippingAddress} />
          )}
        </div>

        <OrderSummary
          order={order}
          currency={currency}
          calculatedShipping={calculatedShipping}
          loadingShipping={loadingShipping}
        />
      </div>
    </div>
  );
}

'use client';

import { processImageUrl } from '../../../lib/utils/image-utils';
import { t, getAttributeLabel } from '../../../lib/i18n';
import type { LanguageCode } from '../../../lib/language';
import type { Product, ProductVariant, AttributeGroupValue, VariantOption, ProductAttribute } from './types';

interface ProductAttributesSelectorProps {
  product: Product;
  attributeGroups: Map<string, AttributeGroupValue[]>;
  selectedColor: string | null;
  selectedSize: string | null;
  selectedAttributeValues: Map<string, string>;
  unavailableAttributes: Map<string, boolean>;
  colorGroups: Array<{ color: string; stock: number; variants: ProductVariant[] }>;
  sizeGroups: Array<{ size: string; stock: number; variants: ProductVariant[] }>;
  language: LanguageCode;
  quantity: number;
  maxQuantity: number;
  isOutOfStock: boolean;
  isVariationRequired: boolean;
  hasUnavailableAttributes: boolean;
  canAddToCart: boolean;
  isAddingToCart: boolean;
  showMessage: string | null;
  onColorSelect: (color: string) => void;
  onSizeSelect: (size: string) => void;
  onAttributeValueSelect: (attrKey: string, value: string) => void;
  onQuantityAdjust: (delta: number) => void;
  onAddToCart: () => Promise<void>;
  getOptionValue: (options: VariantOption[] | undefined, key: string) => string | null;
  getRequiredAttributesMessage: () => string;
}

// Helper function to get color hex/rgb from color name
const getColorValue = (colorName: string): string => {
  const colorMap: Record<string, string> = {
    'beige': '#F5F5DC', 'black': '#000000', 'blue': '#0000FF', 'brown': '#A52A2A',
    'gray': '#808080', 'grey': '#808080', 'green': '#008000', 'red': '#FF0000',
    'white': '#FFFFFF', 'yellow': '#FFFF00', 'orange': '#FFA500', 'pink': '#FFC0CB',
    'purple': '#800080', 'navy': '#000080', 'maroon': '#800000', 'olive': '#808000',
    'teal': '#008080', 'cyan': '#00FFFF', 'magenta': '#FF00FF', 'lime': '#00FF00',
    'silver': '#C0C0C0', 'gold': '#FFD700',
  };
  const normalizedName = colorName.toLowerCase().trim();
  return colorMap[normalizedName] || '#CCCCCC';
};

export function ProductAttributesSelector({
  product,
  attributeGroups,
  selectedColor,
  selectedSize,
  selectedAttributeValues,
  unavailableAttributes,
  colorGroups,
  sizeGroups,
  language,
  onColorSelect,
  onSizeSelect,
  onAttributeValueSelect,
  getOptionValue,
}: ProductAttributesSelectorProps) {
  const attributeGroupsEntries = Array.from(attributeGroups.entries());
  console.log('🎨 [PRODUCT ATTRIBUTES SELECTOR] attributeGroups entries:', attributeGroupsEntries.length);
  console.log('🎨 [PRODUCT ATTRIBUTES SELECTOR] attributeGroups keys:', Array.from(attributeGroups.keys()));
  console.log('🎨 [PRODUCT ATTRIBUTES SELECTOR] product.productAttributes:', product?.productAttributes);
  
  return (
    <div className="mt-8 p-4 bg-white border border-gray-200 rounded-2xl space-y-4">
      {/* Attribute Selectors - Support both new (productAttributes) and old (colorGroups) format */}
      {/* Display all attributes from attributeGroups, not just from productAttributes */}
      {attributeGroupsEntries.length > 0 ? (
        // Use attributeGroups which contains all attributes (from productAttributes and variants)
        Array.from(attributeGroups.entries()).map(([attrKey, attrGroups]) => {
          // Try to get attribute name from productAttributes if available
          const productAttr = product?.productAttributes?.find((pa: ProductAttribute) => pa.attribute?.key === attrKey);
          const attributeName = productAttr?.attribute?.name || attrKey.charAt(0).toUpperCase() + attrKey.slice(1);
          const isColor = attrKey === 'color';
          const isSize = attrKey === 'size';

          if (attrGroups.length === 0) return null;

          // Check if this attribute is unavailable for the selected variant
          const isUnavailable = unavailableAttributes.get(attrKey) || false;
          
          return (
            <div key={attrKey} className="space-y-1.5">
              <label className={`text-xs font-bold uppercase ${isUnavailable ? 'text-red-600' : ''}`}>
                {attrKey === 'color' ? t(language, 'product.color') : 
                 attrKey === 'size' ? t(language, 'product.size') : 
                 attributeName}:
              </label>
              {isColor ? (
                <div className="flex flex-wrap gap-1.5 items-center">
                  {attrGroups.map((g) => {
                    const isSelected = selectedColor === g.value?.toLowerCase().trim();
                    // IMPORTANT: Don't disable based on stock - show all colors, even if stock is 0
                    // Stock is just informational, not a reason to hide the option
                    const isDisabled = false; // Always show all colors
                    // Process imageUrl to ensure it's in the correct format
                    const processedImageUrl = g.imageUrl ? processImageUrl(g.imageUrl) : null;
                    const hasImage = processedImageUrl && processedImageUrl.trim() !== '';
                    const colorHex = g.colors && Array.isArray(g.colors) && g.colors.length > 0 
                      ? g.colors[0] 
                      : getColorValue(g.value);
                    
                    // Dynamic sizing based on number of values
                    // Keep size consistent for 2 values, reduce for more
                    const totalValues = attrGroups.length;
                    const sizeClass = totalValues > 6 
                      ? 'w-8 h-8' 
                      : totalValues > 3 
                      ? 'w-9 h-9' 
                      : 'w-10 h-10';
                    
                    return (
                      <div key={g.valueId || g.value} className="flex flex-col items-center gap-0.5">
                        <button 
                          onClick={() => onColorSelect(g.value)}
                          className={`${sizeClass} rounded-full transition-all overflow-hidden ${
                            isSelected 
                              ? 'border-[3px] border-green-500 scale-110' 
                              : g.stock <= 0
                                ? 'border-2 border-gray-200 opacity-60 hover:opacity-80' 
                                : 'border-2 border-gray-300 hover:scale-105'
                          }`}
                          style={hasImage ? {} : { backgroundColor: colorHex }}
                          title={`${getAttributeLabel(language, attrKey, g.value)}${g.stock > 0 ? ` (${g.stock} ${t(language, 'product.pcs')})` : ` (${t(language, 'product.outOfStock')})`}`} 
                        >
                          {hasImage && processedImageUrl ? (
                            <img 
                              src={processedImageUrl} 
                              alt={g.label}
                              className="w-full h-full object-cover"
                              onError={(e) => {
                                console.error(`❌ [COLOR IMAGE] Failed to load image for color "${g.value}":`, processedImageUrl);
                                (e.target as HTMLImageElement).style.display = 'none';
                              }}
                              onLoad={() => {
                                console.log(`✅ [COLOR IMAGE] Successfully loaded image for color "${g.value}":`, processedImageUrl);
                              }}
                            />
                          ) : null}
                        </button>
                        {g.stock > 0 && (
                          <span className={`${totalValues > 8 ? 'text-[10px]' : 'text-xs'} text-gray-500`}>{g.stock}</span>
                        )}
                        {g.stock <= 0 && (
                          <span className={`${totalValues > 8 ? 'text-[10px]' : 'text-xs'} text-gray-400`}>0</span>
                        )}
                      </div>
                    );
                  })}
                </div>
              ) : isSize ? (
                <div className="flex flex-wrap gap-1.5">
                  {attrGroups.map((g) => {
                    // Use stock from groups (already calculated with compatibility)
                    const displayStock = g.stock;
                    const isSelected = selectedSize === g.value.toLowerCase().trim();
                    // IMPORTANT: Don't disable based on stock - show all sizes, even if stock is 0
                    // Stock is just informational, not a reason to hide the option
                    const isDisabled = false; // Always show all sizes
                    
                    // Process imageUrl to ensure it's in the correct format
                    const processedImageUrl = g.imageUrl ? processImageUrl(g.imageUrl) : null;
                    const hasImage = processedImageUrl && processedImageUrl.trim() !== '';
                    
                    // Dynamic sizing based on number of values
                    // Keep size consistent for 2 values, reduce for more
                    const totalValues = attrGroups.length;
                    const paddingClass = totalValues > 6 
                      ? 'px-2 py-1' 
                      : totalValues > 3 
                      ? 'px-2.5 py-1.5' 
                      : 'px-3 py-2';
                    const textSizeClass = totalValues > 6 
                      ? 'text-xs' 
                      : 'text-sm';
                    const imageSizeClass = totalValues > 6 
                      ? 'w-4 h-4' 
                      : 'w-5 h-5';
                    const minWidthClass = totalValues > 6 
                      ? 'min-w-[40px]' 
                      : 'min-w-[50px]';

                    return (
                      <button 
                        key={g.valueId || g.value}
                        onClick={() => onSizeSelect(g.value)}
                        className={`${minWidthClass} ${paddingClass} rounded-lg border-2 transition-all flex items-center gap-1.5 ${
                          isSelected 
                            ? 'border-green-500 bg-gray-50' 
                            : displayStock <= 0
                              ? 'border-gray-200 opacity-60 hover:opacity-80' 
                              : 'border-gray-200 hover:border-gray-400'
                        }`}
                      >
                        {hasImage && processedImageUrl && (
                          <img 
                            src={processedImageUrl} 
                            alt={g.label}
                            className={`${imageSizeClass} object-cover rounded border border-gray-300 flex-shrink-0`}
                            onError={(e) => {
                              console.error(`❌ [SIZE IMAGE] Failed to load image for size "${g.value}":`, processedImageUrl);
                              (e.target as HTMLImageElement).style.display = 'none';
                            }}
                            onLoad={() => {
                              console.log(`✅ [SIZE IMAGE] Successfully loaded image for size "${g.value}":`, processedImageUrl);
                            }}
                          />
                        )}
                        <div className="flex flex-col text-center">
                          <span className={`${textSizeClass} font-medium`}>{getAttributeLabel(language, attrKey, g.value)}</span>
                          <span className={`${totalValues > 10 ? 'text-[10px]' : 'text-xs'} ${displayStock > 0 ? 'text-gray-500' : 'text-gray-400'}`}>({displayStock})</span>
                        </div>
                      </button>
                    );
                  })}
                </div>
              ) : (
                // Generic attribute selector
                <div className="flex flex-wrap gap-1.5">
                  {attrGroups.map((g) => {
                    const selectedValueId = selectedAttributeValues.get(attrKey);
                    const isSelected = selectedValueId === g.valueId || (!g.valueId && selectedColor === g.value);
                    // IMPORTANT: Don't disable based on stock - show all attribute values, even if stock is 0
                    // Stock is just informational, not a reason to hide the option
                    const isDisabled = false; // Always show all attribute values
                    
                    // Process imageUrl to ensure it's in the correct format
                    const processedImageUrl = g.imageUrl ? processImageUrl(g.imageUrl) : null;
                    const hasImage = processedImageUrl && processedImageUrl.trim() !== '';
                    const hasColors = g.colors && Array.isArray(g.colors) && g.colors.length > 0;
                    const colorHex = hasColors && g.colors 
                      ? g.colors[0] 
                      : null;
                    
                    // Debug logging for image issues
                    if (g.imageUrl && !hasImage) {
                      console.warn(`⚠️ [ATTRIBUTE IMAGE] Failed to process imageUrl for attribute "${attrKey}" value "${g.value}":`, g.imageUrl);
                    }
                    
                    // Dynamic sizing based on number of values
                    // Keep size consistent for 2 values, reduce for more
                    const totalValues = attrGroups.length;
                    const paddingClass = totalValues > 6 
                      ? 'px-2 py-1' 
                      : totalValues > 3 
                      ? 'px-3 py-1.5' 
                      : 'px-4 py-2';
                    const textSizeClass = totalValues > 6 
                      ? 'text-xs' 
                      : 'text-sm';
                    const imageSizeClass = totalValues > 6 
                      ? 'w-4 h-4' 
                      : totalValues > 3 
                      ? 'w-5 h-5' 
                      : 'w-6 h-6';
                    const gapClass = totalValues > 6 
                      ? 'gap-1' 
                      : 'gap-2';

                    return (
                      <button
                        key={g.valueId || g.value}
                        onClick={() => {
                          if (!isDisabled) {
                            onAttributeValueSelect(attrKey, g.valueId || g.value);
                          }
                        }}
                        className={`${paddingClass} rounded-lg border-2 transition-all flex items-center ${gapClass} ${
                          isSelected
                            ? 'border-green-500 bg-gray-50'
                            : g.stock <= 0
                              ? 'border-gray-200 opacity-60 hover:opacity-80'
                              : 'border-gray-200 hover:border-gray-400'
                        }`}
                        style={!hasImage && colorHex ? { backgroundColor: colorHex } : {}}
                      >
                        {hasImage && processedImageUrl ? (
                          <img 
                            src={processedImageUrl} 
                            alt={g.label}
                            className={`${imageSizeClass} object-cover rounded border border-gray-300 flex-shrink-0`}
                            onError={(e) => {
                              console.error(`❌ [ATTRIBUTE IMAGE] Failed to load image for attribute "${attrKey}" value "${g.value}":`, processedImageUrl);
                              (e.target as HTMLImageElement).style.display = 'none';
                            }}
                            onLoad={() => {
                              console.log(`✅ [ATTRIBUTE IMAGE] Successfully loaded image for attribute "${attrKey}" value "${g.value}":`, processedImageUrl);
                            }}
                          />
                        ) : hasColors && colorHex ? (
                          <div 
                            className={`${imageSizeClass} rounded border border-gray-300 flex-shrink-0`}
                            style={{ backgroundColor: colorHex }}
                          />
                        ) : null}
                        <div className="flex flex-col text-center">
                          <span className={textSizeClass}>{getAttributeLabel(language, attrKey, g.value)}</span>
                          <span className={`${totalValues > 10 ? 'text-[10px]' : 'text-xs'} ${g.stock > 0 ? 'text-gray-500' : 'text-gray-400'}`}>({g.stock})</span>
                        </div>
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })
      ) : (
        // Old format: Use colorGroups and sizeGroups
        <>
          {colorGroups.length > 0 && (
            <div className="space-y-2">
              <label className="text-sm font-medium">{t(language, 'product.color')}:</label>
              <div className="flex flex-wrap gap-2 items-center">
                {colorGroups.map((g) => {
                  const isSelected = selectedColor === g.color?.toLowerCase().trim();
                  const isDisabled = g.stock <= 0;
                  
                  return (
                    <div key={g.color} className="flex flex-col items-center gap-1">
                      <button 
                        onClick={() => !isDisabled && onColorSelect(g.color)}
                        disabled={isDisabled}
                        className={`w-10 h-10 rounded-full transition-all ${
                          isSelected 
                            ? 'border-[3px] border-green-500 scale-110' 
                            : isDisabled 
                              ? 'border-2 border-gray-100 opacity-30 grayscale cursor-not-allowed' 
                              : 'border-2 border-gray-300 hover:scale-105'
                        }`}
                        style={{ backgroundColor: getColorValue(g.color) }} 
                        title={isDisabled ? `${getAttributeLabel(language, 'color', g.color)} (${t(language, 'product.outOfStock')})` : `${getAttributeLabel(language, 'color', g.color)}${g.stock > 0 ? ` (${g.stock} ${t(language, 'product.pcs')})` : ''}`} 
                      />
                      {g.stock > 0 && (
                        <span className="text-xs text-gray-500">{g.stock}</span>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </>
      )}

      {/* Size Groups - Show only if not using new format */}
      {!product?.productAttributes && sizeGroups.length > 0 && (
        <div className="space-y-2">
          <label className="text-sm font-bold uppercase">{t(language, 'product.size')}</label>
          <div className="flex flex-wrap gap-2">
            {sizeGroups.map((g) => {
              let displayStock = g.stock;
              if (selectedColor) {
                const v = g.variants.find(v => {
                  const colorOpt = getOptionValue(v.options, 'color');
                  return colorOpt === selectedColor.toLowerCase().trim();
                });
                displayStock = v ? v.stock : 0;
              }
              const isSelected = selectedSize === g.size;
              const isDisabled = displayStock <= 0;

              return (
                <button 
                  key={g.size} 
                  onClick={() => !isDisabled && onSizeSelect(g.size)}
                  disabled={isDisabled}
                  className={`min-w-[50px] px-3 py-2 rounded-lg border-2 transition-all ${
                    isSelected 
                      ? 'border-green-500 bg-gray-50' 
                      : isDisabled 
                        ? 'border-gray-100 bg-gray-50 opacity-50 cursor-not-allowed' 
                        : 'border-gray-200 hover:border-gray-400'
                  }`}
                >
                  <div className="flex flex-col text-center">
                    <span className={`text-sm font-medium ${isDisabled ? 'text-gray-400' : 'text-gray-900'}`}>{getAttributeLabel(language, 'size', g.size)}</span>
                    {displayStock > 0 && (
                      <span className={`text-xs ${isDisabled ? 'text-gray-300' : 'text-gray-500'}`}>{displayStock} {t(language, 'product.pcs')}</span>
                    )}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Maximize2 } from "lucide-react";
import { ProductLabels } from "../../../components/ProductLabels";
import { ProductImagePlaceholder } from "../../../components/ProductImagePlaceholder";
import { t } from "../../../lib/i18n";
import type { LanguageCode } from "../../../lib/language";
import type { Product } from "./types";

interface ProductImageGalleryProps {
  images: string[];
  product: Product;
  discountPercent: number | null;
  language: LanguageCode;
  currentImageIndex: number;
  onImageIndexChange: (index: number) => void;
  thumbnailStartIndex: number;
  onThumbnailStartIndexChange: (index: number) => void;
}

const THUMBNAILS_PER_VIEW = 3;

export function ProductImageGallery({
  images,
  product,
  discountPercent,
  language,
  currentImageIndex,
  onImageIndexChange,
  thumbnailStartIndex,
  onThumbnailStartIndexChange,
}: ProductImageGalleryProps) {
  const [showZoom, setShowZoom] = useState(false);
  const [failedIndices, setFailedIndices] = useState<Set<number>>(new Set());

  const markFailed = (index: number) => {
    setFailedIndices((prev) => new Set(prev).add(index));
  };

  const mainImageFailed = failedIndices.has(currentImageIndex);
  const currentSrc = images[currentImageIndex];

  // Auto-scroll thumbnails to show selected image
  useEffect(() => {
    if (images.length > THUMBNAILS_PER_VIEW) {
      if (currentImageIndex < thumbnailStartIndex) {
        // Selected image is above visible range - scroll up
        onThumbnailStartIndexChange(currentImageIndex);
      } else if (currentImageIndex >= thumbnailStartIndex + THUMBNAILS_PER_VIEW) {
        // Selected image is below visible range - scroll down
        onThumbnailStartIndexChange(currentImageIndex - THUMBNAILS_PER_VIEW + 1);
      }
    }
  }, [currentImageIndex, images.length, thumbnailStartIndex, onThumbnailStartIndexChange]);

  // Show only 3 thumbnails at a time, scrollable with navigation arrows
  const visibleThumbnails = images.slice(thumbnailStartIndex, thumbnailStartIndex + THUMBNAILS_PER_VIEW);

  return (
    <>
      <div className="flex gap-6 items-start">
        {/* Left Column - Thumbnails (Vertical) - Show 3 at a time, scrollable */}
        <div className="flex flex-col gap-4 w-28 flex-shrink-0">
          <div className="flex flex-col gap-4 flex-1 overflow-hidden">
            {visibleThumbnails.map((image, index) => {
              const actualIndex = thumbnailStartIndex + index;
              const isActive = actualIndex === currentImageIndex;
              return (
                <button 
                  key={actualIndex}
                  onClick={() => onImageIndexChange(actualIndex)}
                  className={`relative w-full aspect-[3/4] rounded-lg overflow-hidden border bg-white transition-all duration-300 flex-shrink-0 ${
                    isActive 
                      ? "border-gray-400 shadow-[0_2px_8px_rgba(0,0,0,0.12)] ring-2 ring-gray-300" 
                      : "border-gray-200 hover:border-gray-300 hover:shadow-[0_2px_6px_rgba(0,0,0,0.08)]"
                  }`}
                >
                  {failedIndices.has(actualIndex) ? (
                    <ProductImagePlaceholder className="w-full h-full" aria-label="" />
                  ) : (
                    <img 
                      src={image} 
                      alt="" 
                      className="w-full h-full object-cover transition-transform duration-300" 
                      onError={() => markFailed(actualIndex)}
                    />
                  )}
                </button>
              );
            })}
          </div>
          
          {/* Navigation Arrows - Scroll thumbnails */}
          {images.length > THUMBNAILS_PER_VIEW && (
            <div className="flex flex-row gap-1.5 justify-center">
              <button 
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  // Scroll thumbnails up
                  const newStart = Math.max(0, thumbnailStartIndex - 1);
                  onThumbnailStartIndexChange(newStart);
                  // Also update current image if needed
                  if (currentImageIndex > newStart + THUMBNAILS_PER_VIEW - 1) {
                    onImageIndexChange(newStart + THUMBNAILS_PER_VIEW - 1);
                  } else if (currentImageIndex < newStart) {
                    onImageIndexChange(newStart);
                  }
                }}
                disabled={thumbnailStartIndex <= 0}
                className="w-9 h-9 rounded border transition-all duration-200 flex items-center justify-center border-gray-300 text-gray-700 hover:border-gray-400 hover:bg-gray-200 hover:shadow-[0_1px_3px_rgba(0,0,0,0.1)] disabled:opacity-30 disabled:cursor-not-allowed disabled:hover:bg-gray-100 disabled:hover:border-gray-300 disabled:hover:shadow-none bg-gray-100"
                aria-label={t(language, 'common.ariaLabels.previousThumbnail')}
              >
                <svg 
                  className="w-4 h-4" 
                  fill="none" 
                  stroke="currentColor" 
                  viewBox="0 0 24 24"
                >
                  <path 
                    strokeLinecap="round" 
                    strokeLinejoin="round" 
                    strokeWidth={2.5} 
                    d="M5 15l7-7 7 7" 
                  />
                </svg>
              </button>
              <button 
                type="button"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  // Scroll thumbnails down
                  const newStart = Math.min(images.length - THUMBNAILS_PER_VIEW, thumbnailStartIndex + 1);
                  onThumbnailStartIndexChange(newStart);
                  // Also update current image if needed
                  if (currentImageIndex < newStart) {
                    onImageIndexChange(newStart);
                  } else if (currentImageIndex > newStart + THUMBNAILS_PER_VIEW - 1) {
                    onImageIndexChange(newStart + THUMBNAILS_PER_VIEW - 1);
                  }
                }}
                disabled={thumbnailStartIndex >= images.length - THUMBNAILS_PER_VIEW}
                className="w-9 h-9 rounded border transition-all duration-200 flex items-center justify-center border-gray-300 text-gray-700 hover:border-gray-400 hover:bg-gray-200 hover:shadow-[0_1px_3px_rgba(0,0,0,0.1)] disabled:opacity-30 disabled:cursor-not-allowed disabled:hover:bg-gray-100 disabled:hover:border-gray-300 disabled:hover:shadow-none bg-gray-100"
                aria-label={t(language, 'common.ariaLabels.nextThumbnail')}
              >
                <svg 
                  className="w-4 h-4" 
                  fill="none" 
                  stroke="currentColor" 
                  viewBox="0 0 24 24"
                >
                  <path 
                    strokeLinecap="round" 
                    strokeLinejoin="round" 
                    strokeWidth={2.5} 
                    d="M19 9l-7 7-7-7" 
                  />
                </svg>
              </button>
            </div>
          )}
        </div>
        
        {/* Right Column - Main Image */}
        <div className="flex-1">
          <div className="relative aspect-square bg-white rounded-lg overflow-hidden group shadow-[0_2px_8px_rgba(0,0,0,0.06)]">
          {images.length > 0 && !mainImageFailed ? (
            <img 
              src={currentSrc} 
              alt={product.title} 
              className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" 
              onError={() => markFailed(currentImageIndex)}
            />
          ) : (
            <ProductImagePlaceholder
              className="w-full h-full"
              aria-label={t(language, "common.messages.noImage")}
            />
          )}
          
          {/* Discount Badge on Image - Blue circle in top-right */}
          {discountPercent && (
            <div className="absolute top-4 right-4 w-14 h-14 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-bold z-10 shadow-[0_2px_8px_rgba(37,99,235,0.3)]">
              -{discountPercent}%
            </div>
          )}

          {product.labels && <ProductLabels labels={product.labels} />}
          
          {/* Control Buttons - Bottom left */}
          <div className="absolute bottom-4 left-4 flex flex-col gap-3 z-10">
            {/* Fullscreen Button */}
            <button 
              onClick={() => setShowZoom(true)} 
              className="w-12 h-12 bg-white/80 backdrop-blur-sm rounded-full flex items-center justify-center border border-white/50 shadow-[0_2px_8px_rgba(0,0,0,0.15)] hover:bg-white/90 transition-all duration-300 hover:shadow-[0_4px_12px_rgba(0,0,0,0.2)]"
              aria-label={t(language, 'common.ariaLabels.fullscreenImage')}
            >
              <Maximize2 className="w-5 h-5 text-gray-800" />
            </button>
          </div>
          </div>
        </div>
      </div>

      {/* Zoom Modal */}
      {showZoom && images.length > 0 && !failedIndices.has(currentImageIndex) && (
        <div className="fixed inset-0 bg-black bg-opacity-90 z-50 flex items-center justify-center p-4" onClick={() => setShowZoom(false)}>
          <img src={currentSrc} alt="" className="max-w-full max-h-full object-contain" />
          <button 
            className="absolute top-4 right-4 text-white text-2xl"
            aria-label={t(language, 'common.buttons.close')}
            onClick={(e) => {
              e.stopPropagation();
              setShowZoom(false);
            }}
          >
            {t(language, 'common.buttons.close')}
          </button>
        </div>
      )}
    </>
  );
}

'use client';

import type { MouseEvent } from 'react';
import { Heart } from 'lucide-react';
import { formatPrice, type CurrencyCode } from '../../../lib/currency';
import { t, getProductText } from '../../../lib/i18n';
import type { LanguageCode } from '../../../lib/language';
import { sanitizeHtml } from '../../../lib/utils/sanitize';
import { CompareIcon } from '../../../components/icons/CompareIcon';
import { ProductAttributesSelector } from './ProductAttributesSelector';
import type { Product, ProductVariant, AttributeGroupValue, VariantOption, ProductAttribute } from './types';

interface ProductInfoAndActionsProps {
  product: Product;
  price: number;
  originalPrice: number | null;
  compareAtPrice: number | null;
  discountPercent: number | null;
  currency: string;
  language: LanguageCode;
  averageRating: number;
  reviewsCount: number;
  quantity: number;
  maxQuantity: number;
  isOutOfStock: boolean;
  isVariationRequired: boolean;
  hasUnavailableAttributes: boolean;
  unavailableAttributes: Map<string, boolean>;
  canAddToCart: boolean;
  isAddingToCart: boolean;
  isInWishlist: boolean;
  isInCompare: boolean;
  showMessage: string | null;
  isLoggedIn: boolean;
  currentVariant: ProductVariant | null;
  attributeGroups: Map<string, AttributeGroupValue[]>;
  selectedColor: string | null;
  selectedSize: string | null;
  selectedAttributeValues: Map<string, string>;
  colorGroups: Array<{ color: string; stock: number; variants: ProductVariant[] }>;
  sizeGroups: Array<{ size: string; stock: number; variants: ProductVariant[] }>;
  onQuantityAdjust: (delta: number) => void;
  onAddToCart: () => Promise<void>;
  onAddToWishlist: (e: MouseEvent) => void;
  onCompareToggle: (e: MouseEvent) => void;
  onScrollToReviews: () => void;
  onColorSelect: (color: string) => void;
  onSizeSelect: (size: string) => void;
  onAttributeValueSelect: (attrKey: string, value: string) => void;
  getOptionValue: (options: VariantOption[] | undefined, key: string) => string | null;
  getRequiredAttributesMessage: () => string;
}

export function ProductInfoAndActions({
  product,
  price,
  originalPrice,
  compareAtPrice,
  discountPercent,
  currency,
  language,
  averageRating,
  reviewsCount,
  quantity,
  maxQuantity,
  isOutOfStock,
  isVariationRequired,
  hasUnavailableAttributes,
  unavailableAttributes,
  canAddToCart,
  isAddingToCart,
  isInWishlist,
  isInCompare,
  showMessage,
  isLoggedIn,
  currentVariant,
  attributeGroups,
  selectedColor,
  selectedSize,
  selectedAttributeValues,
  colorGroups,
  sizeGroups,
  onQuantityAdjust,
  onAddToCart,
  onAddToWishlist,
  onCompareToggle,
  onScrollToReviews,
  onColorSelect,
  onSizeSelect,
  onAttributeValueSelect,
  getOptionValue,
  getRequiredAttributesMessage,
}: ProductInfoAndActionsProps) {
  return (
    <div className="flex flex-col h-full">
      <div className="flex-1">
        {product.brand && <p className="text-sm text-gray-500 mb-2">{product.brand.name}</p>}
        <h1 className="text-4xl font-bold text-gray-900 mb-4">
          {getProductText(language, product.id, 'title') || product.title}
        </h1>
        <div className="mb-6">
          <div className="flex flex-col gap-1">
            {/* Discounted price with discount percentage */}
            <div className="flex items-center gap-2">
              <p className="text-3xl font-bold text-gray-900">{formatPrice(price, currency as CurrencyCode)}</p>
              {discountPercent && discountPercent > 0 && (
                <span className="text-lg font-semibold text-blue-600">
                  -{discountPercent}%
                </span>
              )}
            </div>
            {/* Original price below discounted price - full width, not inline */}
            {(originalPrice || (compareAtPrice && compareAtPrice > price)) && (
              <p className="text-xl text-gray-500 line-through decoration-gray-400 mt-1">
                {formatPrice(originalPrice || compareAtPrice || 0, currency as CurrencyCode)}
              </p>
            )}
          </div>
        </div>
        <div className="text-gray-600 mb-8 prose prose-sm" dangerouslySetInnerHTML={{ __html: sanitizeHtml(getProductText(language, product.id, 'longDescription') || product.description || '') }} />

        {/* Attributes Section */}
        <div className="mb-8">
          <ProductAttributesSelector
            product={product}
            attributeGroups={attributeGroups}
            selectedColor={selectedColor}
            selectedSize={selectedSize}
            selectedAttributeValues={selectedAttributeValues}
            unavailableAttributes={unavailableAttributes}
            colorGroups={colorGroups}
            sizeGroups={sizeGroups}
            language={language}
            quantity={quantity}
            maxQuantity={maxQuantity}
            isOutOfStock={isOutOfStock}
            isVariationRequired={isVariationRequired}
            hasUnavailableAttributes={hasUnavailableAttributes}
            canAddToCart={canAddToCart}
            isAddingToCart={isAddingToCart}
            showMessage={showMessage}
            onColorSelect={onColorSelect}
            onSizeSelect={onSizeSelect}
            onAttributeValueSelect={onAttributeValueSelect}
            onQuantityAdjust={onQuantityAdjust}
            onAddToCart={onAddToCart}
            getOptionValue={getOptionValue}
            getRequiredAttributesMessage={getRequiredAttributesMessage}
          />
        </div>

        {/* Rating Section */}
        <div className="mt-8 p-4 bg-white border border-gray-200 rounded-2xl space-y-4">
          <div className="flex items-center gap-2 pb-3 border-b border-gray-200">
            <div className="flex items-center gap-2">
              <div className="flex items-center gap-1">
                {[1, 2, 3, 4, 5].map((star) => (
                  <svg
                    key={star}
                    className={`w-5 h-5 ${
                      star <= Math.round(averageRating)
                        ? 'text-yellow-400'
                        : 'text-gray-300'
                    }`}
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                  </svg>
                ))}
              </div>
              <span className="text-sm font-semibold text-gray-900">
                {averageRating > 0 ? averageRating.toFixed(1) : '0.0'}
              </span>
            </div>
            <span 
              onClick={onScrollToReviews}
              className="text-sm text-gray-600 cursor-pointer hover:text-gray-900 hover:underline transition-colors"
            >
              ({reviewsCount} {reviewsCount === 1 ? t(language, 'common.reviews.review') : t(language, 'common.reviews.reviews')})
            </span>
          </div>
        </div>
      </div>
      
      {/* Action Buttons - Aligned with bottom of image */}
      <div className="mt-auto pt-6">
        {/* Show required attributes message if needed */}
        {isVariationRequired && (
          <div className="mb-3 p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
            <p className="text-sm text-yellow-800 font-medium">
              {getRequiredAttributesMessage()}
            </p>
          </div>
        )}
        {/* Show unavailable attributes message if needed */}
        {hasUnavailableAttributes && !isVariationRequired && (
          <div className="mb-3 p-3 bg-red-50 border border-red-200 rounded-lg">
            <p className="text-sm text-red-800 font-medium">
              {Array.from(unavailableAttributes.entries()).map(([attrKey]) => {
                const productAttr = product?.productAttributes?.find((pa: ProductAttribute) => pa.attribute?.key === attrKey);
                const attributeName = productAttr?.attribute?.name || attrKey.charAt(0).toUpperCase() + attrKey.slice(1);
                return attrKey === 'color' ? t(language, 'product.color') : 
                       attrKey === 'size' ? t(language, 'product.size') : 
                       attributeName;
              }).join(', ')} {t(language, 'product.outOfStock')}
            </p>
          </div>
        )}
        <div className="flex items-center gap-3 pt-4 border-t">
          <div className="flex items-center border rounded-xl overflow-hidden bg-gray-50">
            <button 
              onClick={() => onQuantityAdjust(-1)} 
              disabled={quantity <= 1}
              className="w-12 h-12 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
            >
              -
            </button>
            <div className="w-12 text-center font-bold">{quantity}</div>
            <button 
              onClick={() => onQuantityAdjust(1)} 
              disabled={quantity >= maxQuantity}
              className="w-12 h-12 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
            >
              +
            </button>
          </div>
          <button 
            disabled={!canAddToCart || isAddingToCart} 
            className="flex-1 h-12 bg-gray-900 text-white rounded-xl uppercase font-bold disabled:bg-gray-300 disabled:cursor-not-allowed"
            onClick={onAddToCart}
          >
            {isAddingToCart ? t(language, 'product.adding') : (isOutOfStock ? t(language, 'product.outOfStock') : (isVariationRequired ? getRequiredAttributesMessage() : (hasUnavailableAttributes ? t(language, 'product.outOfStock') : t(language, 'product.addToCart'))))}
          </button>
          <button 
            onClick={onCompareToggle} 
            className={`w-12 h-12 rounded-xl border-2 flex items-center justify-center transition-all duration-200 ${isInCompare ? 'border-gray-900 bg-gray-50' : 'border-gray-200 hover:border-gray-300'}`}
          >
            <CompareIcon isActive={isInCompare} />
          </button>
          <button 
            onClick={onAddToWishlist} 
            className={`w-12 h-12 rounded-xl border-2 flex items-center justify-center ${isInWishlist ? 'border-gray-900 bg-gray-50' : 'border-gray-200'}`}
          >
            <Heart fill={isInWishlist ? 'currentColor' : 'none'} />
          </button>
        </div>
      </div>
      {showMessage && <div className="mt-4 p-4 bg-gray-900 text-white rounded-md shadow-lg">{showMessage}</div>}
    </div>
  );
}

import { useState, useCallback, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { apiClient } from '../../../../lib/api-client';
import { getStoredLanguage } from '../../../../lib/language';
import { RESERVED_ROUTES } from '../types';
import type { Product } from '../types';

interface UseProductFetchProps {
  slug: string;
  variantIdFromUrl: string | null;
}

export function useProductFetch({
  slug,
  variantIdFromUrl,
}: UseProductFetchProps) {
  const router = useRouter();
  const [product, setProduct] = useState<Product | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchProduct = useCallback(async () => {
    if (!slug || RESERVED_ROUTES.includes(slug.toLowerCase())) return;
    
    try {
      setLoading(true);
      const currentLang = getStoredLanguage();
      let data: Product;
      
      try {
        data = await apiClient.get<Product>(`/api/v1/products/${slug}`, {
          params: { lang: currentLang }
        });
      } catch (error: unknown) {
        const errorStatus = error && typeof error === 'object' && 'status' in error ? Number(error.status) : undefined;
        if (errorStatus === 404 && currentLang !== 'en') {
          try {
            data = await apiClient.get<Product>(`/api/v1/products/${slug}`, {
              params: { lang: 'en' }
            });
          } catch {
            throw error;
          }
        } else {
          throw error;
        }
      }
      
      setProduct(data);
    } catch (error: unknown) {
      const err = error as { status?: number };
      if (err?.status === 404) {
        setProduct(null);
      }
    } finally {
      setLoading(false);
    }
  }, [slug, variantIdFromUrl]);

  useEffect(() => {
    if (!slug) return;
    if (RESERVED_ROUTES.includes(slug.toLowerCase())) {
      router.replace(`/${slug}`);
    }
  }, [slug, router]);

  useEffect(() => {
    if (!slug || RESERVED_ROUTES.includes(slug.toLowerCase())) return;
    fetchProduct();
    
    const handleLanguageUpdate = () => {
      fetchProduct();
    };
    
    window.addEventListener('language-updated', handleLanguageUpdate);
    return () => {
      window.removeEventListener('language-updated', handleLanguageUpdate);
    };
  }, [slug, variantIdFromUrl, router, fetchProduct]);

  return { product, loading, fetchProduct };
}

