import { useState, useEffect, useMemo } from 'react';
import type { Product, ProductVariant, AttributeGroupValue } from './types';
import type { LanguageCode } from '../../../lib/language';
import { t } from '../../../lib/i18n';

interface UseProductStockProps {
  currentVariant: ProductVariant | null;
  product: Product | null;
  attributeGroups: Map<string, AttributeGroupValue[]>;
  colorGroups: Array<{ color: string; stock: number; variants: ProductVariant[] }>;
  sizeGroups: Array<{ size: string; stock: number; variants: ProductVariant[] }>;
  selectedColor: string | null;
  selectedSize: string | null;
  language: LanguageCode;
}

interface UseProductStockReturn {
  quantity: number;
  setQuantity: (quantity: number | ((prev: number) => number)) => void;
  maxQuantity: number;
  isOutOfStock: boolean;
  unavailableAttributes: Map<string, boolean>;
  hasUnavailableAttributes: boolean;
  canAddToCart: boolean;
  adjustQuantity: (delta: number) => void;
  getRequiredAttributesMessage: () => string;
  isVariationRequired: boolean;
}

/**
 * Hook for managing product stock, quantity, and cart availability
 */
export function useProductStock({
  currentVariant,
  product,
  attributeGroups,
  colorGroups,
  sizeGroups,
  selectedColor,
  selectedSize,
  language,
}: UseProductStockProps): UseProductStockReturn {
  const [quantity, setQuantity] = useState(1);

  // Calculate max quantity based on current variant stock
  const maxQuantity = useMemo(() => {
    return currentVariant?.stock && currentVariant.stock > 0 ? currentVariant.stock : 0;
  }, [currentVariant?.stock]);

  // Check if current variant is out of stock
  const isOutOfStock = useMemo(() => {
    return !currentVariant || currentVariant.stock <= 0;
  }, [currentVariant]);

  // Check which attributes are available and required
  const hasColorAttribute = useMemo(() => {
    return colorGroups.length > 0 && colorGroups.some((g) => g.stock > 0);
  }, [colorGroups]);

  const hasSizeAttribute = useMemo(() => {
    return sizeGroups.length > 0 && sizeGroups.some((g) => g.stock > 0);
  }, [sizeGroups]);

  const needsColor = hasColorAttribute && !selectedColor;
  const needsSize = hasSizeAttribute && !selectedSize;
  const isVariationRequired = needsColor || needsSize;

  // Generate user-friendly message for required attributes
  const getRequiredAttributesMessage = (): string => {
    if (needsColor && needsSize) {
      return t(language, 'product.selectColorAndSize');
    } else if (needsColor) {
      return t(language, 'product.selectColor');
    } else if (needsSize) {
      return t(language, 'product.selectSize');
    }
    return t(language, 'product.selectOptions');
  };

  // Check if selected variant's attribute values have stock
  // Returns a map of attribute keys to whether they're unavailable (stock = 0)
  const unavailableAttributes = useMemo(() => {
    const unavailable = new Map<string, boolean>();

    if (!currentVariant || !product) return unavailable;

    // Check each attribute in the selected variant
    currentVariant.options?.forEach((option) => {
      const attrKey = option.key || option.attribute;
      if (!attrKey) return;

      // Get the attribute group for this attribute
      const attrGroup = attributeGroups.get(attrKey);
      if (!attrGroup) return;

      // Find the attribute value in the group that matches the variant's option
      const attrValue = attrGroup.find((g) => {
        if (option.valueId && g.valueId) {
          return g.valueId === option.valueId;
        }
        return g.value?.toLowerCase().trim() === option.value?.toLowerCase().trim();
      });

      // If attribute value found and has no stock, mark as unavailable
      if (attrValue && attrValue.stock <= 0) {
        unavailable.set(attrKey, true);
      }
    });

    return unavailable;
  }, [currentVariant, attributeGroups, product]);

  // Check if any attribute is unavailable
  const hasUnavailableAttributes = useMemo(() => {
    return unavailableAttributes.size > 0;
  }, [unavailableAttributes]);

  // Check if product can be added to cart
  const canAddToCart = useMemo(() => {
    return !isOutOfStock && !isVariationRequired && !hasUnavailableAttributes;
  }, [isOutOfStock, isVariationRequired, hasUnavailableAttributes]);

  // Update quantity when variant changes
  useEffect(() => {
    if (!currentVariant || currentVariant.stock <= 0) {
      setQuantity(0);
      return;
    }
    setQuantity((prev) => {
      const currentStock = currentVariant.stock;
      if (prev > currentStock) return currentStock;
      if (prev <= 0 && currentStock > 0) return 1;
      return prev;
    });
  }, [currentVariant?.id, currentVariant?.stock]);

  // Adjust quantity with validation
  const adjustQuantity = (delta: number) => {
    if (isOutOfStock || isVariationRequired) return;
    setQuantity((prev) => {
      const next = prev + delta;
      if (next < 1) return currentVariant && currentVariant.stock > 0 ? 1 : 0;
      return next > maxQuantity ? maxQuantity : next;
    });
  };

  return {
    quantity,
    setQuantity,
    maxQuantity,
    isOutOfStock,
    unavailableAttributes,
    hasUnavailableAttributes,
    canAddToCart,
    adjustQuantity,
    getRequiredAttributesMessage,
    isVariationRequired,
  };
}

import type { Product, ProductVariant, AttributeGroupValue } from '../types';
import { getCurrentSelections } from './variant-compatibility';
import { calculateStock } from './stock-calculator';
import { findAttributeValue } from './attribute-value-finder';

interface BuildGroupsFromProductAttributesProps {
  product: Product;
  selectedColor: string | null;
  selectedSize: string | null;
  selectedAttributeValues: Map<string, string>;
}

/**
 * Build attribute groups from productAttributes (new format)
 */
export function buildGroupsFromProductAttributes({
  product,
  selectedColor,
  selectedSize,
  selectedAttributeValues,
}: BuildGroupsFromProductAttributesProps): Map<string, AttributeGroupValue[]> {
  const groups = new Map<string, AttributeGroupValue[]>();

  if (!product.productAttributes || product.productAttributes.length === 0) {
    return groups;
  }

  product.productAttributes.forEach((productAttr) => {
    const attrKey = productAttr.attribute.key;
    const valueMap = new Map<
      string,
      { valueId?: string; value: string; label: string; variants: ProductVariant[] }
    >();

    // IMPORTANT: Show ALL attribute values, regardless of other selections
    // We don't filter variants here - we show all values that exist in any variant
    // Stock will be calculated separately based on current selections

    product.variants?.forEach((variant) => {
      // Include ALL variants - don't filter by compatibility
      // This ensures all attribute values are shown
      // IMPORTANT: Use filter() instead of find() to get ALL options for this attribute
      // A variant can have multiple values for the same attribute (e.g., color: [red, blue])

      const options =
        variant.options?.filter((opt) => {
          if (opt.valueId && opt.attributeId === productAttr.attribute.id) {
            return true;
          }
          return opt.key === attrKey || opt.attribute === attrKey;
        }) || [];

      // Process ALL options for this attribute (not just the first one)
      options.forEach((option) => {
        const valueId = option.valueId || '';
        const value = option.value || '';
        // Get label from AttributeValue if available, otherwise use value
        let label = option.value || '';
        if (valueId && productAttr.attribute.values) {
          const attrValue = (productAttr.attribute.values as Array<{ id?: string; label?: string; value?: string }>).find(
            (v) => v.id === valueId
          );
          if (attrValue) {
            label = attrValue.label || attrValue.value || value;
          }
        }

        const mapKey = valueId || value;
        if (!valueMap.has(mapKey)) {
          valueMap.set(mapKey, {
            valueId: valueId || undefined,
            value,
            label,
            variants: [],
          });
        }
        // Add variant to this value's variants list (avoid duplicates)
        if (!valueMap.get(mapKey)!.variants.some((v) => v.id === variant.id)) {
          valueMap.get(mapKey)!.variants.push(variant);
        }
      });
    });

    // Get current selections for stock calculation (excluding this attribute)
    const currentSelections = getCurrentSelections(
      attrKey,
      selectedColor,
      selectedSize,
      selectedAttributeValues
    );

    const groupsArray = Array.from(valueMap.values()).map((item) => {
      // Find the attribute value to get imageUrl and colors
      const attrValue = findAttributeValue(
        productAttr.attribute.values,
        item.valueId,
        item.value,
        item.label
      );

      // Calculate stock
      const stock = calculateStock(item.variants, currentSelections, attrKey);

      return {
        valueId: item.valueId,
        value: item.value,
        label: item.label,
        stock: stock,
        variants: item.variants,
        imageUrl: attrValue?.imageUrl || null,
        colors: attrValue?.colors || null,
      };
    });

    groups.set(attrKey, groupsArray);
  });

  // Also extract any additional attributes from variant options that might not be in productAttributes
  // This handles cases where attributes were added to variants but not yet synced to productAttributes
  if (product?.variants) {
    const allAttributeKeys = new Set<string>();

    // Collect all attribute keys from variant options
    product.variants.forEach((variant) => {
      variant.options?.forEach((opt) => {
        const attrKey = opt.key || opt.attribute || '';
        if (attrKey && attrKey !== 'color' && attrKey !== 'size') {
          allAttributeKeys.add(attrKey);
        }
      });
    });

    // For each attribute key not already in groups, create attribute group from variants
    allAttributeKeys.forEach((attrKey) => {
      if (!groups.has(attrKey)) {
        const valueMap = new Map<
          string,
          { valueId?: string; value: string; label: string; variants: ProductVariant[] }
        >();

        product.variants?.forEach((variant) => {
          const options =
            variant.options?.filter((opt) => opt.key === attrKey || opt.attribute === attrKey) ||
            [];

          // Process ALL options for this attribute (not just the first one)
          options.forEach((option) => {
            const valueId = option.valueId || '';
            const value = option.value || '';
            const label = option.value || '';

            const mapKey = valueId || value;
            if (!valueMap.has(mapKey)) {
              valueMap.set(mapKey, {
                valueId: valueId || undefined,
                value,
                label,
                variants: [],
              });
            }
            // Add variant to this value's variants list (avoid duplicates)
            if (!valueMap.get(mapKey)!.variants.some((v) => v.id === variant.id)) {
              valueMap.get(mapKey)!.variants.push(variant);
            }
          });
        });

        if (valueMap.size > 0) {
          // Try to find attribute values from productAttributes to get imageUrl
          const productAttr = product.productAttributes?.find(
            (pa: { attribute?: { key?: string } }) => pa.attribute?.key === attrKey
          );

          // Get current selections for stock calculation (excluding this attribute)
          const currentSelections = getCurrentSelections(
            attrKey,
            selectedColor,
            selectedSize,
            selectedAttributeValues
          );

          const groupsArray = Array.from(valueMap.values()).map((item) => {
            // Try to find attribute value to get imageUrl and colors
            const attrValue = productAttr?.attribute?.values
              ? findAttributeValue(
                  productAttr.attribute.values,
                  item.valueId,
                  item.value,
                  item.label
                )
              : null;

            // Calculate stock
            const stock = calculateStock(item.variants, currentSelections, attrKey);

            return {
              valueId: item.valueId,
              value: item.value,
              label: item.label,
              stock: stock,
              variants: item.variants,
              imageUrl: attrValue?.imageUrl || null,
              colors: attrValue?.colors || null,
            };
          });

          groups.set(attrKey, groupsArray);
        }
      }
    });
  }

  return groups;
}

import type { Product, ProductVariant, AttributeGroupValue } from '../types';
import { getCurrentSelections } from './variant-compatibility';
import { calculateStock } from './stock-calculator';

interface BuildGroupsFromVariantsProps {
  product: Product;
  selectedColor: string | null;
  selectedSize: string | null;
  selectedAttributeValues: Map<string, string>;
}

/**
 * Build attribute groups from variants (old format)
 */
export function buildGroupsFromVariants({
  product,
  selectedColor,
  selectedSize,
  selectedAttributeValues,
}: BuildGroupsFromVariantsProps): Map<string, AttributeGroupValue[]> {
  const groups = new Map<string, AttributeGroupValue[]>();

  if (!product?.variants) {
    return groups;
  }

  const colorMap = new Map<string, ProductVariant[]>();
  const sizeMap = new Map<string, ProductVariant[]>();
  const otherAttributesMap = new Map<string, Map<string, ProductVariant[]>>();

  // IMPORTANT: Show ALL attribute values, regardless of other selections
  // We don't filter variants here - we show all values that exist in any variant
  // Stock will be calculated separately based on current selections

  product.variants.forEach((variant) => {
    // For old format, show all variants (no filtering by compatibility)
    // This ensures all attribute values are shown
    // IMPORTANT: Process ALL options for each attribute, not just the first one
    // A variant can have multiple values for the same attribute (e.g., color: [red, blue])

    // Extract ALL color values (not just the first one)
    variant.options?.forEach((opt) => {
      const attrKey = opt.key || opt.attribute || '';
      const value = opt.value || '';

      if (!value) return;

      if (attrKey === 'color') {
        const normalizedColor = value.toLowerCase().trim();
        if (!colorMap.has(normalizedColor)) {
          colorMap.set(normalizedColor, []);
        }
        // Add variant to this color's variants list (avoid duplicates)
        if (!colorMap.get(normalizedColor)!.some((v) => v.id === variant.id)) {
          colorMap.get(normalizedColor)!.push(variant);
        }
      } else if (attrKey === 'size') {
        const normalizedSize = value.toLowerCase().trim();
        if (!sizeMap.has(normalizedSize)) {
          sizeMap.set(normalizedSize, []);
        }
        // Add variant to this size's variants list (avoid duplicates)
        if (!sizeMap.get(normalizedSize)!.some((v) => v.id === variant.id)) {
          sizeMap.get(normalizedSize)!.push(variant);
        }
      } else if (attrKey) {
        // Extract other attributes
        if (!otherAttributesMap.has(attrKey)) {
          otherAttributesMap.set(attrKey, new Map());
        }
        const valueMap = otherAttributesMap.get(attrKey)!;
        const normalizedValue = value.toLowerCase().trim();
        if (!valueMap.has(normalizedValue)) {
          valueMap.set(normalizedValue, []);
        }
        // Add variant to this value's variants list (avoid duplicates)
        if (!valueMap.get(normalizedValue)!.some((v) => v.id === variant.id)) {
          valueMap.get(normalizedValue)!.push(variant);
        }
      }
    });
  });

  // Get current selections for stock calculation
  const colorSelections = getCurrentSelections('color', selectedColor, selectedSize, selectedAttributeValues);
  const sizeSelections = getCurrentSelections('size', selectedColor, selectedSize, selectedAttributeValues);

  if (colorMap.size > 0) {
    groups.set(
      'color',
      Array.from(colorMap.entries()).map(([value, variants]) => {
        const stock = calculateStock(variants, colorSelections, 'color');
        return {
          value,
          label: value,
          stock: stock,
          variants,
        };
      })
    );
  }

  if (sizeMap.size > 0) {
    groups.set(
      'size',
      Array.from(sizeMap.entries()).map(([value, variants]) => {
        const stock = calculateStock(variants, sizeSelections, 'size');
        return {
          value,
          label: value,
          stock: stock,
          variants,
        };
      })
    );
  }

  // Add other attributes
  otherAttributesMap.forEach((valueMap, attrKey) => {
    const attrSelections = getCurrentSelections(attrKey, selectedColor, selectedSize, selectedAttributeValues);

    groups.set(
      attrKey,
      Array.from(valueMap.entries()).map(([value, variants]) => {
        const stock = calculateStock(variants, attrSelections, attrKey);
        return {
          value,
          label: value,
          stock: stock,
          variants,
          imageUrl: null,
          colors: null,
        };
      })
    );
  });

  return groups;
}

import type { Product, ProductVariant, VariantOption } from '../types';
import {
  processImageUrl,
  smartSplitUrls,
} from '../../../../lib/utils/image-utils';
import { variantHasColor } from './variant-helpers';
import { getOptionValue } from './variant-helpers';

/**
 * Helper function to normalize URLs for comparison
 */
function normalizeUrl(url: string): string {
  let normalized = url.trim();
  if (normalized.startsWith('/')) normalized = normalized.substring(1);
  if (normalized.endsWith('/'))
    normalized = normalized.substring(0, normalized.length - 1);
  return normalized.toLowerCase();
}

/**
 * Check if variant image is an attribute value image (these are excluded from gallery)
 */
function isAttributeValueImage(url: string, product: Product): boolean {
  if (!product.productAttributes) return false;

  for (const productAttr of product.productAttributes) {
    if (productAttr.attribute?.values) {
      for (const val of productAttr.attribute.values) {
        if (val.imageUrl) {
          const attrProcessed = processImageUrl(val.imageUrl);
          if (attrProcessed) {
            const normalizedAttr = normalizeUrl(attrProcessed);
            const normalizedVariant = normalizeUrl(url);
            if (normalizedAttr === normalizedVariant) {
              return true;
            }
          }
        }
      }
    }
  }
  return false;
}

/**
 * Find image index in images array by matching URL
 */
function findImageIndex(
  targetUrl: string,
  images: string[],
  processedTargetUrl: string
): number {
  return images.findIndex((img) => {
    if (!img) return false;

    const processedImg = processImageUrl(img);
    if (!processedImg) return false;

    const normalizedImg = normalizeUrl(processedImg);
    const normalizedTarget = normalizeUrl(processedTargetUrl);

    // Exact match after normalization
    if (normalizedImg === normalizedTarget) {
      return true;
    }

    // Match with/without leading slash
    const imgWithSlash = processedImg.startsWith('/')
      ? processedImg
      : `/${processedImg}`;
    const imgWithoutSlash = processedImg.startsWith('/')
      ? processedImg.substring(1)
      : processedImg;
    const targetWithSlash = processedTargetUrl.startsWith('/')
      ? processedTargetUrl
      : `/${processedTargetUrl}`;
    const targetWithoutSlash = processedTargetUrl.startsWith('/')
      ? processedTargetUrl.substring(1)
      : processedTargetUrl;

    if (
      imgWithSlash === targetWithSlash ||
      imgWithoutSlash === targetWithoutSlash ||
      imgWithSlash === targetWithoutSlash ||
      imgWithoutSlash === targetWithSlash
    ) {
      return true;
    }

    // Match by filename (for cases where paths differ but filename is same)
    if (!processedImg.startsWith('data:') && !processedTargetUrl.startsWith('data:')) {
      const imgFilename = processedImg.split('/').pop()?.toLowerCase().split('?')[0];
      const targetFilename = processedTargetUrl.split('/').pop()?.toLowerCase().split('?')[0];
      if (imgFilename && targetFilename && imgFilename === targetFilename) {
        return true;
      }
    }

    // For base64 images, compare directly
    if (processedImg.startsWith('data:') && processedTargetUrl.startsWith('data:')) {
      if (processedImg === processedTargetUrl) {
        return true;
      }
    }

    return false;
  });
}

/**
 * Switch to variant's image if it exists
 * This function finds the variant's image in the images array and switches to it
 * Note: If variant image matches an attribute value image, it won't be in the gallery,
 * so we won't switch to it (attribute value images are excluded from gallery)
 */
export function switchToVariantImage(
  variant: ProductVariant | null,
  product: Product | null,
  images: string[],
  setCurrentImageIndex: (index: number) => void
): void {
  if (!variant || !variant.imageUrl || !product) {
    return;
  }

  const splitUrls = smartSplitUrls(variant.imageUrl);
  if (splitUrls.length === 0) {
    return;
  }

  // Try to find the first variant image in the images array
  for (const url of splitUrls) {
    if (!url || url.trim() === '') continue;

    const processedUrl = processImageUrl(url);
    if (!processedUrl) {
      continue;
    }

    // If this variant image is an attribute value image, skip it
    if (isAttributeValueImage(processedUrl, product)) {
      continue;
    }

    const imageIndex = findImageIndex(url, images, processedUrl);

    if (imageIndex !== -1) {
      setCurrentImageIndex(imageIndex);
      return;
    }
  }

  // Fallback: If variant image not found, try to find any variant with the same color
  if (product?.variants) {
    const variantColor = getOptionValue(variant.options, 'color');
    if (variantColor) {
      const colorVariants = product.variants.filter((v) => {
        return variantHasColor(v, variantColor) && v.imageUrl;
      });

      // Try to find image from any variant with the same color
      for (const colorVariant of colorVariants) {
        if (!colorVariant.imageUrl) continue;

        const colorSplitUrls = smartSplitUrls(colorVariant.imageUrl);
        for (const colorUrl of colorSplitUrls) {
          if (!colorUrl || colorUrl.trim() === '') continue;

          const processedColorUrl = processImageUrl(colorUrl);
          if (!processedColorUrl) continue;

          // Skip attribute value images
          if (isAttributeValueImage(processedColorUrl, product)) continue;

          const colorImageIndex = findImageIndex(colorUrl, images, processedColorUrl);

          if (colorImageIndex !== -1) {
            setCurrentImageIndex(colorImageIndex);
            return;
          }
        }
      }
    }
  }
}

/**
 * Handle color selection and switch to variant image
 */
export function handleColorSelect(
  color: string,
  product: Product | null,
  images: string[],
  selectedColor: string | null,
  setSelectedColor: (color: string | null) => void,
  setCurrentImageIndex: (index: number) => void
): void {
  if (!color || !product) return;
  const normalizedColor = color.toLowerCase().trim();
  if (selectedColor === normalizedColor) {
    setSelectedColor(null);
  } else {
    setSelectedColor(normalizedColor);

    // Immediately try to find and switch to a variant image with this color
    const colorVariants =
      product.variants?.filter(
        (v) => variantHasColor(v, normalizedColor) && v.imageUrl
      ) || [];

    // Try to find image from variants with this color
    for (const variant of colorVariants) {
      if (!variant.imageUrl) continue;

      const splitUrls = smartSplitUrls(variant.imageUrl);
      for (const url of splitUrls) {
        if (!url || url.trim() === '') continue;

        const processedUrl = processImageUrl(url);
        if (!processedUrl) continue;

        const imageIndex = findImageIndex(url, images, processedUrl);

        if (imageIndex !== -1) {
          setCurrentImageIndex(imageIndex);
          return; // Found and switched, exit early
        }
      }
    }
  }
}

import type { ProductVariant, VariantOption } from '../types';

/**
 * Check if a variant is compatible with currently selected attributes
 * This is used to filter which attribute values to show based on current selections
 * IMPORTANT: A variant can have multiple values for the same attribute (e.g., color: [red, blue, yellow])
 * So we need to check ALL options, not just the first one
 */
export function isVariantCompatible(
  variant: ProductVariant,
  currentSelections: Map<string, string>,
  excludeAttrKey?: string
): boolean {
  // If no selections, all variants are compatible
  if (currentSelections.size === 0) return true;

  // Check each selected attribute (excluding the one we're building)
  for (const [attrKey, selectedValue] of currentSelections.entries()) {
    // Skip the attribute we're currently building
    if (excludeAttrKey && attrKey === excludeAttrKey) {
      continue;
    }

    // IMPORTANT: Check ALL options for this attribute, not just the first one
    // A variant can have multiple values for the same attribute
    const normalizedSelectedValue = selectedValue.toLowerCase().trim();
    let hasMatchingValue = false;

    // Check all options for this attribute
    const matchingOptions =
      variant.options?.filter((opt) => {
        const optKey = opt.key || opt.attribute;
        return optKey === attrKey;
      }) || [];

    if (matchingOptions.length === 0) {
      // Variant doesn't have this attribute, so it's not compatible
      return false;
    }

    // Check if any of the options match the selected value
    for (const option of matchingOptions) {
      const optValue = option.value?.toLowerCase().trim();
      const optValueId = option.valueId;

      // Match by value (case-insensitive)
      if (optValue === normalizedSelectedValue) {
        hasMatchingValue = true;
        break;
      }

      // Match by valueId
      if (optValueId && optValueId === selectedValue) {
        hasMatchingValue = true;
        break;
      }
    }

    // If no matching value found, variant is not compatible
    if (!hasMatchingValue) {
      return false;
    }
  }
  return true; // All selected attributes match
}

/**
 * Get currently selected attributes (excluding the attribute we're building)
 */
export function getCurrentSelections(
  excludeAttrKey: string,
  selectedColor: string | null,
  selectedSize: string | null,
  selectedAttributeValues: Map<string, string>
): Map<string, string> {
  const selections = new Map<string, string>();
  if (selectedColor && excludeAttrKey !== 'color') {
    selections.set('color', selectedColor);
  }
  if (selectedSize && excludeAttrKey !== 'size') {
    selections.set('size', selectedSize);
  }
  selectedAttributeValues.forEach((value, key) => {
    if (key !== excludeAttrKey) {
      selections.set(key, value);
    }
  });
  return selections;
}

import type { Product, ProductVariant, VariantOption } from '../types';
import { variantHasColor } from './variant-helpers';
import { getOptionValue } from './variant-helpers';

/**
 * Find variant by color and size
 * @param product - Product to search in
 * @param color - Color value to match
 * @param size - Size value to match
 * @returns Matching variant or null
 */
export function findVariantByColorAndSize(
  product: Product | null,
  color: string | null,
  size: string | null
): ProductVariant | null {
  if (!product?.variants || product.variants.length === 0) return null;

  const normalizedColor = color?.toLowerCase().trim();
  const normalizedSize = size?.toLowerCase().trim();

  // 1. Try exact match (Case-insensitive)
  // IMPORTANT: Use variantHasColor to check ALL color options, not just the first one
  if (normalizedColor && normalizedSize) {
    const variant = product.variants.find((v) => {
      const hasColor = variantHasColor(v, normalizedColor);
      const vSize = getOptionValue(v.options, 'size');
      return hasColor && vSize === normalizedSize;
    });
    if (variant) return variant;
  }

  // 2. If color selected but no exact match with size, find any variant of this color
  if (normalizedColor) {
    // Prefer in-stock variant of this color
    // IMPORTANT: Use variantHasColor to check ALL color options
    const colorVariants = product.variants.filter((v) =>
      variantHasColor(v, normalizedColor)
    );

    if (colorVariants.length > 0) {
      return colorVariants.find((v) => v.stock > 0) || colorVariants[0];
    }
  }

  // 3. If only size selected or fallback for size
  if (normalizedSize) {
    const sizeVariants = product.variants.filter((v) => {
      const vSize = getOptionValue(v.options, 'size');
      return vSize === normalizedSize;
    });

    if (sizeVariants.length > 0) {
      return sizeVariants.find((v) => v.stock > 0) || sizeVariants[0];
    }
  }

  // 4. Ultimate fallback
  return product.variants.find((v) => v.stock > 0) || product.variants[0] || null;
}

/**
 * Find variant by all selected attributes (color, size, and other attributes)
 * This function considers all selected attribute values to find the best matching variant
 * @param product - Product to search in
 * @param color - Color value to match
 * @param size - Size value to match
 * @param otherAttributes - Map of other attribute key-value pairs
 * @returns Matching variant or null
 */
export function findVariantByAllAttributes(
  product: Product | null,
  color: string | null,
  size: string | null,
  otherAttributes: Map<string, string>
): ProductVariant | null {
  if (!product?.variants || product.variants.length === 0) return null;

  const normalizedColor = color?.toLowerCase().trim();
  const normalizedSize = size?.toLowerCase().trim();

  // Build a map of all selected attributes (including color and size)
  const allSelectedAttributes = new Map<string, string>();
  if (normalizedColor) allSelectedAttributes.set('color', normalizedColor);
  if (normalizedSize) allSelectedAttributes.set('size', normalizedSize);
  otherAttributes.forEach((value, key) => {
    if (key !== 'color' && key !== 'size') {
      allSelectedAttributes.set(key, value.toLowerCase().trim());
    }
  });

  // Helper to check if a variant matches all selected attributes
  const variantMatches = (variant: ProductVariant): boolean => {
    // Check color - IMPORTANT: Use variantHasColor to check ALL color options
    if (normalizedColor) {
      if (!variantHasColor(variant, normalizedColor)) return false;
    }

    // Check size
    if (normalizedSize) {
      const vSize = getOptionValue(variant.options, 'size');
      if (vSize !== normalizedSize) return false;
    }

    // Check other attributes
    for (const [attrKey, attrValue] of otherAttributes.entries()) {
      if (attrKey === 'color' || attrKey === 'size') continue;

      const variantValue = getOptionValue(variant.options, attrKey);
      const normalizedAttrValue = attrValue.toLowerCase().trim();

      // Try matching by valueId first (if available)
      const option = variant.options?.find(
        (opt) => opt.key === attrKey || opt.attribute === attrKey
      );

      if (option) {
        // Check by valueId if both have it
        if (option.valueId && attrValue) {
          // If the selected value is an ID, match by ID
          if (option.valueId === attrValue) {
            continue;
          }
        }

        // Fallback to value matching
        if (variantValue !== normalizedAttrValue) {
          return false;
        }
      } else {
        return false;
      }
    }

    return true;
  };

  // 1. Try to find exact match with all attributes
  const exactMatch = product.variants.find(
    (v) => variantMatches(v) && v.imageUrl
  );
  if (exactMatch) {
    return exactMatch;
  }

  // 2. Try to find any match (even without image) with all attributes
  const anyMatch = product.variants.find((v) => variantMatches(v));
  if (anyMatch) {
    return anyMatch;
  }

  // 3. Fallback: find by color and size only
  if (normalizedColor || normalizedSize) {
    return findVariantByColorAndSize(
      product,
      normalizedColor || null,
      normalizedSize || null
    );
  }

  // 4. Ultimate fallback
  return product.variants.find((v) => v.stock > 0) || product.variants[0] || null;
}

import Link from 'next/link';
import { Suspense } from 'react';
import { Button } from '@shop/ui';
import { apiClient } from '../../lib/api-client';
import { getStoredLanguage } from '../../lib/language';
import { t } from '../../lib/i18n';
import { PriceFilter } from '../../components/PriceFilter';
import { ColorFilter } from '../../components/ColorFilter';
import { SizeFilter } from '../../components/SizeFilter';
import { BrandFilter } from '../../components/BrandFilter';
import { ProductsHeader } from '../../components/ProductsHeader';
import { ProductsGrid } from '../../components/ProductsGrid';
import { CategoryNavigation } from '../../components/CategoryNavigation';
import { MobileFiltersDrawer } from '../../components/MobileFiltersDrawer';
import { ProductsFiltersProvider } from '../../components/ProductsFiltersProvider';
import { MOBILE_FILTERS_EVENT } from '../../lib/events';

const PAGE_CONTAINER = 'max-w-7xl mx-auto px-4 sm:px-6 lg:px-8';
// Container for filters section to align with Header logo (same Y-axis)
// Header logo uses: pl-2 sm:pl-4 md:pl-6 lg:pl-8

interface Product {
  id: string;
  slug: string;
  title: string;
  price: number;
  compareAtPrice: number | null;
  image: string | null;
  inStock: boolean;
  brand: {
    id: string;
    name: string;
  } | null;
  labels?: Array<{
    id: string;
    type: 'text' | 'percentage';
    value: string;
    position: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
    color: string | null;
  }>;
}

interface ProductsResponse {
  data: Product[];
  meta: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  };
}

/** API may return extra fields; we normalize below. */
interface ProductListApiRow extends Partial<Product> {
  id: string;
  slug: string;
  title: string;
  price: number;
  originalPrice?: number | null;
  defaultVariantId?: string | null;
  colors?: unknown;
}

type ProductsPageSearchParams = Promise<Record<string, string | string[] | undefined>>;

function firstSearchParam(value: string | string[] | undefined): string | undefined {
  if (value === undefined) return undefined;
  return Array.isArray(value) ? value[0] : value;
}

/**
 * Fetch products (PRODUCTION SAFE)
 */
async function getProducts(
  page: number = 1,
  search?: string,
  category?: string,
  minPrice?: string,
  maxPrice?: string,
  colors?: string,
  sizes?: string,
  brand?: string,
  limit: number = 12
): Promise<ProductsResponse> {
  try {
    const language = getStoredLanguage();
    const params: Record<string, string> = {
      page: page.toString(),
      limit: limit.toString(),
      lang: language,
    };

    if (search?.trim()) params.search = search.trim();
    if (category?.trim()) params.category = category.trim();
    if (minPrice?.trim()) params.minPrice = minPrice.trim();
    if (maxPrice?.trim()) params.maxPrice = maxPrice.trim();
    if (colors?.trim()) params.colors = colors.trim();
    if (sizes?.trim()) params.sizes = sizes.trim();
    if (brand?.trim()) params.brand = brand.trim();

    const queryString = new URLSearchParams(params).toString();

    // Fallback chain: NEXT_PUBLIC_APP_URL -> VERCEL_URL -> localhost (for local dev)
    const baseUrl =
      process.env.NEXT_PUBLIC_APP_URL ||
      (process.env.VERCEL_URL ? `https://${process.env.VERCEL_URL}` : "http://localhost:3000");

    const targetUrl = `${baseUrl}/api/v1/products?${queryString}`;
    const res = await fetch(targetUrl, {
      cache: "no-store"
    });

    if (!res.ok) throw new Error(`API failed: ${res.status}`);

    const response = await res.json();
    if (!response.data || !Array.isArray(response.data)) {
      return {
        data: [],
        meta: { total: 0, page: 1, limit: 12, totalPages: 0 }
      };
    }

    return response;

  } catch (e) {
    console.error("❌ PRODUCT ERROR", e);
    return {
      data: [],
      meta: { total: 0, page: 1, limit: 12, totalPages: 0 }
    };
  }
}

/**
 * PAGE
 */
export default async function ProductsPage({
  searchParams,
}: {
  searchParams?: ProductsPageSearchParams;
}) {
  const params = searchParams ? await searchParams : {};
  const page = parseInt(firstSearchParam(params.page) || "1", 10);
  const limitParam = firstSearchParam(params.limit)?.toString().trim();
  const categoryParam = firstSearchParam(params.category);
  const searchParam = firstSearchParam(params.search);
  const minPriceParam = firstSearchParam(params.minPrice);
  const maxPriceParam = firstSearchParam(params.maxPrice);
  const colorsParam = firstSearchParam(params.colors);
  const sizesParam = firstSearchParam(params.sizes);
  const brandParam = firstSearchParam(params.brand);
  const sortParam = firstSearchParam(params.sort);
  const parsedLimit = limitParam && !Number.isNaN(parseInt(limitParam, 10))
    ? parseInt(limitParam, 10)
    : null;
  const perPage = parsedLimit ? Math.min(parsedLimit, 200) : 12;

  const productsData = await getProducts(
    page,
    firstSearchParam(params.search),
    firstSearchParam(params.category),
    firstSearchParam(params.minPrice),
    firstSearchParam(params.maxPrice),
    firstSearchParam(params.colors),
    firstSearchParam(params.sizes),
    firstSearchParam(params.brand),
    perPage
  );

  // ------------------------------------
  // 🔧 FIX: normalize products 
  // add missing inStock, missing image fields 
  // ------------------------------------
  const normalizedProducts = productsData.data.map((p: ProductListApiRow) => ({
    id: p.id,
    slug: p.slug,
    title: p.title,
    price: p.price,
    compareAtPrice: p.compareAtPrice ?? p.originalPrice ?? null,
    image: p.image ?? null,
    inStock: p.inStock ?? true,      // ⭐ FIXED
    brand: p.brand ?? null,
    defaultVariantId: p.defaultVariantId ?? null,
    colors: Array.isArray(p.colors) ? (p.colors as string[]) : [],
    labels: Array.isArray(p.labels) ? p.labels : [],
  }));

  // FILTERS
  const selectedColors = colorsParam ? colorsParam.split(',').map((c: string) => c.trim().toLowerCase()) : [];
  const selectedSizes = sizesParam ? sizesParam.split(',').map((s: string) => s.trim()) : [];
  const selectedBrands = brandParam ? brandParam.split(',').map((b: string) => b.trim()) : [];

  // PAGINATION: 12 per page by default, preserve limit in URLs
  const buildPaginationUrl = (num: number) => {
    const q = new URLSearchParams();
    q.set("page", num.toString());
    const currentLimit = firstSearchParam(params.limit) ?? "12";
    q.set("limit", currentLimit);
    Object.entries(params).forEach(([k, v]) => {
      if (k === "page" || k === "limit") return;
      const s = Array.isArray(v) ? v[0] : v;
      if (s && typeof s === "string") q.set(k, s);
    });
    return `/products?${q.toString()}`;
  };

  /** Page numbers (and ellipsis) to show in pagination */
  const getPaginationPages = (): (number | "ellipsis")[] => {
    const total = productsData.meta.totalPages;
    const current = page;
    if (total <= 7) {
      return Array.from({ length: total }, (_, i) => i + 1);
    }
    const set = new Set<number>([1, total, current - 1, current, current + 1]);
    const sorted = Array.from(set).filter((p) => p >= 1 && p <= total).sort((a, b) => a - b);
    const out: (number | "ellipsis")[] = [];
    for (let i = 0; i < sorted.length; i++) {
      if (i > 0 && sorted[i]! - sorted[i - 1]! > 1) out.push("ellipsis");
      out.push(sorted[i]!);
    }
    return out;
  };

  // Get language for translations
  const language = getStoredLanguage();

  return (
    <div className="w-full overflow-x-hidden max-w-full">
      {/* Category Navigation - Full Width */}
      <CategoryNavigation />
      
      {/* Products Header - With Container */}
      <div className={PAGE_CONTAINER}>
        <ProductsHeader
          total={productsData.meta.total}
          perPage={productsData.meta.limit}
        />
      </div>

      <div className="max-w-7xl mx-auto pl-2 sm:pl-4 md:pl-6 lg:pl-8 pr-4 sm:pr-6 lg:pr-8 flex flex-col lg:flex-row gap-8">
        <ProductsFiltersProvider
          category={categoryParam}
          search={searchParam}
          minPrice={minPriceParam}
          maxPrice={maxPriceParam}
        >
        <aside className="w-64 hidden lg:block bg-gray-50 rounded-xl flex-shrink-0">
          <div className="sticky top-4 p-4 space-y-6">
            <Suspense fallback={<div>{t(language, 'common.messages.loadingFilters')}</div>}>
              <PriceFilter currentMinPrice={minPriceParam} currentMaxPrice={maxPriceParam} category={categoryParam} search={searchParam} />
              <ColorFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedColors={selectedColors} />
              <SizeFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedSizes={selectedSizes} />
              <BrandFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedBrands={selectedBrands} />
            </Suspense>
          </div>
        </aside>

        <div className="flex-1 min-w-0 w-full lg:w-auto py-4 overflow-x-hidden">

          {normalizedProducts.length > 0 ? (
            <>
              <ProductsGrid products={normalizedProducts} sortBy={sortParam || "default"} />

              {productsData.meta.totalPages > 1 && (
                <nav
                  className="mt-10 flex flex-wrap items-center justify-center gap-2"
                  aria-label="Pagination"
                >
                  {page > 1 ? (
                    <Link href={buildPaginationUrl(page - 1)}>
                      <Button
                        variant="outline"
                        className="min-w-[90px] rounded-lg border-neutral-300 bg-white px-4 py-2 text-sm font-medium text-neutral-700 shadow-sm transition hover:border-neutral-400 hover:bg-neutral-50"
                      >
                        {t(language, 'common.pagination.previous')}
                      </Button>
                    </Link>
                  ) : (
                    <span className="min-w-[90px] rounded-lg border border-neutral-200 bg-neutral-50 px-4 py-2 text-center text-sm font-medium text-neutral-400">
                      {t(language, 'common.pagination.previous')}
                    </span>
                  )}

                  <div className="flex items-center gap-1">
                    {getPaginationPages().map((item, idx) =>
                      item === "ellipsis" ? (
                        <span key={`ellipsis-${idx}`} className="px-2 text-neutral-400" aria-hidden>
                          …
                        </span>
                      ) : (
                        <span key={item}>
                          {item === page ? (
                            <span
                              className="flex h-9 min-w-[2.25rem] items-center justify-center rounded-lg bg-neutral-800 px-3 py-1.5 text-sm font-semibold text-white shadow-sm"
                              aria-current="page"
                            >
                              {item}
                            </span>
                          ) : (
                            <Link
                              href={buildPaginationUrl(item)}
                              className="flex h-9 min-w-[2.25rem] items-center justify-center rounded-lg border border-neutral-300 bg-white px-3 py-1.5 text-sm font-medium text-neutral-700 shadow-sm transition hover:border-neutral-400 hover:bg-neutral-50"
                            >
                              {item}
                            </Link>
                          )}
                        </span>
                      )
                    )}
                  </div>

                  {page < productsData.meta.totalPages ? (
                    <Link href={buildPaginationUrl(page + 1)}>
                      <Button
                        variant="outline"
                        className="min-w-[90px] rounded-lg border-neutral-300 bg-white px-4 py-2 text-sm font-medium text-neutral-700 shadow-sm transition hover:border-neutral-400 hover:bg-neutral-50"
                      >
                        {t(language, 'common.pagination.next')}
                      </Button>
                    </Link>
                  ) : (
                    <span className="min-w-[90px] rounded-lg border border-neutral-200 bg-neutral-50 px-4 py-2 text-center text-sm font-medium text-neutral-400">
                      {t(language, 'common.pagination.next')}
                    </span>
                  )}
                </nav>
              )}
            </>
          ) : (
            <div className="text-center py-12">
              <p className="text-gray-500 text-lg">{t(language, 'common.messages.noProductsFound')}</p>
            </div>
          )}

        </div>

      {/* Mobile Filters Drawer */}
      <MobileFiltersDrawer openEventName={MOBILE_FILTERS_EVENT}>
        <div className="p-4 space-y-6">
          <Suspense fallback={<div>{t(language, 'common.messages.loadingFilters')}</div>}>
            <PriceFilter currentMinPrice={minPriceParam} currentMaxPrice={maxPriceParam} category={categoryParam} search={searchParam} />
            <ColorFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedColors={selectedColors} />
            <SizeFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedSizes={selectedSizes} />
            <BrandFilter category={categoryParam} search={searchParam} minPrice={minPriceParam} maxPrice={maxPriceParam} selectedBrands={selectedBrands} />
          </Suspense>
        </div>
      </MobileFiltersDrawer>
        </ProductsFiltersProvider>
      </div>
    </div>
  );
}

