'use client';

import { useState, useEffect } from 'react';
import { apiClient } from '../../../lib/api-client';
import { getStoredLanguage } from '../../../lib/language';
import type { Category } from '../utils';

interface Product {
  id: string;
  slug: string;
  title: string;
  image: string | null;
}

interface ProductsResponse {
  data: Product[];
  meta: {
    total: number;
  };
}

/**
 * Hook for fetching first product with image for each category
 */
export function useCategoryProducts(categories: Category[], t: (path: string) => string) {
  const [categoryProducts, setCategoryProducts] = useState<Record<string, Product | null>>({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (categories.length === 0) {
      setLoading(false);
      return;
    }

    const fetchCategoryProducts = async () => {
      try {
        setLoading(true);
        const language = getStoredLanguage();
        const products: Record<string, Product | null> = {};
        
        // Add "All" category
        const allCategoriesWithAll = [
          { id: 'all', slug: 'all', title: t('products.categoryNavigation.all'), fullPath: 'all', children: [] } as Category,
          ...categories
        ];

        // Fetch products for each category
        const categoryPromises = allCategoriesWithAll.map(async (category) => {
          try {
            const params: Record<string, string> = {
              limit: '5',
              lang: language,
            };
            if (category.slug !== 'all') {
              params.category = category.slug;
            }

            console.log(`🔍 [CategoryNavigation] Fetching products for category: "${category.title}" (slug: "${category.slug}")`, params);
            const productsResponse = await apiClient.get<ProductsResponse>('/api/v1/products', {
              params,
            });
            
            console.log(`📦 [CategoryNavigation] Response for "${category.title}":`, {
              total: productsResponse.meta?.total || 0,
              productsCount: productsResponse.data?.length || 0,
              firstProductId: productsResponse.data?.[0]?.id,
              firstProductImage: productsResponse.data?.[0]?.image,
            });
            
            // If category has 0 products, it might mean category was not found
            if (productsResponse.meta?.total === 0 && category.slug !== 'all') {
              console.warn(`⚠️ [CategoryNavigation] Category "${category.title}" (${category.slug}) has 0 products - category might not exist in database`);
            }
            
            // Get first product with image
            const productWithImage = productsResponse.data && productsResponse.data.length > 0
              ? (productsResponse.data.find(p => p.image) || productsResponse.data[0] || null)
              : null;
            products[category.slug] = productWithImage;
            
            console.log(`✅ [CategoryNavigation] Category "${category.title}" (${category.slug}): selected product: ${productWithImage?.id} (image: ${productWithImage?.image ? 'yes' : 'no'})`);
          } catch (err) {
            console.error(`❌ [CategoryNavigation] Error fetching product for category ${category.slug}:`, err);
            products[category.slug] = null;
          }
        });

        await Promise.all(categoryPromises);
        setCategoryProducts(products);
        
        // Log final state to verify each category has unique product
        console.log('✅ [CategoryNavigation] All categories processed');
        console.log('📊 [CategoryNavigation] Final category products mapping:', 
          Object.entries(products).map(([slug, product]) => ({
            slug,
            productId: product?.id || 'null',
            productImage: product?.image || 'null',
          }))
        );
        
        // Check for duplicate products
        const productIds = Object.values(products).map(p => p?.id).filter(Boolean);
        const uniqueProductIds = new Set(productIds);
        if (productIds.length !== uniqueProductIds.size) {
          console.warn('⚠️ [CategoryNavigation] WARNING: Some categories have the same product!', {
            totalProducts: productIds.length,
            uniqueProducts: uniqueProductIds.size,
            duplicates: productIds.filter((id, index) => productIds.indexOf(id) !== index)
          });
        }
      } catch (err) {
        console.error('Error fetching category products:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchCategoryProducts();
  }, [categories, t]);

  return { categoryProducts, loading };
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';

/**
 * Hook for managing category navigation scroll state
 */
export function useCategoryScroll() {
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(false);

  const updateScrollButtons = useCallback(() => {
    const container = scrollContainerRef.current;
    if (!container) {
      console.warn('[CategoryNavigation] Container not found for updateScrollButtons');
      return;
    }

    const scrollLeft = container.scrollLeft;
    const scrollWidth = container.scrollWidth;
    const clientWidth = container.clientWidth;
    
    const canLeft = scrollLeft > 8;
    const canRight = scrollLeft + clientWidth < scrollWidth - 8;

    console.info('[CategoryNavigation] Update scroll buttons:', {
      scrollLeft,
      scrollWidth,
      clientWidth,
      canLeft,
      canRight
    });

    setCanScrollLeft(canLeft);
    setCanScrollRight(canRight);
  }, []);

  useEffect(() => {
    const container = scrollContainerRef.current;
    if (!container) return;

    const handleResize = () => {
      // Небольшая задержка для корректного расчета размеров после ресайза
      setTimeout(() => updateScrollButtons(), 100);
    };
    
    const handleScroll = () => {
      updateScrollButtons();
    };
    
    container.addEventListener('scroll', handleScroll);
    window.addEventListener('resize', handleResize);
    
    // Инициализация с небольшой задержкой для корректного расчета размеров
    setTimeout(() => {
      updateScrollButtons();
    }, 100);

    return () => {
      container.removeEventListener('scroll', handleScroll);
      window.removeEventListener('resize', handleResize);
    };
  }, [updateScrollButtons]);

  const scrollByAmount = (amount: number) => {
    const container = scrollContainerRef.current;
    if (!container) {
      console.warn('[CategoryNavigation] Container not found for scrolling');
      return;
    }
    
    const scrollLeftBefore = container.scrollLeft;
    console.info('[CategoryNavigation] Scrolling:', { 
      direction: amount > 0 ? 'right' : 'left', 
      amount, 
      scrollLeftBefore,
      scrollWidth: container.scrollWidth,
      clientWidth: container.clientWidth
    });
    
    container.scrollBy({ left: amount, behavior: 'smooth' });
    
    // Обновляем состояние после небольшой задержки для плавной прокрутки
    setTimeout(() => {
      updateScrollButtons();
    }, 100);
  };

  return {
    scrollContainerRef,
    canScrollLeft,
    canScrollRight,
    scrollByAmount,
    updateScrollButtons,
  };
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Card } from '@shop/ui';
import { apiClient } from '../lib/api-client';
import { getStoredLanguage } from '../lib/language';
import { getColorHex } from '../lib/colorMap';
import { useTranslation } from '../lib/i18n-client';
import { useProductsFilters } from './ProductsFiltersProvider';

interface ColorFilterProps {
  category?: string;
  search?: string;
  minPrice?: string;
  maxPrice?: string;
  selectedColors?: string[];
}

export interface ColorOption {
  value: string;
  label: string;
  count: number;
  imageUrl?: string | null;
  colors?: string[] | null;
}

export function ColorFilter({ category, search, minPrice, maxPrice, selectedColors = [] }: ColorFilterProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const filtersContext = useProductsFilters();
  const { t } = useTranslation();
  const [colors, setColors] = useState<ColorOption[]>([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<string[]>(selectedColors);

  useEffect(() => {
    if (filtersContext?.data?.colors) {
      setColors(filtersContext.data.colors);
      setLoading(false);
      return;
    }
    if (filtersContext === null) {
      fetchColors();
    } else {
      setLoading(filtersContext.loading);
    }
  }, [category, search, minPrice, maxPrice, filtersContext?.data?.colors, filtersContext?.loading, filtersContext === null]);

  useEffect(() => {
    setSelected(selectedColors);
  }, [selectedColors]);

  const fetchColors = async () => {
    try {
      setLoading(true);
      const language = getStoredLanguage();
      const params: Record<string, string> = {
        lang: language,
      };
      
      if (category) params.category = category;
      if (search) params.search = search;
      if (minPrice) params.minPrice = minPrice;
      if (maxPrice) params.maxPrice = maxPrice;

      // Fetch filters from API
      const response = await apiClient.get<{
        colors: ColorOption[];
        sizes: { value: string; count: number }[];
      }>('/api/v1/products/filters', { params });
      
      setColors(response.colors || []);
    } catch (error) {
      setColors([]);
    } finally {
      setLoading(false);
    }
  };

  const handleColorToggle = (colorValue: string) => {
    const newSelected = selected.includes(colorValue)
      ? selected.filter((c) => c !== colorValue)
      : [...selected, colorValue];

    setSelected(newSelected);
    applyFilters(newSelected);
  };

  const applyFilters = (colorsToApply: string[]) => {
    // Ստեղծում ենք նոր URLSearchParams URL-ի հիման վրա, որպեսզի պահպանենք բոլոր params-ները
    const params = new URLSearchParams(searchParams.toString());
    
    // Թարմացնում ենք colors պարամետրը
    if (colorsToApply.length > 0) {
      params.set('colors', colorsToApply.join(','));
    } else {
      params.delete('colors');
    }
    
    // Reset page to 1 when filters change
    params.delete('page');

    router.push(`/products?${params.toString()}`);
  };

  if (loading) {
    return (
      <Card className="p-4 mb-6">
        <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.color.title')}</h3>
        <div className="text-sm text-gray-500">{t('products.filters.color.loading')}</div>
      </Card>
    );
  }

  return (
    <Card className="p-4 mb-6">
      <h3 className="text-base font-bold text-gray-800 mb-4 uppercase tracking-wide">{t('products.filters.color.title')}</h3>
      {colors.length === 0 ? (
        <div className="text-sm text-gray-500 py-4 text-center">
          {t('products.filters.color.noColors')}
        </div>
      ) : (
        <div className="space-y-2 max-h-64 overflow-y-auto">
          {colors.map((color) => {
            const isSelected = selected.includes(color.value);
            // Determine color hex: use colors[0] if available, otherwise use getColorHex
            const colorHex = color.colors && Array.isArray(color.colors) && color.colors.length > 0 
              ? color.colors[0] 
              : getColorHex(color.label);
            const hasImage = color.imageUrl && color.imageUrl.trim() !== '';

            return (
              <button
                key={color.value}
                type="button"
                onClick={() => handleColorToggle(color.value)}
                aria-pressed={isSelected}
                className={`w-full flex items-center justify-between py-2 px-1 rounded transition-colors group ${
                  isSelected
                    ? 'bg-blue-50 hover:bg-blue-100 border border-blue-200'
                    : 'hover:bg-gray-50'
                }`}
              >
                <div className="flex items-center gap-3">
                  <div
                    className={`w-4 h-4 rounded-full border flex-shrink-0 overflow-hidden ${
                      isSelected ? 'border-blue-500 border-2' : 'border-gray-300'
                    }`}
                    style={hasImage ? {} : { backgroundColor: colorHex }}
                    aria-label={color.label}
                  >
                    {hasImage ? (
                      <img 
                        src={color.imageUrl!} 
                        alt={color.label}
                        className="w-full h-full object-cover"
                        onError={(e) => {
                          // Fallback to color hex if image fails to load
                          (e.target as HTMLImageElement).style.backgroundColor = colorHex;
                          (e.target as HTMLImageElement).style.display = 'none';
                        }}
                      />
                    ) : null}
                  </div>
                  <span
                    className={`text-sm group-hover:text-gray-700 ${
                      isSelected ? 'text-blue-900 font-medium' : 'text-gray-900'
                    }`}
                  >
                    {color.label}
                  </span>
                </div>
                <span
                  className={`text-xs px-2 py-0.5 rounded-full ${
                    isSelected
                      ? 'text-blue-700 bg-blue-100'
                      : 'text-gray-500 bg-gray-100'
                  }`}
                >
                  {color.count}
                </span>
              </button>
            );
          })}
        </div>
      )}
    </Card>
  );
}

'use client';

import { useState, useRef } from 'react';
import { useTranslation } from '../lib/i18n-client';

interface ColorPaletteSelectorProps {
  colors: string[];
  onColorsChange: (colors: string[]) => void;
}

/**
 * Color Palette Selector Component
 * Allows selecting colors via custom color picker
 */
export function ColorPaletteSelector({ colors, onColorsChange }: ColorPaletteSelectorProps) {
  const { t } = useTranslation();
  const [customColor, setCustomColor] = useState('#000000');
  const colorInputRef = useRef<HTMLInputElement>(null);

  const handleColorPickerChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Only update the swatch color preview, don't add to list yet
    const newColor = e.target.value;
    setCustomColor(newColor);
  };

  const handleAddColor = () => {
    // Add color when user clicks the add button
    if (customColor && customColor !== '#000000' && !colors.includes(customColor)) {
      onColorsChange([...colors, customColor]);
      setCustomColor('#000000');
    }
  };

  const handleRemoveColor = (index: number) => {
    onColorsChange(colors.filter((_, i) => i !== index));
  };

  const handleColorChange = (index: number, newColor: string) => {
    const newColors = [...colors];
    newColors[index] = newColor;
    onColorsChange(newColors);
  };

  return (
    <div className="space-y-4">
      {/* Selected Colors */}
      {colors.length > 0 && (
        <div className="space-y-2">
          <label className="block text-sm font-medium text-gray-700">
            {t('admin.attributes.valueModal.selectedColors')} ({colors.length})
          </label>
          <div className="flex flex-wrap gap-2">
            {colors.map((color, index) => (
              <div key={index} className="flex items-center gap-2 bg-gray-50 rounded-lg p-2 border border-gray-200">
                <div className="relative">
                  <div
                    className="w-10 h-10 rounded-lg border-2 border-gray-300 shadow-sm cursor-pointer"
                    style={{ backgroundColor: color }}
                    title={color}
                  />
                  <input
                    type="color"
                    value={color}
                    onChange={(e) => handleColorChange(index, e.target.value)}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
                <input
                  type="text"
                  value={color}
                  onChange={(e) => handleColorChange(index, e.target.value)}
                  className="w-24 px-2 py-1 text-xs border border-gray-300 rounded focus:ring-2 focus:ring-gray-900 focus:border-transparent"
                  placeholder="#000000"
                />
                <button
                  type="button"
                  onClick={() => handleRemoveColor(index)}
                  className="text-red-600 hover:text-red-800 transition-colors"
                  title={t('admin.attributes.valueModal.removeColor')}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Add Color Swatch */}
      <div>
        <label className="block text-sm font-medium text-gray-700 mb-2">
          {t('admin.attributes.valueModal.addColor')}
        </label>
        <div className="flex items-center gap-3">
          <div className="relative inline-block">
            <div
              className="w-12 h-12 rounded-lg border-2 border-gray-300 shadow-sm cursor-pointer hover:border-gray-500 transition-colors"
              style={{ backgroundColor: customColor }}
              onClick={() => colorInputRef.current?.click()}
              title={t('admin.attributes.valueModal.addColor')}
            />
            <input
              ref={colorInputRef}
              type="color"
              value={customColor}
              onChange={handleColorPickerChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
          </div>
          <button
            type="button"
            onClick={handleAddColor}
            disabled={!customColor || customColor === '#000000' || colors.includes(customColor)}
            className="px-4 py-2 bg-gray-900 text-white rounded-lg hover:bg-gray-800 transition-colors disabled:opacity-50 disabled:cursor-not-allowed text-sm"
          >
            {t('admin.attributes.valueModal.add')}
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { apiClient } from '../lib/api-client';
import { getStoredLanguage, type LanguageCode } from '../lib/language';
import { ProductCard } from './ProductCard';
import { t } from '../lib/i18n';
import type { ProductLabel } from './ProductLabels';
import { logger } from '../lib/utils/logger';

interface Product {
  id: string;
  slug: string;
  title: string;
  price: number;
  compareAtPrice?: number | null;
  image: string | null;
  inStock: boolean;
  brand: {
    id: string;
    name: string;
  } | null;
  colors?: Array<{ value: string; imageUrl?: string | null; colors?: string[] | null }>;
  sizes?: Array<{ value: string; imageUrl?: string | null }>;
  attributes?: Record<
    string,
    Array<{ valueId?: string; value: string; label: string; imageUrl?: string | null; colors?: string[] | null }>
  >;
  originalPrice?: number | null;
  discountPercent?: number | null;
  labels?: ProductLabel[];
}

interface ProductsResponse {
  data: Product[];
  meta: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  };
}

type FilterType = 'new' | 'featured' | 'bestseller';

interface Tab {
  id: FilterType;
  label: string;
  filter: string | null;
}

const PRODUCTS_PER_PAGE = 10;
const MOBILE_GRID_LAYOUT =
  'grid grid-cols-2 gap-4 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5';

/**
 * FeaturedProductsTabs Component
 * Displays products with tabs for filtering (NEW OFFERS, NEW, FEATURED, TOP SELLERS)
 * Similar to the reference design with underlined active tab
 */
export function FeaturedProductsTabs() {
  const [language, setLanguage] = useState<LanguageCode>('en');
  const [activeTab, setActiveTab] = useState<FilterType>('new');
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const updateLanguage = () => {
      const storedLang = getStoredLanguage();
      setLanguage(storedLang);
    };

    updateLanguage();

    const handleLanguageUpdate = () => {
      updateLanguage();
    };

    window.addEventListener('language-updated', handleLanguageUpdate);
    return () => {
      window.removeEventListener('language-updated', handleLanguageUpdate);
    };
  }, []);

  const tabs: Tab[] = [
    { id: 'new', label: t(language, 'home.featured_products.tab_new'), filter: 'new' },
    {
      id: 'bestseller',
      label: t(language, 'home.featured_products.tab_bestseller'),
      filter: 'bestseller',
    },
    {
      id: 'featured',
      label: t(language, 'home.featured_products.tab_featured'),
      filter: 'featured',
    },
  ];

  const fetchProducts = useCallback(
    async (filter: string | null) => {
      try {
        setLoading(true);
        setError(null);

        const currentLang = language;
        const params: Record<string, string> = {
          page: '1',
          limit: PRODUCTS_PER_PAGE.toString(),
          lang: currentLang,
        };

        if (filter) {
          params.filter = filter;
        }

        const response = await apiClient.get<ProductsResponse>('/api/v1/products', {
          params,
        });

        setProducts((response.data || []).slice(0, PRODUCTS_PER_PAGE));
      } catch (err) {
        logger.error('[FeaturedProductsTabs] Error', { err });
        setError(t(language, 'home.featured_products.errorLoading'));
        setProducts([]);
      } finally {
        setLoading(false);
      }
    },
    [language],
  );

  const handleTabChange = (tabId: FilterType) => {
    setActiveTab(tabId);
    const tab = tabs.find((t) => t.id === tabId);
    fetchProducts(tab?.filter || null);
  };

  useEffect(() => {
    fetchProducts('new');
  }, [fetchProducts]);

  return (
    <section className="py-16 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h2 className="text-3xl font-bold text-gray-900 text-center">
          {t(language, 'home.featured_products.title')}
        </h2>
        <p className="mt-3 mb-8 text-base text-gray-600 text-center">
          {t(language, 'home.featured_products.subtitle')}
        </p>

        <div className="flex justify-center items-center gap-6 md:gap-8 mb-8 flex-wrap">
          {tabs.map((tab) => {
            const isActive = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                type="button"
                onClick={() => handleTabChange(tab.id)}
                className={`
                  relative px-4 py-2 text-sm font-medium transition-colors duration-200
                  ${
                    isActive
                      ? 'text-blue-600'
                      : 'text-gray-600 hover:text-gray-900'
                  }
                `}
                aria-label={t(language, 'home.featured_products.ariaShowProducts').replace(
                  '{label}',
                  tab.label,
                )}
                aria-pressed={isActive}
              >
                {tab.label}
                {isActive && (
                  <span
                    className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600"
                    aria-hidden="true"
                  />
                )}
              </button>
            );
          })}
        </div>

        {loading ? (
          <div className={MOBILE_GRID_LAYOUT}>
            {[...Array(PRODUCTS_PER_PAGE)].map((_, i) => (
              <div key={i} className="bg-white rounded-lg overflow-hidden animate-pulse">
                <div className="aspect-square bg-gray-200"></div>
                <div className="p-4 space-y-2">
                  <div className="h-4 bg-gray-200 rounded w-3/4"></div>
                  <div className="h-3 bg-gray-200 rounded w-1/2"></div>
                  <div className="h-5 bg-gray-200 rounded w-1/3"></div>
                </div>
              </div>
            ))}
          </div>
        ) : error ? (
          <div className="text-center py-12">
            <p className="text-red-600 mb-4">{error}</p>
            <button
              type="button"
              onClick={() => {
                const tab = tabs.find((t) => t.id === activeTab);
                fetchProducts(tab?.filter || null);
              }}
              className="px-4 py-2 bg-gray-900 text-white rounded hover:bg-gray-800 transition-colors"
            >
              {t(language, 'home.featured_products.tryAgain')}
            </button>
          </div>
        ) : products.length > 0 ? (
          <div className={MOBILE_GRID_LAYOUT}>
            {products.slice(0, PRODUCTS_PER_PAGE).map((product) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        ) : (
          <div className="text-center py-12">
            <p className="text-gray-500">{t(language, 'home.featured_products.noProducts')}</p>
          </div>
        )}
      </div>
    </section>
  );
}

