'use client';

import { useState, useEffect, useRef } from 'react';
import { Globe, Banknote } from 'lucide-react';
import {
  LANGUAGES,
  type LanguageCode,
  getStoredLanguage,
  setStoredLanguage,
} from '../lib/language';
import type { CurrencyCode } from '../lib/currency';
import { CURRENCIES } from '../lib/currency';
import { getLanguageColor } from './LanguageSwitcherHeader';

/** Uppercase labels on the pill trigger (matches Figma-style locale display). */
const LANGUAGE_PILL_LABEL: Record<Exclude<LanguageCode, 'ka'>, string> = {
  en: 'ENG',
  hy: 'HY',
  ru: 'RU',
};

const ChevronDownIcon = () => (
  <svg width="10" height="10" viewBox="0 0 12 12" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden>
    <path d="M3 4.5L6 7.5L9 4.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
  </svg>
);

function toHeaderLanguage(stored: LanguageCode): Exclude<LanguageCode, 'ka'> {
  return stored === 'ka' ? 'en' : stored;
}

function pillLabelForLang(stored: LanguageCode): string {
  return LANGUAGE_PILL_LABEL[toHeaderLanguage(stored)];
}

export interface LocaleCurrencyPillProps {
  selectedCurrency: CurrencyCode;
  onCurrencyChange: (currency: CurrencyCode) => void;
  /** When true, closes the dropdown (e.g. search modal or mobile drawer open). */
  menuSuppressed?: boolean;
  variant?: 'desktop' | 'mobile';
}

/**
 * Single pill: globe + language code + "/" + banknote + currency + chevron; one menu for language and currency.
 */
export function LocaleCurrencyPill({
  selectedCurrency,
  onCurrencyChange,
  menuSuppressed = false,
  variant = 'desktop',
}: LocaleCurrencyPillProps) {
  const [showMenu, setShowMenu] = useState(false);
  const [currentLang, setCurrentLang] = useState<Exclude<LanguageCode, 'ka'>>(() =>
    toHeaderLanguage(getStoredLanguage()),
  );
  const menuRef = useRef<HTMLDivElement>(null);

  const isMobile = variant === 'mobile';

  useEffect(() => {
    const handleLanguageUpdate = () => {
      setCurrentLang(toHeaderLanguage(getStoredLanguage()));
    };

    window.addEventListener('language-updated', handleLanguageUpdate);
    return () => {
      window.removeEventListener('language-updated', handleLanguageUpdate);
    };
  }, []);

  useEffect(() => {
    if (menuSuppressed) {
      setShowMenu(false);
    }
  }, [menuSuppressed]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const changeLanguage = (langCode: LanguageCode) => {
    if (currentLang === langCode) {
      setShowMenu(false);
      return;
    }
    setCurrentLang(toHeaderLanguage(langCode));
    setShowMenu(false);
    setStoredLanguage(langCode);
  };

  const handleCurrencySelect = (code: CurrencyCode) => {
    onCurrencyChange(code);
    setShowMenu(false);
  };

  const triggerClass = isMobile
    ? 'flex h-9 sm:h-10 min-h-9 sm:min-h-10 items-center gap-1.5 sm:gap-2 rounded-full bg-[#f4f4f4] px-2.5 sm:px-3 text-[#333]'
    : 'flex h-12 min-h-12 items-center gap-2 rounded-full bg-[#f4f4f4] px-4 text-[#333]';

  const iconClass = isMobile ? 'h-3.5 w-3.5 sm:h-4 sm:w-4 shrink-0' : 'h-[18px] w-[18px] shrink-0';
  const textClass = isMobile
    ? 'text-xs sm:text-sm font-bold leading-none'
    : 'text-[16px] font-bold leading-none';

  return (
    <div className="relative" ref={menuRef}>
      <button
        type="button"
        onClick={() => setShowMenu(!showMenu)}
        aria-expanded={showMenu}
        aria-haspopup="true"
        className={triggerClass}
      >
        <Globe className={iconClass} strokeWidth={2} aria-hidden />
        <span className={textClass}>{pillLabelForLang(currentLang)}</span>
        <span className={`font-bold text-[#333] ${isMobile ? 'text-xs sm:text-sm' : 'text-[16px]'}`} aria-hidden>
          /
        </span>
        <Banknote className={iconClass} strokeWidth={2} aria-hidden />
        <span className={textClass}>{selectedCurrency}</span>
        <ChevronDownIcon />
      </button>

      {showMenu && (
        <div className="absolute right-0 top-full z-50 mt-2 max-h-[min(70vh,420px)] w-56 overflow-y-auto rounded-xl border border-gray-200/80 bg-white shadow-2xl animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="py-1">
            {Object.values(LANGUAGES)
              .filter((lang) => lang.code !== 'ka')
              .map((lang) => {
                const isActive = toHeaderLanguage(currentLang) === lang.code;
                const colorClass = getLanguageColor(lang.code, isActive);
                return (
                  <button
                    key={lang.code}
                    type="button"
                    onClick={() => changeLanguage(lang.code)}
                    disabled={isActive}
                    className={`w-full border-l-4 px-3 py-2.5 text-left text-sm transition-all duration-150 ${
                      isActive
                        ? `${colorClass} cursor-default font-semibold text-gray-900`
                        : 'border-transparent text-gray-700 hover:border-gray-200 hover:bg-gray-50'
                    }`}
                  >
                    <div className="flex min-w-0 items-center justify-between gap-2">
                      <span className={isActive ? 'font-semibold' : 'font-medium'}>{lang.nativeName}</span>
                      <span
                        className={`shrink-0 text-xs ${isActive ? 'font-semibold text-gray-700' : 'text-gray-500'}`}
                      >
                        {LANGUAGE_PILL_LABEL[lang.code as Exclude<LanguageCode, 'ka'>]}
                      </span>
                    </div>
                  </button>
                );
              })}
          </div>
          <div className="border-t border-gray-100" role="separator" />
          <div className="py-1">
            {Object.values(CURRENCIES).map((currency) => (
              <button
                key={currency.code}
                type="button"
                onClick={() => handleCurrencySelect(currency.code)}
                className={`flex w-full items-center justify-between px-4 py-2.5 text-left text-sm transition-all duration-150 ${
                  selectedCurrency === currency.code
                    ? 'bg-gradient-to-r from-gray-100 to-gray-50 font-semibold text-gray-900'
                    : 'text-gray-700 hover:bg-gray-50'
                }`}
              >
                <span>{currency.code}</span>
                <span className="text-gray-500">{currency.symbol}</span>
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useEffect, useMemo, useState } from 'react';
import { usePathname } from 'next/navigation';
import { Home, UserRound, Store } from 'lucide-react';
import { getCompareCount, getWishlistCount } from '../lib/storageCounts';
import { CartIcon } from './icons/CartIcon';

interface MobileNavItem {
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  href?: string;
  action?: () => void;
  onClick?: () => void;
  badge?: 'wishlist' | 'compare';
  visible?: boolean;
}

/**
 * Ստեղծում է հաստատուն mobile նավիգացիոն վահանակ՝ էջի ներքևում,
 * որպեսզի հիմնական գործողությունները միշտ լինեն ձեռքի տակ փոքր էկրաններում։
 */
export function MobileBottomNav() {
  const pathname = usePathname();
  const isProductsPage = pathname?.startsWith('/products');
  const [wishlistCount, setWishlistCount] = useState(0);
  const [compareCount, setCompareCount] = useState(0);

  useEffect(() => {
    const updateCounts = () => {
      const wishlist = getWishlistCount();
      const compare = getCompareCount();
      console.debug('[MobileBottomNav] wishlist/compare counts refreshed', { wishlist, compare });
      setWishlistCount(wishlist);
      setCompareCount(compare);
    };

    updateCounts();
    window.addEventListener('wishlist-updated', updateCounts);
    window.addEventListener('compare-updated', updateCounts);

    return () => {
      window.removeEventListener('wishlist-updated', updateCounts);
      window.removeEventListener('compare-updated', updateCounts);
    };
  }, []);

  const navItems: MobileNavItem[] = useMemo(
    () => [
      { 
        label: 'Home', 
        href: '/', 
        icon: Home, 
        visible: true,
      },
      // Shop with Store icon
      { 
        label: 'Shop', 
        href: '/products', 
        icon: Store, 
        visible: true,
        onClick: () => console.info('🛒 [MobileBottomNav] Shop tapped, navigating to /products'),
      },
      // On mobile we show Cart instead of Wishlist
      { 
        label: 'Cart', 
        href: '/cart', 
        icon: CartIcon, 
        visible: true,
      },
      { label: 'My account', href: '/profile', icon: UserRound, visible: true },
    ],
    [isProductsPage]
  );

  const resolveBadgeValue = (badge?: MobileNavItem['badge']) => {
    if (badge === 'wishlist') return wishlistCount;
    if (badge === 'compare') return compareCount;
    return 0;
  };

  return (
    <nav className="lg:hidden fixed bottom-0 inset-x-0 z-40 bg-white border-t border-gray-200 shadow-[0_-4px_20px_rgba(15,23,42,0.08)]">
      <div className="mx-auto flex max-w-md items-stretch justify-between px-2 py-2">
        {navItems.filter(item => item.visible).map(({ label, href, icon: Icon, badge, action, onClick }) => {
          const isActive = href ? pathname === href : false;
          const badgeValue = resolveBadgeValue(badge);

          const content = (
            <>
              <div className="relative">
                <Icon className={`h-5 w-5 ${isActive ? 'text-gray-900' : 'text-gray-500'}`} />
                {badgeValue > 0 && (
                  <span className="absolute -top-2 -right-2 rounded-full bg-red-500 px-1.5 text-[10px] font-semibold text-white">
                    {badgeValue > 99 ? '99+' : badgeValue}
                  </span>
                )}
              </div>
              <span className="mt-1 text-[11px]">{label}</span>
            </>
          );

          if (action) {
            return (
              <button
                key={label}
                type="button"
                onClick={action}
                className="flex flex-1 flex-col items-center rounded-xl px-2 py-1 text-xs font-medium text-gray-500 transition"
              >
                {content}
              </button>
            );
          }

          return (
            <Link
              key={label}
              href={href || '#'}
              onClick={onClick}
              className={`flex flex-1 flex-col items-center rounded-xl px-2 py-1 text-xs font-medium transition ${
                isActive ? 'text-gray-900' : 'text-gray-500'
              }`}
            >
              {content}
            </Link>
          );
        })}
      </div>
    </nav>
  );
}

'use client';

import { useState, useEffect } from 'react';
import type { ReactNode } from 'react';
import { useTranslation } from '../lib/i18n-client';

interface MobileFiltersDrawerProps {
  title?: string;
  triggerLabel?: string;
  children: ReactNode;
  openEventName?: string;
}

/**
 * Mobile filters drawer that կարող է բացվել թե՛ կոճակից, թե՛ արտաքին իրադարձությունից։
 */
export function MobileFiltersDrawer({
  title,
  triggerLabel,
  children,
  openEventName,
}: MobileFiltersDrawerProps) {
  const { t } = useTranslation();
  const defaultTitle = title || t('products.mobileFilters.title');
  const defaultTriggerLabel = triggerLabel || t('products.mobileFilters.title');
  const [open, setOpen] = useState(false);

  useEffect(() => {
    if (open) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [open]);

  useEffect(() => {
    if (!openEventName) return;

    const handleExternalToggle = () => {
      console.debug('[MobileFiltersDrawer] external toggle received');
      setOpen((prev) => !prev);
    };

    window.addEventListener(openEventName, handleExternalToggle);
    return () => {
      window.removeEventListener(openEventName, handleExternalToggle);
    };
  }, [openEventName]);

  return (
    <div className="lg:hidden">
      {open && (
        <div
          className="fixed inset-0 z-50 flex bg-black/40 backdrop-blur-sm"
          onClick={() => setOpen(false)}
        >
          <div
            className="h-full min-h-screen w-1/2 min-w-[16rem] max-w-full bg-white flex flex-col shadow-2xl"
            role="dialog"
            aria-modal="true"
            onClick={(event) => event.stopPropagation()}
          >
            <div className="flex items-center justify-between border-b border-gray-200 px-5 py-4">
              <p className="text-lg font-semibold text-gray-900">{defaultTitle}</p>
              <button
                type="button"
                onClick={() => setOpen(false)}
                className="h-10 w-10 rounded-full border border-gray-200 text-gray-600 hover:border-gray-300 hover:text-gray-900"
                aria-label={t('products.mobileFilters.close')}
              >
                <svg className="mx-auto h-5 w-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto px-5 py-6 space-y-6">{children}</div>
          </div>
        </div>
      )}
    </div>
  );
}

