'use client';

import { getColorHex } from '../../lib/colorMap';

interface ColorData {
  value: string;
  imageUrl?: string | null;
  colors?: string[] | null;
}

interface ProductColorsProps {
  colors: Array<string | ColorData>;
  isCompact?: boolean;
  maxVisible?: number;
}

/**
 * Component for displaying product color options
 */
export function ProductColors({ colors, isCompact = false, maxVisible = 6 }: ProductColorsProps) {
  if (!colors || colors.length === 0) {
    return null;
  }

  return (
    <div className={`flex items-center gap-1.5 ${isCompact ? 'mb-1' : 'mb-2'} flex-wrap`}>
      {colors.slice(0, maxVisible).map((colorData, index) => {
        const colorValue = typeof colorData === 'string' ? colorData : colorData.value;
        const imageUrl = typeof colorData === 'object' ? colorData.imageUrl : null;
        const colorsHex = typeof colorData === 'object' ? colorData.colors : null;
        
        // Determine color hex: use colorsHex[0] if available, otherwise use getColorHex
        const colorHex = colorsHex && Array.isArray(colorsHex) && colorsHex.length > 0 
          ? colorsHex[0] 
          : getColorHex(colorValue);
        
        return (
          <div
            key={index}
            className={`${isCompact ? 'w-4 h-4' : 'w-5 h-5'} rounded-full border border-gray-300 flex-shrink-0 overflow-hidden`}
            style={imageUrl ? {} : { backgroundColor: colorHex }}
            title={colorValue}
            aria-label={`Color: ${colorValue}`}
          >
            {imageUrl ? (
              <img 
                src={imageUrl} 
                alt={colorValue}
                className="w-full h-full object-cover"
                onError={(e) => {
                  // Fallback to color hex if image fails to load
                  const fallbackColor = colorHex || '#CCCCCC';
                  (e.target as HTMLImageElement).style.backgroundColor = fallbackColor;
                  (e.target as HTMLImageElement).style.display = 'none';
                }}
              />
            ) : null}
          </div>
        );
      })}
      {colors.length > maxVisible && (
        <span className={`${isCompact ? 'text-xs' : 'text-sm'} text-gray-500`}>
          +{colors.length - maxVisible}
        </span>
      )}
    </div>
  );
}

import React from 'react';

export type ProductLabelPosition = 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';

export interface ProductLabel {
  id: string;
  type: 'text' | 'percentage';
  value: string;
  position: ProductLabelPosition;
  color: string | null;
}

interface ProductLabelsProps {
  labels: ProductLabel[];
}

/**
 * ProductLabels
 *
 * UI-комպոնենտ, որը corner-երով խմբավորում է product-ի labels-ը
 * և նույն position ունեցող labels-ը ցուցադրում է vertical stack-ով։
 * Սա ապահովում է, որ միաժամանակ մի քանի label ունենալու դեպքում
 * դրանք իրար վրա չեն նստում, այլ ունեն հստակ вертикալ հեռավորություն։
 */
export const ProductLabels: React.FC<ProductLabelsProps> = ({ labels }) => {
  if (!labels || labels.length === 0) return null;

  // Փոքր logging, որ հեշտ լինի debug անել label-ների խնդիրները
  console.info('[UI][ProductLabels] Rendering labels', {
    total: labels.length,
    positions: labels.map((l) => l.position),
  });

  const positions: ProductLabelPosition[] = ['top-left', 'top-right', 'bottom-left', 'bottom-right'];

  const getColorClasses = (label: ProductLabel) => {
    if (label.color) {
      return '';
    }

    if (label.type === 'percentage') {
      return 'bg-red-600 text-white';
    }

    const value = label.value.toLowerCase();
    if (value.includes('new') || value.includes('նոր')) {
      return 'bg-green-600 text-white';
    }
    if (value.includes('hot') || value.includes('տաք')) {
      return 'bg-orange-600 text-white';
    }
    if (value.includes('sale') || value.includes('զեղչ')) {
      return 'bg-red-600 text-white';
    }

    return 'bg-blue-600 text-white';
  };

  const getCornerPositionClasses = (position: ProductLabelPosition) => {
    switch (position) {
      case 'top-left':
        return 'top-2 left-2 items-start';
      case 'top-right':
        return 'top-2 right-2 items-end';
      case 'bottom-left':
        return 'bottom-2 left-2 items-start';
      case 'bottom-right':
        return 'bottom-2 right-2 items-end';
      default:
        return '';
    }
  };

  return (
    <div className="absolute inset-0 pointer-events-none z-20">
      {positions.map((position) => {
        const labelsForPosition = labels.filter((label) => label.position === position);
        if (labelsForPosition.length === 0) return null;

        return (
          <div
            key={position}
            className={`absolute flex flex-col gap-1 ${getCornerPositionClasses(position)}`}
          >
            {labelsForPosition.map((label) => (
              <div
                key={label.id}
                className={`px-2 py-0.5 text-[10px] font-semibold rounded-md shadow-sm pointer-events-auto ${getColorClasses(
                  label,
                )}`}
                style={label.color ? { backgroundColor: label.color, color: 'white' } : undefined}
              >
                {label.type === 'percentage' ? `${label.value}%` : label.value}
              </div>
            ))}
          </div>
        );
      })}
    </div>
  );
};

'use client';

import { Button } from '@shop/ui';
import { useAuth } from '../lib/auth/AuthContext';
import { useTranslation } from '../lib/i18n-client';
import { useReviews } from './ProductReviews/hooks/useReviews';
import { useReviewForm } from './ProductReviews/hooks/useReviewForm';
import { ReviewSummary } from './ProductReviews/ReviewSummary';
import { ReviewForm } from './ProductReviews/ReviewForm';
import { ReviewList } from './ProductReviews/ReviewList';
import { ProductReviewsLoading } from './ProductReviews/ProductReviewsLoading';

interface ProductReviewsProps {
  productId?: string; // For backward compatibility
  productSlug?: string; // Preferred: use slug for API calls
}

export function ProductReviews({ productId, productSlug }: ProductReviewsProps) {
  const { isLoggedIn, user } = useAuth();
  const { t } = useTranslation();
  
  const { reviews, loading, setReviews } = useReviews(productId, productSlug);
  
  const {
    showForm,
    setShowForm,
    rating,
    setRating,
    hoveredRating,
    setHoveredRating,
    comment,
    setComment,
    submitting,
    editingReviewId,
    handleEditReview,
    handleCancelEdit,
    handleSubmit,
    handleUpdateReview,
  } = useReviewForm({
    productId,
    productSlug,
    reviews,
    setReviews,
  });

  // Get user's review if exists
  const userReview = user ? reviews.find(r => r.userId === user.id) : null;

  if (loading) {
    return <ProductReviewsLoading />;
  }

  const handleShowForm = () => {
    if (!isLoggedIn) {
      alert(t('common.reviews.loginRequired'));
      return;
    }
    setShowForm(true);
  };

  const handleLoginRequired = () => {
    alert(t('common.reviews.loginRequired'));
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 border-t border-gray-200">
      <div className="mb-8">
        <h2 className="text-3xl font-bold text-gray-900 mb-4">
          {t('common.reviews.title')}
        </h2>

        {/* Rating Summary */}
        <ReviewSummary reviews={reviews} />

        {/* Write Review Button */}
        {!showForm && (
          <Button
            variant="primary"
            onClick={handleShowForm}
            className="mb-8"
          >
            {t('common.reviews.writeReview')}
          </Button>
        )}

        {/* Review Form */}
        {showForm && (
          <ReviewForm
            rating={rating}
            hoveredRating={hoveredRating}
            comment={comment}
            submitting={submitting}
            editingReviewId={editingReviewId}
            onRatingChange={setRating}
            onHover={setHoveredRating}
            onCommentChange={setComment}
            onSubmit={editingReviewId ? handleUpdateReview : handleSubmit}
            onCancel={editingReviewId ? handleCancelEdit : () => {
              setShowForm(false);
              setRating(0);
              setComment('');
            }}
          />
        )}
      </div>

      {/* Reviews List */}
      <ReviewList
        reviews={reviews}
        currentUserId={user?.id}
        showForm={showForm}
        onEditReview={handleEditReview}
        onShowForm={handleShowForm}
        onLoginRequired={handleLoginRequired}
      />
    </div>
  );
}

