'use client';

import { useState, useEffect, useRef, type MouseEvent, type TouchEvent } from 'react';

interface UseCarouselProps {
  itemCount: number;
  visibleItems: number;
  autoRotateInterval?: number;
}

/**
 * Hook for managing carousel state and interactions
 */
export function useCarousel({ itemCount, visibleItems, autoRotateInterval = 5000 }: UseCarouselProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);
  const [hasMoved, setHasMoved] = useState(false);
  const carouselRef = useRef<HTMLDivElement>(null);

  const maxIndex = Math.max(0, itemCount - visibleItems);

  // Auto-rotate carousel
  useEffect(() => {
    if (itemCount <= visibleItems || isDragging) return;
    
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => {
        return prevIndex >= maxIndex ? 0 : prevIndex + 1;
      });
    }, autoRotateInterval);

    return () => clearInterval(interval);
  }, [itemCount, visibleItems, isDragging, maxIndex, autoRotateInterval]);

  // Adjust currentIndex when visibleItems changes
  useEffect(() => {
    if (currentIndex > maxIndex) {
      setCurrentIndex(maxIndex);
    }
  }, [visibleItems, itemCount, maxIndex, currentIndex]);

  const goToPrevious = () => {
    setCurrentIndex((prevIndex) => {
      return prevIndex === 0 ? maxIndex : prevIndex - 1;
    });
  };

  const goToNext = () => {
    setCurrentIndex((prevIndex) => {
      return prevIndex >= maxIndex ? 0 : prevIndex + 1;
    });
  };

  const goToIndex = (index: number) => {
    setCurrentIndex(Math.max(0, Math.min(maxIndex, index)));
  };

  const handleMouseDown = (e: MouseEvent<HTMLDivElement>) => {
    if (!carouselRef.current) return;
    setHasMoved(false);
    setIsDragging(true);
    setStartX(e.pageX - carouselRef.current.offsetLeft);
    setScrollLeft(currentIndex);
  };

  const handleMouseMove = (e: MouseEvent<HTMLDivElement>) => {
    if (!isDragging || !carouselRef.current) return;
    const x = e.pageX - carouselRef.current.offsetLeft;
    const deltaX = Math.abs(x - startX);
    
    // Only consider it dragging if mouse moved more than 5px
    if (deltaX > 5) {
      setHasMoved(true);
      e.preventDefault();
      const walk = (x - startX) * 2; // Scroll speed multiplier
      const cardWidth = 100 / visibleItems;
      const newIndex = Math.round((scrollLeft - walk / (carouselRef.current.offsetWidth / 100)) / cardWidth);
      const clampedIndex = Math.max(0, Math.min(maxIndex, newIndex));
      setCurrentIndex(clampedIndex);
    }
  };

  const handleMouseUp = () => {
    const wasDragging = isDragging;
    const didMove = hasMoved;
    setIsDragging(false);
    // Reset hasMoved after a short delay to allow click events to process
    if (wasDragging && didMove) {
      setTimeout(() => setHasMoved(false), 150);
    } else {
      setHasMoved(false);
    }
  };

  const handleTouchStart = (e: TouchEvent<HTMLDivElement>) => {
    if (!carouselRef.current) return;
    setHasMoved(false);
    setIsDragging(true);
    setStartX(e.touches[0].pageX - carouselRef.current.offsetLeft);
    setScrollLeft(currentIndex);
  };

  const handleTouchMove = (e: TouchEvent<HTMLDivElement>) => {
    if (!isDragging || !carouselRef.current) return;
    const x = e.touches[0].pageX - carouselRef.current.offsetLeft;
    const deltaX = Math.abs(x - startX);
    
    // Only consider it dragging if touch moved more than 5px
    if (deltaX > 5) {
      setHasMoved(true);
      const walk = (x - startX) * 2;
      const cardWidth = 100 / visibleItems;
      const newIndex = Math.round((scrollLeft - walk / (carouselRef.current.offsetWidth / 100)) / cardWidth);
      const clampedIndex = Math.max(0, Math.min(maxIndex, newIndex));
      setCurrentIndex(clampedIndex);
    }
  };

  const handleTouchEnd = () => {
    const wasDragging = isDragging;
    const didMove = hasMoved;
    setIsDragging(false);
    if (wasDragging && didMove) {
      setTimeout(() => setHasMoved(false), 150);
    } else {
      setHasMoved(false);
    }
  };

  const handleWheel = (e: React.WheelEvent<HTMLDivElement>) => {
    if (e.deltaY === 0) return;
    e.preventDefault();
    const delta = e.deltaY > 0 ? 1 : -1;
    setCurrentIndex((prevIndex) => {
      const newIndex = prevIndex + delta;
      return Math.max(0, Math.min(maxIndex, newIndex));
    });
  };

  return {
    currentIndex,
    isDragging,
    hasMoved,
    carouselRef,
    goToPrevious,
    goToNext,
    goToIndex,
    handleMouseDown,
    handleMouseMove,
    handleMouseUp,
    handleTouchStart,
    handleTouchMove,
    handleTouchEnd,
    handleWheel,
  };
}

'use client';

import { useState, useCallback, useRef, useEffect } from 'react';

export interface InstantSearchResultItem {
  id: string;
  slug: string;
  title: string;
  price: number;
  compareAtPrice: number | null;
  image: string | null;
  category: string | null;
}

export interface UseInstantSearchOptions {
  debounceMs?: number;
  minQueryLength?: number;
  maxResults?: number;
  lang?: string;
}

export function useInstantSearch(options: UseInstantSearchOptions = {}) {
  const {
    debounceMs = 200,
    minQueryLength = 1,
    maxResults = 8,
    lang = 'en',
  } = options;

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<InstantSearchResultItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isOpen, setIsOpen] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const abortControllerRef = useRef<AbortController | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const performSearch = useCallback(
    async (searchQuery: string) => {
      if (searchQuery.length < minQueryLength) {
        setResults([]);
        setError(null);
        return;
      }

      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
      abortControllerRef.current = new AbortController();
      const signal = abortControllerRef.current.signal;

      setLoading(true);
      setError(null);

      try {
        const params = new URLSearchParams({
          q: searchQuery,
          limit: String(maxResults),
          lang,
        });
        const res = await fetch(`/api/search/instant?${params.toString()}`, {
          signal,
          cache: 'no-store',
          headers: { 'Cache-Control': 'no-cache' },
        });

        if (!res.ok) {
          const data = await res.json().catch(() => ({}));
          throw new Error(data.error || data.details || `Search failed: ${res.status}`);
        }

        const data = await res.json();
        setResults(Array.isArray(data.results) ? data.results : []);
      } catch (err) {
        if (err instanceof Error && err.name === 'AbortError') {
          return;
        }
        setResults([]);
        setError(err instanceof Error ? err.message : 'Search failed');
      } finally {
        setLoading(false);
        abortControllerRef.current = null;
      }
    },
    [minQueryLength, maxResults, lang]
  );

  useEffect(() => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }

    if (query.trim().length < minQueryLength) {
      setResults([]);
      setError(null);
      setSelectedIndex(-1);
      return;
    }

    debounceRef.current = setTimeout(() => {
      debounceRef.current = null;
      performSearch(query.trim());
    }, debounceMs);

    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, [query, debounceMs, minQueryLength, performSearch]);

  useEffect(() => {
    setSelectedIndex(-1);
  }, [results]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (!isOpen || results.length === 0) {
        if (e.key === 'Escape') {
          setIsOpen(false);
        }
        return;
      }

      switch (e.key) {
        case 'ArrowDown':
          e.preventDefault();
          setSelectedIndex((prev) => (prev < results.length - 1 ? prev + 1 : 0));
          break;
        case 'ArrowUp':
          e.preventDefault();
          setSelectedIndex((prev) => (prev > 0 ? prev - 1 : results.length - 1));
          break;
        case 'Escape':
          e.preventDefault();
          setSelectedIndex(-1);
          setIsOpen(false);
          break;
        default:
          break;
      }
    },
    [isOpen, results.length]
  );

  const clearSearch = useCallback(() => {
    setQuery('');
    setResults([]);
    setError(null);
    setLoading(false);
    setIsOpen(false);
    setSelectedIndex(-1);
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
      debounceRef.current = null;
    }
  }, []);

  return {
    query,
    setQuery,
    results,
    loading,
    error,
    isOpen,
    setIsOpen,
    selectedIndex,
    setSelectedIndex,
    performSearch,
    handleKeyDown,
    clearSearch,
  };
}

'use client';

import { useState, useEffect } from 'react';
import { apiClient } from '../../lib/api-client';
import { getStoredLanguage, type LanguageCode } from '../../lib/language';

interface RelatedProduct {
  id: string;
  slug: string;
  title: string;
  price: number;
  originalPrice?: number | null;
  compareAtPrice: number | null;
  discountPercent?: number | null;
  image: string | null;
  inStock: boolean;
  brand?: {
    id: string;
    name: string;
  } | null;
  categories?: Array<{
    id: string;
    slug: string;
    title: string;
  }>;
  variants?: Array<{
    options?: Array<{
      key: string;
      value: string;
    }>;
  }>;
}

interface UseRelatedProductsProps {
  categorySlug?: string;
  currentProductId: string;
  language: LanguageCode;
}

/**
 * Hook for fetching related products
 */
export function useRelatedProducts({ categorySlug, currentProductId, language }: UseRelatedProductsProps) {
  const [products, setProducts] = useState<RelatedProduct[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchRelatedProducts = async () => {
      try {
        setLoading(true);
        
        // Build params - if no categorySlug, fetch all products
        const params: Record<string, string> = {
          limit: '30', // Fetch more to ensure we have 10 after filtering
          lang: language,
        };
        
        if (categorySlug) {
          params.category = categorySlug;
          console.log('[RelatedProducts] Fetching related products for category:', categorySlug);
        } else {
          console.log('[RelatedProducts] No categorySlug, fetching all products');
        }
        
        const response = await apiClient.get<{
          data: RelatedProduct[];
          meta: {
            total: number;
          };
        }>('/api/v1/products', {
          params,
        });

        console.log('[RelatedProducts] Received products:', response.data.length);
        // Filter out current product and take exactly 10
        const filtered = response.data.filter(p => p.id !== currentProductId);
        console.log('[RelatedProducts] After filtering current product:', filtered.length);
        const finalProducts = filtered.slice(0, 10);
        console.log('[RelatedProducts] Final products to display:', finalProducts.length);
        setProducts(finalProducts);
      } catch (error) {
        console.error('[RelatedProducts] Error fetching related products:', error);
        setProducts([]);
      } finally {
        setLoading(false);
      }
    };

    fetchRelatedProducts();
  }, [categorySlug, currentProductId, language]);

  return { products, loading };
}

import { ApiError } from "./types";
import type { RequestOptions } from "./types";
import { buildUrl } from "./url-builder";
import { getHeaders } from "./headers";
import { handleUnauthorized } from "./auth-utils";
import { shouldLogError, shouldLogWarning, parseErrorResponse, createApiError } from "./error-handler";

/**
 * Handle network errors
 */
function handleNetworkError(error: unknown, baseUrl: string, url: string): never {
  const networkError = error as { message?: string; name?: string };
  
  // Check if it's a timeout error
  if (networkError.message?.includes('timeout') || networkError.message?.includes('Request timeout')) {
    console.error('⏱️ [API CLIENT] Request timeout:', networkError.message);
    throw networkError;
  }
  
  console.error('❌ [API CLIENT] Network error during fetch:', networkError);
  
  // Check if it's a connection refused error
  const isConnectionRefused = 
    networkError.message?.includes('Failed to fetch') || 
    networkError.message?.includes('ERR_CONNECTION_REFUSED') ||
    networkError.message?.includes('NetworkError') ||
    networkError.message?.includes('Network request failed');
  
  if (isConnectionRefused) {
    const errorMessage = baseUrl 
      ? `⚠️ API սերվերը հասանելի չէ!\n\n` +
        `Չհաջողվեց միանալ ${baseUrl}\n\n` +
        `Լուծում:\n` +
        `1. Համոզվեք, որ API սերվերը գործարկված է\n` +
        `2. Ստուգեք, որ ${baseUrl.split(':').pop() || 'port'} պորտը զբաղված չէ այլ գործընթացով\n\n` +
        `Հարցման URL: ${url}`
      : `⚠️ API route-ը հասանելի չէ!\n\n` +
        `Չհաջողվեց միանալ Next.js API route-ին: ${url}\n\n` +
        `Լուծում:\n` +
        `1. Համոզվեք, որ Next.js dev server-ը գործարկված է (npm run dev)\n` +
        `2. Ստուգեք, որ API route-ը գոյություն ունի: ${url}\n\n`;
    
    console.error('❌ [API CLIENT]', errorMessage);
    throw new Error(errorMessage);
  }
  
  throw new Error(`Ցանցային սխալ: Չհաջողվեց միանալ API-ին ${url}. ${networkError.message || 'Խնդրում ենք ստուգել, արդյոք Next.js server-ը գործարկված է:'}`);
}

/**
 * Handle error response
 */
async function handleErrorResponse(
  response: Response,
  url: string,
  baseUrl: string
): Promise<never> {
  const isUnauthorized = response.status === 401;
  const isNotFound = response.status === 404;
  
  // Log 404 as warning (expected situation - resource doesn't exist)
  if (shouldLogWarning(response.status)) {
    console.warn(`⚠️ [API CLIENT] Not Found (404): ${url}`);
  }
  // Log other errors (except 401 which is expected)
  else if (shouldLogError(response.status)) {
    console.error(`❌ [API CLIENT] Error: ${response.status} ${response.statusText}`, {
      url,
      status: response.status,
      statusText: response.statusText,
      headers: Object.fromEntries(response.headers.entries()),
    });
  }
  
  // Handle 401 Unauthorized - clear token and redirect
  if (isUnauthorized) {
    handleUnauthorized();
  }
  
  const { errorText, errorData } = await parseErrorResponse(response);
  
  // Log error details
  if (isNotFound) {
    console.warn('⚠️ [API CLIENT] Not Found response:', errorData || errorText);
  } else if (!isUnauthorized && shouldLogError(response.status)) {
    console.error('❌ [API CLIENT] Error response:', errorData || errorText);
  }
  
  throw createApiError(response, errorText, errorData);
}

/**
 * GET request
 */
export async function getRequest<T>(
  baseUrl: string,
  endpoint: string,
  options?: RequestOptions,
  retryCount = 0
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  const maxRetries = 3;
  const retryDelay = 1000; // 1 second
  const timeout = 30000; // 30 seconds timeout
  
  console.log('🌐 [API CLIENT] GET request:', { url, endpoint, baseUrl });
  
  let response: Response;
  try {
    // Create timeout controller
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);
    
    try {
      response = await fetch(url, {
        method: 'GET',
        headers: getHeaders(options),
        cache: 'no-store', // Disable caching for server components
        signal: controller.signal,
        ...options,
      });
      clearTimeout(timeoutId);
    } catch (fetchError: unknown) {
      clearTimeout(timeoutId);
      const error = fetchError as { name?: string };
      if (error.name === 'AbortError') {
        throw new Error(`Request timeout: API server did not respond within ${timeout / 1000} seconds. URL: ${url}`);
      }
      throw fetchError;
    }
    
    // Log response status safely
    try {
      console.log('🌐 [API CLIENT] GET response status:', response.status, response.statusText || '');
    } catch {
      console.warn('⚠️ [API CLIENT] Failed to log response status');
    }
  } catch (networkError: unknown) {
    handleNetworkError(networkError, baseUrl, url);
  }

  if (!response.ok) {
    // Retry on 429 (Too Many Requests) errors
    if (response.status === 429 && retryCount < maxRetries) {
      const delay = retryDelay * (retryCount + 1); // Exponential backoff
      console.warn(`⚠️ [API CLIENT] Rate limited, retrying in ${delay}ms... (attempt ${retryCount + 1}/${maxRetries})`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return getRequest<T>(baseUrl, endpoint, options, retryCount + 1);
    }

    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    if (!response) {
      throw new Error('Response is undefined');
    }

    const contentType = response.headers?.get('content-type');
    console.log('🌐 [API CLIENT] Response content-type:', contentType);
    
    if (!contentType || !contentType.includes('application/json')) {
      const text = await response.text();
      console.error('❌ [API CLIENT] GET Non-JSON response:', {
        contentType,
        status: response.status,
        text: text?.substring(0, 200) || '', // First 200 chars
      });
      throw new Error(`Expected JSON response but got ${contentType}. Status: ${response.status}`);
    }
    
    const jsonData = await response.json();
    console.log('✅ [API CLIENT] GET Response parsed successfully');
    
    if (!jsonData) {
      console.warn('⚠️ [API CLIENT] Response data is null or undefined');
      return null as T;
    }
    
    return jsonData;
  } catch (parseError: unknown) {
    const error = parseError as { message?: string; stack?: string };
    console.error('❌ [API CLIENT] GET JSON parse error:', parseError);
    console.error('❌ [API CLIENT] Parse error stack:', error.stack);
    if (error.message && error.message.includes('Expected JSON')) {
      throw parseError;
    }
    throw new Error(`Failed to parse response as JSON: ${error.message || String(parseError)}`);
  }
}

/**
 * POST request
 */
export async function postRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  try {
    const url = buildUrl(baseUrl, endpoint, options?.params);
    
    console.log('📤 [API CLIENT] POST request:', { url, data: data ? 'provided' : 'none' });
    
    const response = await fetch(url, {
      method: 'POST',
      headers: getHeaders(options),
      body: data ? JSON.stringify(data) : undefined,
      ...options,
    });

    console.log('📥 [API CLIENT] Response status:', response.status, response.statusText);

    if (!response.ok) {
      const isUnauthorized = response.status === 401;
      
      // Handle 401 Unauthorized - clear token and redirect
      if (isUnauthorized) {
        handleUnauthorized();
      }
      
      await handleErrorResponse(response, url, baseUrl);
    }

    try {
      const jsonData = await response.json();
      console.log('✅ [API CLIENT] Response parsed successfully');
      return jsonData;
    } catch (parseError: unknown) {
      console.error('❌ [API CLIENT] JSON parse error:', parseError);
      throw new Error(`Failed to parse response: ${String(parseError)}`);
    }
  } catch (error: unknown) {
    // Handle network errors, URL construction errors, etc.
    if (error instanceof TypeError && error.message.includes('fetch')) {
      console.error('❌ [API CLIENT] Network error:', error);
      const errorMsg = baseUrl
        ? `Network error: Unable to connect to API. Please check if the API server is running at ${baseUrl}`
        : `Network error: Unable to connect to Next.js API routes. Please check if the Next.js server is running.`;
      throw new Error(errorMsg);
    }
    
    // Re-throw if it's already our custom ApiError
    if (error instanceof ApiError) {
      throw error;
    }
    
    // Re-throw if it's a parse error
    const errorObj = error as { message?: string };
    if (errorObj.message && errorObj.message.includes('Failed to parse')) {
      throw error;
    }
    
    // Otherwise wrap in a generic error
    console.error('❌ [API CLIENT] POST request failed:', error);
    throw new Error(`API request failed: ${errorObj.message || String(error)}`);
  }
}

/**
 * PUT request
 */
export async function putRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  console.log('📤 [API CLIENT] PUT request:', { url, endpoint, hasData: !!data });
  
  const response = await fetch(url, {
    method: 'PUT',
    headers: getHeaders(options),
    body: data ? JSON.stringify(data) : undefined,
    ...options,
  });

  console.log('📥 [API CLIENT] PUT response status:', response.status, response.statusText);

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    const jsonData = await response.json();
    console.log('✅ [API CLIENT] PUT Response parsed successfully');
    return jsonData;
  } catch (parseError: unknown) {
    console.error('❌ [API CLIENT] PUT JSON parse error:', {
      url,
      status: response.status,
      error: parseError,
    });
    throw new Error(`Failed to parse response: ${String(parseError)}`);
  }
}

/**
 * PATCH request
 */
export async function patchRequest<T>(
  baseUrl: string,
  endpoint: string,
  data?: unknown,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  const response = await fetch(url, {
    method: 'PATCH',
    headers: getHeaders(options),
    body: data ? JSON.stringify(data) : undefined,
    ...options,
  });

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  try {
    return await response.json();
  } catch (parseError: unknown) {
    console.error('❌ [API CLIENT] PATCH JSON parse error:', parseError);
    throw new Error(`Failed to parse response: ${String(parseError)}`);
  }
}

/**
 * DELETE request
 */
export async function deleteRequest<T>(
  baseUrl: string,
  endpoint: string,
  options?: RequestOptions
): Promise<T> {
  const url = buildUrl(baseUrl, endpoint, options?.params);
  
  const response = await fetch(url, {
    method: 'DELETE',
    headers: getHeaders(options),
    ...options,
  });

  if (!response.ok) {
    await handleErrorResponse(response, url, baseUrl);
  }

  // DELETE requests might not return a body
  try {
    const text = await response.text();
    if (text) {
      return JSON.parse(text);
    }
    return null as T;
  } catch {
    // If there's no body or parse fails, return null for DELETE
    return null as T;
  }
}

import type { RequestOptions } from "./types";

/**
 * Build URL from endpoint and params
 */
export function buildUrl(
  baseUrl: string,
  endpoint: string,
  params?: Record<string, string>
): string {
  // Ensure endpoint starts with /
  const normalizedEndpoint = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
  
  // If baseUrl is empty (relative paths for Next.js API routes)
  if (!baseUrl || baseUrl.trim() === '') {
    // Check if we're on the server (Node.js environment)
    const isServer = typeof window === 'undefined';
    
    // On server, we need an absolute URL
    if (isServer) {
      // Try to get the base URL from environment variable or construct it
      let serverUrl = process.env.NEXT_PUBLIC_APP_URL;
      if (!serverUrl) {
        if (process.env.VERCEL_URL) {
          serverUrl = `https://${process.env.VERCEL_URL}`;
        } else {
          serverUrl = 'http://localhost:3000';
        }
      }
      
      let url = `${serverUrl}${normalizedEndpoint}`;
      if (params && Object.keys(params).length > 0) {
        const searchParams = Object.entries(params)
          .filter(([_, value]) => value !== undefined && value !== null)
          .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
          .join('&');
        url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
      }
      return url;
    }
    
    // On client, use relative URL
    let url = normalizedEndpoint;
    if (params && Object.keys(params).length > 0) {
      const searchParams = Object.entries(params)
        .filter(([_, value]) => value !== undefined && value !== null)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
        .join('&');
      url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
    }
    return url;
  }
  
  // Build base URL for absolute URLs
  let normalizedBaseUrl = baseUrl;
  if (!normalizedBaseUrl.endsWith('/')) {
    normalizedBaseUrl = normalizedBaseUrl.replace(/\/+$/, '');
  }
  
  // Combine base URL and endpoint
  const fullUrl = `${normalizedBaseUrl}${normalizedEndpoint}`;
  
  // Use URL constructor for proper URL handling
  try {
    const url = new URL(fullUrl);
    
    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          url.searchParams.append(key, String(value));
        }
      });
    }
    
    return url.toString();
  } catch (error) {
    // Fallback: manual URL construction if URL constructor fails
    console.error('❌ [API CLIENT] URL construction error:', error, { baseUrl, endpoint, fullUrl });
    
    let url = fullUrl;
    if (params && Object.keys(params).length > 0) {
      const searchParams = Object.entries(params)
        .filter(([_, value]) => value !== undefined && value !== null)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
        .join('&');
      url = `${url}${url.includes('?') ? '&' : '?'}${searchParams}`;
    }
    
    return url;
  }
}

'use client';

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { useRouter } from 'next/navigation';
import { apiClient, ApiError } from '../api-client';
import { getApiLikeData, getErrorMessage, getThrownHttpStatus } from '../types/errors';

/**
 * User interface
 */
interface User {
  id: string;
  email?: string;
  phone?: string;
  firstName?: string;
  lastName?: string;
  roles?: string[];
}

/**
 * Auth Context interface
 */
interface AuthContextType {
  user: User | null;
  token: string | null;
  isLoggedIn: boolean;
  isLoading: boolean;
  isAdmin: boolean;
  roles: string[];
  login: (_emailOrPhone: string, _password: string) => Promise<void>;
  register: (_data: RegisterData) => Promise<void>;
  logout: () => void;
}

/**
 * Register data interface
 */
interface RegisterData {
  email?: string;
  phone?: string;
  password: string;
  firstName?: string;
  lastName?: string;
}

/**
 * Auth response from API
 */
interface AuthResponse {
  user: User;
  token: string;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const AUTH_TOKEN_KEY = 'auth_token';
const AUTH_USER_KEY = 'auth_user';

/**
 * Auth Provider component
 */
export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const router = useRouter();

  // Load auth state from localStorage on mount
  useEffect(() => {
    console.log('🔐 [AUTH] Loading auth state from localStorage...');
    
    const loadAuthState = async () => {
      try {
        const storedToken = localStorage.getItem(AUTH_TOKEN_KEY);
        const storedUser = localStorage.getItem(AUTH_USER_KEY);

        if (storedToken && storedUser) {
          console.log('✅ [AUTH] Found stored auth data');
          const parsedUser = JSON.parse(storedUser);
          
          // If user doesn't have roles, fetch from API
          if (!parsedUser.roles || !Array.isArray(parsedUser.roles)) {
            console.log('⚠️ [AUTH] User data missing roles, fetching from API...');
            try {
              const profileData = await apiClient.get<{ roles: string[] }>('/api/v1/users/profile');
              if (profileData.roles) {
                parsedUser.roles = profileData.roles;
                localStorage.setItem(AUTH_USER_KEY, JSON.stringify(parsedUser));
                console.log('✅ [AUTH] Roles updated from API:', profileData.roles);
              }
            } catch (fetchError) {
              console.error('❌ [AUTH] Failed to fetch user roles:', fetchError);
            }
          }
          
          setToken(storedToken);
          setUser(parsedUser);
        } else {
          console.log('ℹ️ [AUTH] No stored auth data found');
        }
      } catch (error) {
        console.error('❌ [AUTH] Error loading auth state:', error);
        // Clear corrupted data
        localStorage.removeItem(AUTH_TOKEN_KEY);
        localStorage.removeItem(AUTH_USER_KEY);
      } finally {
        setIsLoading(false);
      }
    };

    loadAuthState();
  }, []);

  /**
   * Login user
   */
  const login = async (emailOrPhone: string, password: string) => {
    console.log('🔐 [AUTH] Login attempt:', { emailOrPhone: emailOrPhone ? 'provided' : 'not provided', password: password ? 'provided' : 'not provided' });
    
    try {
      setIsLoading(true);

      // Determine if it's email or phone
      const isEmail = emailOrPhone.includes('@');
      const requestData = isEmail
        ? { email: emailOrPhone, password }
        : { phone: emailOrPhone, password };

      console.log('📤 [AUTH] Sending login request to API...');
      const response = await apiClient.post<AuthResponse>('/api/v1/auth/login', requestData, {
        skipAuth: true, // Don't send token for login
      });

      console.log('✅ [AUTH] Login successful:', { 
        userId: response.user.id,
        roles: response.user.roles,
        isAdmin: response.user.roles?.includes('admin')
      });

      // Store auth data
      localStorage.setItem(AUTH_TOKEN_KEY, response.token);
      localStorage.setItem(AUTH_USER_KEY, JSON.stringify(response.user));

      setToken(response.token);
      setUser(response.user);

      // Trigger auth update event
      window.dispatchEvent(new Event('auth-updated'));

      // Don't redirect here - let the login page handle redirect based on query params
    } catch (error: unknown) {
      console.error('❌ [AUTH] Login error:', error);
      
      // Extract error message from API response
      let errorMessage = 'Login failed. Please try again.';
      
      // Check if it's an ApiError
      if (error instanceof ApiError) {
        if (error.status === 401) {
          errorMessage = error.message || 'Invalid email/phone or password';
        } else if (error.status === 403) {
          errorMessage = error.message || 'Your account has been blocked';
        } else if (error.status === 400) {
          errorMessage = error.message || 'Please provide email/phone and password';
        } else {
          errorMessage = error.message || errorMessage;
        }
      } else {
        const status = getThrownHttpStatus(error);
        const msg = getErrorMessage(error);
        if (status === 401) {
          errorMessage = msg || 'Invalid email/phone or password';
        } else if (status === 403) {
          errorMessage = msg || 'Your account has been blocked';
        } else if (status === 400) {
          errorMessage = msg || 'Please provide email/phone and password';
        } else if (msg) {
          errorMessage = msg;
        }
      }

      throw new Error(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * Register new user
   */
  const register = async (data: RegisterData) => {
    console.log('🔐 [AUTH] Registration attempt:', { 
      email: data.email || 'not provided',
      phone: data.phone || 'not provided',
      hasFirstName: !!data.firstName,
      hasLastName: !!data.lastName
    });

    try {
      setIsLoading(true);

      console.log('📤 [AUTH] Sending registration request to API...', { data });
      const response = await apiClient.post<AuthResponse>('/api/v1/auth/register', data, {
        skipAuth: true, // Don't send token for registration
      });

      console.log('✅ [AUTH] Registration response received:', response);

      if (!response || !response.user || !response.token) {
        console.error('❌ [AUTH] Invalid response structure:', response);
        throw new Error('Invalid response from server');
      }

      console.log('✅ [AUTH] Registration successful:', { userId: response.user.id });

      // Store auth data
      try {
        localStorage.setItem(AUTH_TOKEN_KEY, response.token);
        localStorage.setItem(AUTH_USER_KEY, JSON.stringify(response.user));
        console.log('💾 [AUTH] Auth data stored in localStorage');
      } catch (storageError) {
        console.error('❌ [AUTH] Failed to store auth data:', storageError);
        throw new Error('Failed to save authentication data');
      }

      setToken(response.token);
      setUser(response.user);

      // Trigger auth update event
      window.dispatchEvent(new Event('auth-updated'));

      console.log('🔄 [AUTH] Redirecting to home page...');
      // Redirect to home page
      router.push('/');
    } catch (error: unknown) {
      console.error('❌ [AUTH] Registration error:', error);
      console.error('❌ [AUTH] Error details:', {
        message: getErrorMessage(error),
        stack: error instanceof Error ? error.stack : undefined,
        name: error instanceof Error ? error.name : undefined,
      });
      
      // Extract error message from API response
      let errorMessage = 'Registration failed. Please try again.';
      
      const apiData = getApiLikeData(error);
      const flatMessage = getErrorMessage(error);
      if (flatMessage || apiData.data) {
        // Check if error has structured data
        if (apiData.data?.detail) {
          errorMessage = apiData.data.detail;
        } else if (apiData.data?.message) {
          errorMessage = apiData.data.message;
        } else {
          // Fallback to parsing error message
          const errorText = flatMessage;
          if (errorText.includes('409') || errorText.includes('already exists') || errorText.includes('User already exists')) {
            errorMessage = 'User with this email or phone already exists';
          } else if (errorText.includes('400') || errorText.includes('Validation failed')) {
            if (errorText.includes('password') || errorText.includes('Password')) {
              errorMessage = 'Password must be at least 6 characters';
            } else if (errorText.includes('email') || errorText.includes('phone')) {
              errorMessage = 'Please provide email or phone and password';
            } else {
              errorMessage = 'Invalid registration data. Please check your input.';
            }
          } else if (errorText.includes('500') || errorText.includes('Internal Server Error')) {
            errorMessage = 'Server error. Please try again later.';
          } else if (errorText.includes('Failed to parse')) {
            errorMessage = 'Invalid response from server. Please try again.';
          } else {
            // Try to extract meaningful message
            const match = errorText.match(/detail[:\s]+([^,\n]+)/i);
            if (match) {
              errorMessage = match[1].trim();
            }
          }
        }
      }

      console.error('❌ [AUTH] Final error message:', errorMessage);
      throw new Error(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  /**
   * Logout user
   */
  const logout = () => {
    console.log('🔐 [AUTH] Logging out...');
    
    // Clear auth data
    localStorage.removeItem(AUTH_TOKEN_KEY);
    localStorage.removeItem(AUTH_USER_KEY);

    setToken(null);
    setUser(null);

    // Trigger auth update event
    window.dispatchEvent(new Event('auth-updated'));

    // Redirect to home page
    router.push('/');
  };

  // Calculate roles and admin status
  const roles = user && Array.isArray(user.roles) ? user.roles : [];
  const isAdmin = roles.includes('admin');
  
  // Debug logging and ensure roles are loaded
  useEffect(() => {
    if (user && token) {
      const userRoles = Array.isArray(user.roles) ? user.roles : [];
      const userIsAdmin = userRoles.includes('admin');
      
      console.log('🔍 [AUTH] User state updated:', {
        userId: user.id,
        roles: user.roles,
        rolesArray: userRoles,
        isAdmin: userIsAdmin,
        rolesType: typeof user.roles,
        rolesIsArray: Array.isArray(user.roles)
      });
      
      // If user doesn't have roles, fetch from API
      if (!user.roles || !Array.isArray(user.roles) || user.roles.length === 0) {
        console.log('⚠️ [AUTH] User missing roles, fetching from API...');
        apiClient.get<{ roles: string[] }>('/api/v1/users/profile')
          .then(profileData => {
            if (profileData.roles && Array.isArray(profileData.roles)) {
              const updatedUser = { ...user, roles: profileData.roles };
              setUser(updatedUser);
              localStorage.setItem(AUTH_USER_KEY, JSON.stringify(updatedUser));
              console.log('✅ [AUTH] Roles updated from API:', profileData.roles);
            }
          })
          .catch(error => {
            console.error('❌ [AUTH] Failed to fetch user roles:', error);
          });
      }
    }
  }, [user, token]);

  const value: AuthContextType = {
    user,
    token,
    isLoggedIn: !!token && !!user,
    isLoading,
    isAdmin,
    roles,
    login,
    register,
    logout,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

/**
 * Hook to use auth context
 */
export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

