import { db } from "@white-shop/db";
import { logger } from "../../../utils/logger";
import type { ProductFilters } from "./types";
import { buildProductWhereClause, buildProductOrderByClause } from "./query-builder";
import { executeProductListQuery, executeProductDetailQuery } from "./query-executor";
import { formatProductForList } from "./product-formatter";
import { formatVariantForAdmin } from "./variant-formatter";

/**
 * Get products for admin
 */
export async function getProducts(filters: ProductFilters) {
  logger.info('getProducts called with filters', { filters });
  const startTime = Date.now();
  
  const page = filters.page || 1;
  const limit = filters.limit || 20;
  const skip = (page - 1) * limit;

  const where = buildProductWhereClause(filters);
  const orderBy = buildProductOrderByClause(filters);

  logger.debug('Executing database queries...', { where: JSON.stringify(where, null, 2) });

  const { products, total } = await executeProductListQuery(where, orderBy, skip, limit);

  const data = products.map(formatProductForList);

  const totalTime = Date.now() - startTime;
  logger.info(`getProducts completed in ${totalTime}ms. Returning ${data.length} products`);

  return {
    data,
    meta: {
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit),
    },
  };
}

/**
 * Get product by ID
 */
export async function getProductById(productId: string) {
  const product = await executeProductDetailQuery(productId);

  if (!product) {
    throw {
      status: 404,
      type: "https://api.shop.am/problems/not-found",
      title: "Product not found",
      detail: `Product with id '${productId}' does not exist`,
    };
  }

  // Безопасное получение translation с проверкой на существование массива
  const productWithRelations = product as typeof product & {
    translations?: Array<{ locale: string; title?: string; slug?: string; subtitle?: string | null; descriptionHtml?: string | null }>;
    labels?: Array<{ id: string; type: string; value: string; position: string; color: string | null }>;
    variants?: Array<unknown>;
  };
  const translations = Array.isArray(productWithRelations.translations) ? productWithRelations.translations : [];
  const translation = translations.find((t: { locale: string }) => t.locale === "en") || translations[0] || null;

  // Безопасное получение labels с проверкой на существование массива
  const labels = Array.isArray(productWithRelations.labels) ? productWithRelations.labels : [];
  
  // Безопасное получение variants с проверкой на существование массива
  const variants = Array.isArray(productWithRelations.variants) ? productWithRelations.variants : [];
  
  // Get all attribute IDs from productAttributes relation
  const productAttributes = Array.isArray((product as { productAttributes?: unknown[] }).productAttributes)
    ? (product as unknown as { productAttributes: Array<{ attributeId?: string; attribute?: { id: string } }> }).productAttributes
    : [];
  const attributeIds = productAttributes
    .map((pa) => pa.attributeId || pa.attribute?.id)
    .filter((id): id is string => !!id);
  
  // Also include attributeIds from product.attributeIds if available (backward compatibility)
  const legacyAttributeIds = Array.isArray((product as { attributeIds?: unknown[] }).attributeIds)
    ? (product as { attributeIds: string[] }).attributeIds
    : [];
  
  // Merge both sources and remove duplicates
  const allAttributeIds = Array.from(new Set([...attributeIds, ...legacyAttributeIds]));

  return {
    id: product.id,
    title: translation?.title || "",
    slug: translation?.slug || "",
    subtitle: translation?.subtitle || null,
    descriptionHtml: translation?.descriptionHtml || null,
    brandId: product.brandId || null,
    primaryCategoryId: product.primaryCategoryId || null,
    categoryIds: product.categoryIds || [],
    attributeIds: allAttributeIds, // All attribute IDs that this product has
    published: product.published,
    media: Array.isArray(product.media) ? product.media : [],
    labels: labels.map((label: { id: string; type: string; value: string; position: string; color: string | null }) => ({
      id: label.id,
      type: label.type,
      value: label.value,
      position: label.position,
      color: label.color,
    })),
    variants: variants.map((v) => formatVariantForAdmin(v as Parameters<typeof formatVariantForAdmin>[0])),
  };
}

import { Prisma } from "@prisma/client";
import { db } from "@white-shop/db";
import { ensureProductVariantAttributesColumn } from "../../../utils/db-ensure";
import { logger } from "../../../utils/logger";

/**
 * Base include configuration for product list queries
 */
const getProductListInclude = () => ({
  translations: {
    where: { locale: "en" },
    take: 1,
  },
  variants: {
    where: { published: true },
    take: 1,
    orderBy: { price: "asc" as const },
  },
  labels: true,
});

/**
 * Base include configuration for product detail queries
 */
const getProductDetailInclude = () => ({
  translations: true,
  brand: {
    include: {
      translations: true,
    },
  },
  categories: {
    include: {
      translations: true,
    },
  },
  variants: {
    include: {
      options: {
        include: {
          attributeValue: {
            include: {
              attribute: true,
              translations: true,
            },
          },
        },
      },
    },
    orderBy: {
      position: "asc" as const,
    },
  },
  labels: true,
});

/**
 * ProductAttributes include configuration
 */
const getProductAttributesInclude = () => ({
  productAttributes: {
    include: {
      attribute: true,
    },
  },
});

/**
 * Check if error is related to product_variants.attributes column
 */
function isVariantAttributesError(error: unknown): boolean {
  const errorMessage = error instanceof Error ? error.message : String(error);
  return errorMessage.includes('product_variants.attributes') || 
         (errorMessage.includes('attributes') && errorMessage.includes('does not exist'));
}

/**
 * Check if error is related to productAttributes table
 */
function isProductAttributesError(error: unknown): boolean {
  const errorObj = error as { code?: string; message?: string };
  const errorMessage = error instanceof Error ? error.message : String(error);
  return (errorObj && typeof errorObj === 'object' && 'code' in errorObj && errorObj.code === 'P2021') || 
         errorMessage.includes('productAttributes') || 
         errorMessage.includes('does not exist');
}

/**
 * Execute product list query with error handling
 */
export async function executeProductListQuery(
  where: Prisma.ProductWhereInput,
  orderBy: Prisma.ProductOrderByWithRelationInput,
  skip: number,
  take: number
) {
  const queryStartTime = Date.now();
  
  try {
    // Test database connection first
    logger.debug('Testing database connection...');
    await db.$queryRaw`SELECT 1`;
    logger.debug('Database connection OK');

    // Fetch products
    logger.debug('Fetching products...');
    const products = await db.product.findMany({
      where,
      skip,
      take,
      orderBy,
      include: getProductListInclude(),
    });
    
    const productsTime = Date.now() - queryStartTime;
    logger.debug(`Products fetched in ${productsTime}ms. Found ${products.length} products`);

    // Get count with timeout
    logger.debug('Counting total products...');
    const countStartTime = Date.now();
    
    const countPromise = db.product.count({ where });
    const timeoutPromise = new Promise<number>((_, reject) => 
      setTimeout(() => reject(new Error("Count query timeout")), 10000)
    );
    
    let total: number;
    try {
      total = await Promise.race([countPromise, timeoutPromise]) as number;
      const countTime = Date.now() - countStartTime;
      logger.debug(`Count completed in ${countTime}ms. Total: ${total}`);
    } catch (countError: unknown) {
      logger.warn('Count query failed, using estimated total', { 
        error: countError instanceof Error ? countError.message : String(countError) 
      });
      total = products.length || take;
    }
    
    const queryTime = Date.now() - queryStartTime;
    logger.debug(`All database queries completed in ${queryTime}ms`);

    return { products, total };
  } catch (error: unknown) {
    // If product_variants.attributes column doesn't exist, try to create it and retry
    if (isVariantAttributesError(error)) {
      logger.warn('product_variants.attributes column not found, attempting to create it...');
      try {
        await ensureProductVariantAttributesColumn();
        // Retry the query after creating the column
        const products = await db.product.findMany({
          where,
          skip,
          take,
          orderBy,
          include: getProductListInclude(),
        });
        
        const productsTime = Date.now() - queryStartTime;
        logger.debug(`Products fetched in ${productsTime}ms. Found ${products.length} products (after creating attributes column)`);
        
        // Get count
        const countStartTime = Date.now();
        const countPromise = db.product.count({ where });
        const timeoutPromise = new Promise<number>((_, reject) => 
          setTimeout(() => reject(new Error("Count query timeout")), 10000)
        );
        
        let total: number;
        try {
          total = await Promise.race([countPromise, timeoutPromise]) as number;
          const countTime = Date.now() - countStartTime;
          logger.debug(`Count completed in ${countTime}ms. Total: ${total}`);
        } catch (countError: unknown) {
          logger.warn('Count query failed, using estimated total', { 
            error: countError instanceof Error ? countError.message : String(countError) 
          });
          total = products.length || take;
        }
        
        const queryTime = Date.now() - queryStartTime;
        logger.debug(`All database queries completed in ${queryTime}ms`);

        return { products, total };
      } catch (retryError: unknown) {
        const queryTime = Date.now() - queryStartTime;
        const errorMessage = retryError instanceof Error ? retryError.message : String(retryError);
        logger.error(`Database query error after ${queryTime}ms (after retry)`, { error: errorMessage });
        throw retryError;
      }
    }

    const queryTime = Date.now() - queryStartTime;
    const errorMessage = error instanceof Error ? error.message : String(error);
    const errorObj = error as { code?: string; meta?: unknown; stack?: string };
    logger.error(`Database query error after ${queryTime}ms`, {
      error: {
        message: errorMessage,
        code: errorObj?.code,
        meta: errorObj?.meta,
        stack: errorObj?.stack?.substring(0, 500),
      },
    });
    
    throw error;
  }
}

/**
 * Execute product detail query with error handling
 */
export async function executeProductDetailQuery(productId: string) {
  try {
    const product = await db.product.findUnique({
      where: { id: productId },
      include: {
        ...getProductDetailInclude(),
        ...getProductAttributesInclude(),
      },
    });
    return product;
  } catch (error: unknown) {
    // If productAttributes table doesn't exist, retry without it
    if (isProductAttributesError(error)) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      logger.warn('productAttributes table not found, fetching without it', { error: errorMessage });
      const product = await db.product.findUnique({
        where: { id: productId },
        include: getProductDetailInclude(),
      });
      return product;
    }
    throw error;
  }
}

/**
 * Format variant for admin product detail response
 */
export function formatVariantForAdmin(variant: {
  id: string;
  price: number;
  compareAtPrice: number | null;
  stock: number;
  sku: string | null;
  imageUrl: string | null;
  published: boolean | null;
  attributes: unknown;
  options?: Array<{
    attributeKey: string | null;
    value: string | null;
    valueId: string | null;
    attributeValue?: {
      value: string;
      id: string;
      attribute: {
        key: string;
      };
    } | null;
  }>;
}) {
  // Безопасное получение options с проверкой на существование массива
  const options = Array.isArray(variant.options) ? variant.options : [];
  
  // Get attributes from JSONB column if available
  let attributes: Record<string, Array<{ valueId: string; value: string; attributeKey: string }>> | null = null;
  let colorValues: string[] = [];
  let sizeValues: string[] = [];
  
  if (variant.attributes && typeof variant.attributes === 'object') {
    // attributes is already in JSONB format: { "color": [...], "size": [...] }
    const attrs = variant.attributes as Record<string, unknown>;
    attributes = attrs as Record<string, Array<{ valueId: string; value: string; attributeKey: string }>>;
    
    // Extract color and size values from JSONB attributes
    if (attrs.color && Array.isArray(attrs.color)) {
      colorValues = attrs.color.map((item: unknown) => {
        if (item && typeof item === 'object' && 'value' in item) {
          return String((item as { value: unknown }).value);
        }
        return String(item);
      }).filter(Boolean);
    }
    if (attrs.size && Array.isArray(attrs.size)) {
      sizeValues = attrs.size.map((item: unknown) => {
        if (item && typeof item === 'object' && 'value' in item) {
          return String((item as { value: unknown }).value);
        }
        return String(item);
      }).filter(Boolean);
    }
  } else if (options.length > 0) {
    // Fallback: build attributes from options if JSONB column is empty
    const attributesMap: Record<string, Array<{ valueId: string; value: string; attributeKey: string }>> = {};
    options.forEach((opt) => {
      const attrKey = opt.attributeKey || opt.attributeValue?.attribute?.key;
      const value = opt.value || opt.attributeValue?.value;
      const valueId = opt.valueId || opt.attributeValue?.id;
      
      if (attrKey && value && valueId) {
        if (!attributesMap[attrKey]) {
          attributesMap[attrKey] = [];
        }
        if (!attributesMap[attrKey].some((item) => item.valueId === valueId)) {
          attributesMap[attrKey].push({
            valueId,
            value,
            attributeKey: attrKey,
          });
        }
        
        // Extract color and size for backward compatibility
        if (attrKey === "color") {
          colorValues.push(value);
        } else if (attrKey === "size") {
          sizeValues.push(value);
        }
      }
    });
    attributes = Object.keys(attributesMap).length > 0 ? attributesMap : null;
  }
  
  // For backward compatibility: use first color/size if multiple values exist
  const colorOption = options.find((opt) => opt.attributeKey === "color");
  const sizeOption = options.find((opt) => opt.attributeKey === "size");
  
  // Use first value from arrays or fallback to single option value
  const color = colorValues.length > 0 ? colorValues[0] : (colorOption?.value || "");
  const size = sizeValues.length > 0 ? sizeValues[0] : (sizeOption?.value || "");

  return {
    id: variant.id,
    price: variant.price.toString(),
    compareAtPrice: variant.compareAtPrice?.toString() || "",
    stock: variant.stock.toString(),
    sku: variant.sku || "",
    color: color, // First color for backward compatibility
    size: size, // First size for backward compatibility
    imageUrl: variant.imageUrl || "",
    published: variant.published || false,
    attributes: attributes, // JSONB attributes with all values - IMPORTANT: This is the main field
    options: options, // Keep options for backward compatibility
    // Additional fields for new format support
    colorValues: colorValues, // All color values
    sizeValues: sizeValues, // All size values
  };
}

import { Prisma } from "@prisma/client";
import { logger } from "../../../utils/logger";
import { processImageUrl, smartSplitUrls } from "../../../utils/image-utils";

/**
 * Update attribute value imageUrls from variant images
 */
export async function updateAttributeValueImageUrls(
  productId: string,
  tx: Prisma.TransactionClient
) {
  try {
    logger.debug('Updating attribute value imageUrls from variant images...');
    const allVariants = await tx.productVariant.findMany({
      where: { productId },
      include: {
        options: {
          include: {
            attributeValue: true,
          },
        },
      },
    });

    for (const variant of allVariants) {
      if (!variant.imageUrl) continue;

      // Use smartSplitUrls to properly handle comma-separated URLs and base64 images
      const variantImageUrls = smartSplitUrls(variant.imageUrl);
      if (variantImageUrls.length === 0) continue;

      // Process and validate first image URL
      const firstVariantImageUrl = processImageUrl(variantImageUrls[0]);
      if (!firstVariantImageUrl) {
        logger.debug(`Variant ${variant.id} has invalid imageUrl, skipping attribute value update`);
        continue;
      }

      // Get all attribute value IDs from this variant's options
      const attributeValueIds = new Set<string>();
      variant.options.forEach((opt) => {
        if (opt.valueId && opt.attributeValue) {
          attributeValueIds.add(opt.valueId);
        }
      });

      // Update each attribute value's imageUrl if it doesn't already have one
      for (const valueId of attributeValueIds) {
        const attrValue = await tx.attributeValue.findUnique({
          where: { id: valueId },
          include: {
            attribute: true,
          },
        });

        if (attrValue) {
          // Check if attribute is "color"
          const isColorAttribute = attrValue.attribute?.key === "color";
          
          // Check if attribute value only has colors but no imageUrl
          const hasColors = attrValue.colors && 
            (Array.isArray(attrValue.colors) ? attrValue.colors.length > 0 : 
             typeof attrValue.colors === 'string' ? attrValue.colors.trim() !== '' && attrValue.colors !== '[]' : 
             Object.keys(attrValue.colors || {}).length > 0);
          const hasNoImageUrl = !attrValue.imageUrl || attrValue.imageUrl.trim() === '';
          const isColorOnly = hasColors && hasNoImageUrl;

          // Skip updating if:
          // 1. It's a color attribute AND doesn't have an imageUrl, OR
          // 2. It only has colors but no imageUrl
          if ((isColorAttribute && hasNoImageUrl) || isColorOnly) {
            logger.debug(`Skipping attribute value ${valueId} - color attribute or color-only value without imageUrl`);
            continue;
          }

          // Only update if:
          // 1. Attribute value doesn't have an imageUrl, OR
          // 2. Variant image is a base64 (more specific) and attribute value has a URL
          const shouldUpdate = !attrValue.imageUrl || 
            (firstVariantImageUrl.startsWith('data:image/') && attrValue.imageUrl && !attrValue.imageUrl.startsWith('data:image/'));

          if (shouldUpdate) {
            logger.debug(`Updating attribute value ${valueId} imageUrl from variant ${variant.id}`, { 
              imageUrl: firstVariantImageUrl.substring(0, 50) + '...' 
            });
            await tx.attributeValue.update({
              where: { id: valueId },
              data: { imageUrl: firstVariantImageUrl },
            });
          } else {
            logger.debug(`Skipping attribute value ${valueId} - already has imageUrl`);
          }
        }
      }
    }
    logger.info('Finished updating attribute value imageUrls from variant images');
  } catch (error: unknown) {
    // Don't fail the transaction if this fails - it's a nice-to-have feature
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.warn('Failed to update attribute value imageUrls from variant images', { error: errorMessage });
  }
}

import { db } from "@white-shop/db";
import { Prisma } from "@prisma/client";
import { logger } from "../../../utils/logger";
import type { UpdateProductData } from "./types";
import { collectVariantImages, buildProductUpdateData, updateProductTranslation, updateProductLabels, updateProductAttributes } from "./product-updater";
import { updateOrCreateVariant } from "./variant-updater";
import { updateAttributeValueImageUrls } from "./attribute-value-updater";

/**
 * Update product
 */
export async function updateProduct(
  productId: string,
  data: UpdateProductData
) {
  try {
    logger.info('Updating product', { productId });
    
    // Check if product exists
    const existing = await db.product.findUnique({
      where: { id: productId },
      include: {
        translations: true,
      }
    });

    if (!existing) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Product not found",
        detail: `Product with id '${productId}' does not exist`,
      };
    }

    // Execute everything in a transaction for atomicity and speed
    const result = await db.$transaction(async (tx: Prisma.TransactionClient) => {
      // Collect all variant images to exclude from main media (if media is being updated)
      const allVariantImages = await collectVariantImages(data.variants, productId, tx);

      // 1. Update product base data
      const updateData = buildProductUpdateData(data, allVariantImages, existing);

      // 2. Update translation
      await updateProductTranslation(productId, data, tx);

      // 3. Update labels
      await updateProductLabels(productId, data.labels, tx);

      // 3.5. Update ProductAttribute relations
      await updateProductAttributes(productId, data.attributeIds, tx);

      // 4. Update variants
      if (data.variants !== undefined) {
        // Get existing variants with their IDs and SKUs for matching
        const existingVariants = await tx.productVariant.findMany({
          where: { productId },
          select: { id: true, sku: true },
        });
        const existingVariantIds = new Set<string>(existingVariants.map((v: { id: string }) => v.id));
        // Create a map of SKU -> variant ID for quick lookup
        const existingSkuMap = new Map<string, string>();
        existingVariants.forEach((v: { id: string; sku: string | null }) => {
          if (v.sku) {
            existingSkuMap.set(v.sku.trim().toLowerCase(), v.id);
          }
        });
        const incomingVariantIds = new Set<string>();
        
        const locale = data.locale || "en";
        
        // Process each variant: update if exists, create if new
        if (data.variants.length > 0) {
          for (const variant of data.variants) {
            const variantId = await updateOrCreateVariant(
              variant,
              productId,
              locale,
              existingVariantIds,
              existingSkuMap,
              tx
            );
            incomingVariantIds.add(variantId);
          }
        }
        
        // Delete variants that are no longer in the list
        const variantsToDelete = Array.from(existingVariantIds).filter(id => !incomingVariantIds.has(id));
        if (variantsToDelete.length > 0) {
          await tx.productVariant.deleteMany({
            where: {
              id: { in: variantsToDelete },
              productId,
            },
          });
          logger.info(`Deleted ${variantsToDelete.length} variant(s)`, { variantIds: variantsToDelete });
        }
      }

      // Update attribute value imageUrls from variant images
      await updateAttributeValueImageUrls(productId, tx);

      // 5. Finally update the product record itself
      return await tx.product.update({
        where: { id: productId },
        data: updateData,
        include: {
          translations: true,
          variants: {
            include: {
              options: true,
            },
          },
          labels: true,
        },
      });
    });

    return result;
  } catch (error: unknown) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error("updateProduct error", { error: errorMessage });
    throw error;
  }
}

import { findOrCreateAttributeValue } from "../../../utils/variant-generator";
import type { Prisma } from "@prisma/client";

/**
 * Variant option for processing
 */
export interface VariantOptionInput {
  attributeKey: string;
  value: string;
  valueId?: string;
}

/**
 * Processed variant option
 */
export interface ProcessedVariantOption {
  valueId?: string;
  attributeKey?: string;
  value?: string;
}

/**
 * Process variant options and build attributes map
 */
export async function processVariantOptions(
  variant: {
    options?: VariantOptionInput[];
    color?: string;
    size?: string;
  },
  locale: string,
  tx: Prisma.TransactionClient
): Promise<{
  options: ProcessedVariantOption[];
  attributesMap: Record<string, Array<{ valueId: string; value: string; attributeKey: string }>>;
}> {
  const options: ProcessedVariantOption[] = [];
  const attributesMap: Record<string, Array<{ valueId: string; value: string; attributeKey: string }>> = {};
  
  // Support both old format (color/size) and new format (options array)
  if (variant.options && Array.isArray(variant.options) && variant.options.length > 0) {
    // New format: use options array
    for (const opt of variant.options) {
      let valueId: string | null = null;
      let attributeKey: string | null = null;
      let value: string | null = null;

      if (opt.valueId) {
        valueId = opt.valueId;
        const attrValue = await tx.attributeValue.findUnique({
          where: { id: opt.valueId },
          include: { attribute: true },
        });
        if (attrValue) {
          attributeKey = attrValue.attribute.key;
          value = attrValue.value;
        }
        options.push({ valueId: opt.valueId });
      } else if (opt.attributeKey && opt.value) {
        const foundValueId = await findOrCreateAttributeValue(opt.attributeKey, opt.value, locale);
        if (foundValueId) {
          valueId = foundValueId;
          attributeKey = opt.attributeKey;
          value = opt.value;
          options.push({ valueId: foundValueId });
        } else {
          attributeKey = opt.attributeKey;
          value = opt.value;
          options.push({ attributeKey: opt.attributeKey, value: opt.value });
        }
      }

      // Build attributes JSONB structure
      if (attributeKey && valueId && value) {
        if (!attributesMap[attributeKey]) {
          attributesMap[attributeKey] = [];
        }
        if (!attributesMap[attributeKey].some(item => item.valueId === valueId)) {
          attributesMap[attributeKey].push({
            valueId,
            value,
            attributeKey,
          });
        }
      }
    }
  } else {
    // Old format: Try to find or create AttributeValues for color and size
    if (variant.color) {
      const colorValueId = await findOrCreateAttributeValue("color", variant.color, locale);
      if (colorValueId) {
        options.push({ valueId: colorValueId });
        if (!attributesMap["color"]) {
          attributesMap["color"] = [];
        }
        attributesMap["color"].push({
          valueId: colorValueId,
          value: variant.color,
          attributeKey: "color",
        });
      } else {
        // Fallback to old format if AttributeValue not found
        options.push({ attributeKey: "color", value: variant.color });
      }
    }
    
    if (variant.size) {
      const sizeValueId = await findOrCreateAttributeValue("size", variant.size, locale);
      if (sizeValueId) {
        options.push({ valueId: sizeValueId });
        if (!attributesMap["size"]) {
          attributesMap["size"] = [];
        }
        attributesMap["size"].push({
          valueId: sizeValueId,
          value: variant.size,
          attributeKey: "size",
        });
      } else {
        // Fallback to old format if AttributeValue not found
        options.push({ attributeKey: "size", value: variant.size });
      }
    }
  }

  return { options, attributesMap };
}

/**
 * Parse variant price, stock, and compareAtPrice
 */
export function parseVariantPrices(variant: {
  price: string | number;
  compareAtPrice?: string | number;
  stock: string | number;
}): {
  price: number;
  stock: number;
  compareAtPrice?: number;
} {
  const price = typeof variant.price === 'number' ? variant.price : parseFloat(String(variant.price));
  const stock = typeof variant.stock === 'number' ? variant.stock : parseInt(String(variant.stock), 10);
  const compareAtPrice = variant.compareAtPrice !== undefined && variant.compareAtPrice !== null && variant.compareAtPrice !== ''
    ? (typeof variant.compareAtPrice === 'number' ? variant.compareAtPrice : parseFloat(String(variant.compareAtPrice)))
    : undefined;

  if (isNaN(price) || price < 0) {
    throw new Error(`Invalid price value: ${variant.price}`);
  }

  return { price, stock, compareAtPrice };
}

import { db } from "@white-shop/db";

/** Payload from admin UI / API for bulk settings update. */
type AdminSettingsUpdatePayload = {
