import * as bcrypt from "bcryptjs";
import * as jwt from "jsonwebtoken";
import { db } from "@white-shop/db";
import { logger } from "../utils/logger";

export interface RegisterData {
  email?: string;
  phone?: string;
  password: string;
  firstName?: string;
  lastName?: string;
}

export interface LoginData {
  email?: string;
  phone?: string;
  password: string;
}

export interface AuthResponse {
  user: {
    id: string;
    email: string | null;
    phone: string | null;
    firstName: string | null;
    lastName: string | null;
    roles: string[];
  };
  token: string;
}

class AuthService {
  /**
   * Register new user
   */
  async register(data: RegisterData): Promise<AuthResponse> {
    logger.debug("Auth registration attempt", {
      hasEmail: !!data.email,
      hasPhone: !!data.phone,
      hasFirstName: !!data.firstName,
      hasLastName: !!data.lastName,
    });

    if (!data.email && !data.phone) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "Either email or phone is required",
      };
    }

    if (!data.password || data.password.length < 6) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "Password must be at least 6 characters",
      };
    }

    // Check if user already exists
    const existingUser = await db.user.findFirst({
      where: {
        OR: [
          ...(data.email ? [{ email: data.email }] : []),
          ...(data.phone ? [{ phone: data.phone }] : []),
        ],
        deletedAt: null,
      },
      select: { id: true },
    });

    if (existingUser) {
      logger.info("Auth registration rejected: user already exists");
      throw {
        status: 409,
        type: "https://api.shop.am/problems/conflict",
        title: "User already exists",
        detail: "User with this email or phone already exists",
      };
    }

    // Hash password
    const passwordHash = await bcrypt.hash(data.password, 10);

    // Create user
    let user;
    try {
      user = await db.user.create({
        data: {
          email: data.email || null,
          phone: data.phone || null,
          passwordHash,
          firstName: data.firstName || null,
          lastName: data.lastName || null,
          locale: "en",
          roles: ["customer"],
        },
        select: {
          id: true,
          email: true,
          phone: true,
          firstName: true,
          lastName: true,
          roles: true,
        },
      });
      logger.info("Auth user created", { userId: user.id });
    } catch (error: unknown) {
      const err = error as { code?: string };
      logger.error("Auth user creation failed", { error: err });
      if (err.code === "P2002") {
        // Prisma unique constraint error
        throw {
          status: 409,
          type: "https://api.shop.am/problems/conflict",
          title: "User already exists",
          detail: "User with this email or phone already exists",
        };
      }
      throw error;
    }

    // Generate JWT token
    if (!process.env.JWT_SECRET) {
      logger.error("Auth config error: JWT_SECRET is not set");
      throw {
        status: 500,
        type: "https://api.shop.am/problems/internal-error",
        title: "Internal Server Error",
        detail: "Server configuration error",
      };
    }

    const token = jwt.sign(
      { userId: user.id },
      process.env.JWT_SECRET as string,
      { expiresIn: process.env.JWT_EXPIRES_IN || "7d" } as jwt.SignOptions
    );
    logger.info("Auth registration success", { userId: user.id });

    return {
      user: {
        id: user.id,
        email: user.email,
        phone: user.phone,
        firstName: user.firstName,
        lastName: user.lastName,
        roles: user.roles,
      },
      token,
    };
  }

  /**
   * Login user
   */
  async login(data: LoginData): Promise<AuthResponse> {
    logger.debug("Auth login attempt", { hasEmail: !!data.email, hasPhone: !!data.phone });

    if (!data.email && !data.phone) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "Either email or phone is required",
      };
    }

    if (!data.password) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "Password is required",
      };
    }

    // Find user
    const user = await db.user.findFirst({
      where: {
        OR: [
          ...(data.email ? [{ email: data.email }] : []),
          ...(data.phone ? [{ phone: data.phone }] : []),
        ],
        deletedAt: null,
      },
      select: {
        id: true,
        email: true,
        phone: true,
        firstName: true,
        lastName: true,
        passwordHash: true,
        roles: true,
        blocked: true,
      },
    });

    if (!user || !user.passwordHash) {
      logger.debug("Auth login: user not found or no password");
      throw {
        status: 401,
        type: "https://api.shop.am/problems/unauthorized",
        title: "Invalid credentials",
        detail: "Invalid email/phone or password",
      };
    }

    // Check password
    const isValidPassword = await bcrypt.compare(
      data.password,
      user.passwordHash
    );

    if (!isValidPassword) {
      logger.debug("Auth login: invalid password");
      throw {
        status: 401,
        type: "https://api.shop.am/problems/unauthorized",
        title: "Invalid credentials",
        detail: "Invalid email/phone or password",
      };
    }

    if (user.blocked) {
      logger.info("Auth login rejected: account blocked", { userId: user.id });
      throw {
        status: 403,
        type: "https://api.shop.am/problems/forbidden",
        title: "Account blocked",
        detail: "Your account has been blocked",
      };
    }

    // Generate JWT token
    if (!process.env.JWT_SECRET) {
      throw {
        status: 500,
        type: "https://api.shop.am/problems/internal-error",
        title: "Internal Server Error",
        detail: "Server configuration error",
      };
    }

    const token = jwt.sign(
      { userId: user.id },
      process.env.JWT_SECRET as string,
      { expiresIn: process.env.JWT_EXPIRES_IN || "7d" } as jwt.SignOptions
    );

    logger.info("Auth login success", { userId: user.id });

    return {
      user: {
        id: user.id,
        email: user.email,
        phone: user.phone,
        firstName: user.firstName,
        lastName: user.lastName,
        roles: user.roles,
      },
      token,
    };
  }
}

export const authService = new AuthService();

/**
 * Cache Service
 *
 * Service for Redis caching integration
 * Handles caching operations with graceful fallback if Redis is unavailable.
 * When Redis is not configured, uses in-memory cache (per process) for dev/local.
 */

import type Redis from "ioredis";

// Redis client will be initialized lazily
let redisClient: Redis | null = null;
/** Upstash REST client when UPSTASH_REDIS_REST_* env vars are set */
let upstashClient: {
  get: (k: string) => Promise<string | null>;
  set: (k: string, v: string, opts?: Record<string, unknown>) => Promise<string | "OK" | null>;
  del: (...keys: string[]) => Promise<number>;
  keys: (pattern: string) => Promise<string[]>;
} | null = null;
let redisAvailable = false;
let connectionAttempted = false;
let errorLogged = false;
let lastErrorTime = 0;
const ERROR_COOLDOWN = 30000; // Only log errors every 30 seconds

/** In-memory fallback when Redis is not configured (dev/local) */
const MEMORY_CACHE_MAX_KEYS = 300;
const memoryCache = new Map<string, { value: string; expiresAt: number }>();

function memoryGet(key: string): string | null {
  const entry = memoryCache.get(key);
  if (!entry) return null;
  if (Date.now() > entry.expiresAt) {
    memoryCache.delete(key);
    return null;
  }
  return entry.value;
}

function memorySetex(key: string, seconds: number, value: string): void {
  while (memoryCache.size >= MEMORY_CACHE_MAX_KEYS) {
    const firstKey = memoryCache.keys().next().value;
    if (firstKey) memoryCache.delete(firstKey);
    else break;
  }
  memoryCache.set(key, {
    value,
    expiresAt: Date.now() + seconds * 1000,
  });
}

/**
 * Initialize Redis client (Upstash REST or ioredis TCP)
 */
async function initRedis() {
  if (connectionAttempted) {
    return;
  }

  const restUrl = process.env.UPSTASH_REDIS_REST_URL;
  const restToken = process.env.UPSTASH_REDIS_REST_TOKEN;
  const redisUrl = process.env.REDIS_URL;

  if (restUrl && restToken) {
    try {
      const { Redis } = await import("@upstash/redis");
      upstashClient = new Redis({ url: restUrl, token: restToken });
      redisAvailable = true;
      connectionAttempted = true;
      return;
    } catch (error: unknown) {
      const err = error as Error;
      connectionAttempted = true;
      redisAvailable = false;
      console.error("❌ [CACHE] Failed to init Upstash Redis:", err?.message ?? error);
      return;
    }
  }

  const useRedisTcp = redisUrl && redisUrl !== "redis://localhost:6379";
  if (!useRedisTcp) {
    connectionAttempted = true;
    return;
  }

  try {
    // Dynamic import for serverless compatibility
    const Redis = (await import('ioredis')).default;
    
    redisClient = new Redis(redisUrl, {
      retryStrategy: (times: number) => {
        if (times > 3) {
          return null; // Stop retrying
        }
        return Math.min(times * 50, 2000);
      },
      maxRetriesPerRequest: 3,
      enableReadyCheck: true,
      lazyConnect: true,
      showFriendlyErrorStack: true,
      enableOfflineQueue: false,
      reconnectOnError: () => false, // Don't auto-reconnect
    });

    redisClient.on('connect', () => {
      console.log('✅ Redis connected');
      errorLogged = false;
      redisAvailable = true;
    });

    redisClient.on('ready', () => {
      redisAvailable = true;
    });

    redisClient.on('error', (error: Error) => {
      redisAvailable = false;
      const now = Date.now();
      if (!errorLogged || (now - lastErrorTime) > ERROR_COOLDOWN) {
        console.error('⚠️  Redis connection error:', error.message);
        console.error('💡 Check REDIS_URL in .env or start Redis server');
        errorLogged = true;
        lastErrorTime = now;
      }
    });

    await redisClient.connect();
    connectionAttempted = true;
  } catch (error: unknown) {
    connectionAttempted = true;
    redisAvailable = false;
    const msg = error instanceof Error ? error.message : String(error);
    console.error('❌ [CACHE] Failed to initialize Redis:', msg);
  }
}

/**
 * Get value from cache
 */
export async function get(key: string): Promise<string | null> {
  if (!redisAvailable) {
    await initRedis();
  }

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    return memoryGet(key);
  }

  try {
    if (upstashClient) {
      const v = await upstashClient.get(key);
      return v ?? null;
    }
    if (redisClient) {
      return await redisClient.get(key);
    }
    return memoryGet(key);
  } catch (error) {
    return memoryGet(key);
  }
}

/**
 * Set value in cache
 */
export async function set(key: string, value: string): Promise<boolean> {
  if (!redisAvailable) {
    await initRedis();
  }

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    return false;
  }

  try {
    if (upstashClient) {
      await upstashClient.set(key, value);
      return true;
    }
    if (redisClient) {
      await redisClient.set(key, value);
      return true;
    }
    return false;
  } catch (error) {
    return false;
  }
}

/**
 * Set value in cache with expiration
 */
export async function setex(key: string, seconds: number, value: string): Promise<boolean> {
  if (!redisAvailable) {
    await initRedis();
  }

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    memorySetex(key, seconds, value);
    return true;
  }

  try {
    if (upstashClient) {
      await upstashClient.set(key, value, { ex: seconds });
      return true;
    }
    if (redisClient) {
      await redisClient.setex(key, seconds, value);
      return true;
    }
    memorySetex(key, seconds, value);
    return true;
  } catch (error) {
    memorySetex(key, seconds, value);
    return true;
  }
}

/**
 * Delete key from cache
 */
export async function del(key: string): Promise<boolean> {
  if (!redisAvailable) {
    await initRedis();
  }

  memoryCache.delete(key);

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    return true;
  }

  try {
    if (upstashClient) {
      await upstashClient.del(key);
      return true;
    }
    if (redisClient) {
      await redisClient.del(key);
      return true;
    }
    return false;
  } catch (error) {
    return false;
  }
}

/**
 * Get multiple keys matching pattern
 */
export async function keys(pattern: string): Promise<string[]> {
  if (!redisAvailable) {
    await initRedis();
  }

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    return [];
  }

  try {
    if (upstashClient) {
      return await upstashClient.keys(pattern);
    }
    if (redisClient) {
      return await redisClient.keys(pattern);
    }
    return [];
  } catch (error) {
    return [];
  }
}

/**
 * Delete multiple keys matching pattern
 */
export async function deletePattern(pattern: string): Promise<number> {
  if (!redisAvailable) {
    await initRedis();
  }

  const regex = pattern.replace(/\*/g, ".*").replace(/\?/g, ".");
  const re = new RegExp(`^${regex}$`);
  let memoryDeleted = 0;
  for (const key of memoryCache.keys()) {
    if (re.test(key)) {
      memoryCache.delete(key);
      memoryDeleted++;
    }
  }

  if (!redisAvailable || (!redisClient && !upstashClient)) {
    return memoryDeleted;
  }

  try {
    if (upstashClient) {
      const matchingKeys = await upstashClient.keys(pattern);
      if (matchingKeys.length > 0) {
        await upstashClient.del(...matchingKeys);
      }
      return matchingKeys.length + memoryDeleted;
    }
    if (redisClient) {
      const matchingKeys = await redisClient.keys(pattern);
      if (matchingKeys.length > 0) {
        await redisClient.del(...matchingKeys);
      }
      return matchingKeys.length + memoryDeleted;
    }
    return memoryDeleted;
  } catch (error) {
    return memoryDeleted;
  }
}

/**
 * Check if Redis is available
 */
export function isAvailable(): boolean {
  return redisAvailable;
}

export const cacheService = {
  get,
  set,
  setex,
  del,
  keys,
  deletePattern,
  isAvailable,
};

import { db } from "@white-shop/db";
import { logger } from "../utils/logger";
import { extractMediaUrl } from "../utils/extractMediaUrl";

class CartService {
  /**
   * Get or create user's cart
   */
  async getCart(userId: string, locale: string = "en") {
    // Get discount settings
    const discountSettings = await db.settings.findMany({
      where: {
        key: {
          in: ["globalDiscount", "categoryDiscounts", "brandDiscounts"],
        },
      },
    });

    const globalDiscount =
      Number(
        discountSettings.find((s: { key: string; value: unknown }) => s.key === "globalDiscount")?.value
      ) || 0;
    
    const categoryDiscountsSetting = discountSettings.find((s: { key: string; value: unknown }) => s.key === "categoryDiscounts");
    const categoryDiscounts = categoryDiscountsSetting ? (categoryDiscountsSetting.value as Record<string, number>) || {} : {};
    
    const brandDiscountsSetting = discountSettings.find((s: { key: string; value: unknown }) => s.key === "brandDiscounts");
    const brandDiscounts = brandDiscountsSetting ? (brandDiscountsSetting.value as Record<string, number>) || {} : {};
    let cart = await db.cart.findFirst({
      where: {
        userId,
      },
      include: {
        items: {
          include: {
            variant: {
              include: {
                product: {
                  include: {
                    translations: true,
                  },
                },
              },
            },
            product: {
              include: {
                translations: true,
              },
            },
          },
        },
      },
    });

    if (!cart) {
      cart = await db.cart.create({
        data: {
          userId,
          locale,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000), // 30 days
          items: {
            create: [],
          },
        },
        include: {
          items: {
            include: {
              variant: {
                include: {
                  product: {
                    include: {
                      translations: true,
                    },
                  },
                },
              },
              product: {
                include: {
                  translations: true,
                },
              },
            },
          },
        },
      });
    }

    // Format items using already-loaded cart data (no N+1: no extra DB calls per item)
    const itemsWithDetails = cart.items.map(
      (item: {
        id: string;
        productId: string;
        variantId: string;
        quantity: number;
        product: {
          id: string;
          media: unknown;
          discountPercent?: number;
          primaryCategoryId?: string | null;
          brandId?: string | null;
          translations: Array<{ locale: string; title?: string; slug?: string }>;
        };
        variant: {
          id: string;
          sku: string | null;
          stock: number;
          price: number;
          compareAtPrice?: number | null;
        };
      }) => {
        const product = item.product;
        const variant = item.variant;
        const translation =
          product?.translations?.find((t: { locale: string }) => t.locale === locale) ||
          product?.translations?.[0];

        const imageUrl = extractMediaUrl(product?.media);

        const productDiscount = product?.discountPercent ?? 0;
        let appliedDiscount = 0;
        if (productDiscount > 0) {
          appliedDiscount = productDiscount;
        } else {
          const primaryCategoryId = product?.primaryCategoryId;
          if (primaryCategoryId && categoryDiscounts[primaryCategoryId]) {
            appliedDiscount = categoryDiscounts[primaryCategoryId];
          } else {
            const brandId = product?.brandId;
            if (brandId && brandDiscounts[brandId]) {
              appliedDiscount = brandDiscounts[brandId];
            } else if (globalDiscount > 0) {
              appliedDiscount = globalDiscount;
            }
          }
        }

        const variantOriginalPrice = variant?.price ?? 0;
        let finalPrice = variantOriginalPrice;
        let originalPrice: number | null = null;
        if (appliedDiscount > 0 && variantOriginalPrice > 0) {
          finalPrice = variantOriginalPrice * (1 - appliedDiscount / 100);
          originalPrice = variantOriginalPrice;
        } else if (variant?.compareAtPrice != null && variant.compareAtPrice > variantOriginalPrice) {
          originalPrice = Number(variant.compareAtPrice);
        }

        return {
          id: item.id,
          variant: {
            id: variant?.id ?? item.variantId,
            sku: variant?.sku ?? "",
            stock: variant?.stock ?? 0,
            product: {
              id: product?.id ?? "",
              title: translation?.title ?? "",
              slug: translation?.slug ?? "",
              image: imageUrl,
            },
          },
          quantity: item.quantity,
          price: finalPrice,
          originalPrice,
          total: finalPrice * item.quantity,
        };
      }
    );

    const subtotal = itemsWithDetails.reduce((sum, item) => sum + item.total, 0);

    return {
      cart: {
        id: cart.id,
        items: itemsWithDetails,
        totals: {
          subtotal,
          discount: 0,
          shipping: 0,
          tax: 0,
          total: subtotal,
          currency: "AMD",
        },
        itemsCount: itemsWithDetails.reduce((sum, item) => sum + item.quantity, 0),
      },
    };
  }

  /**
   * Add item to cart
   */
  async addItem(
    userId: string,
    data: { variantId: string; productId: string; quantity?: number },
    locale: string = "en"
  ) {
    const { variantId, productId, quantity = 1 } = data;

    if (!variantId || !productId) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "variantId and productId are required",
      };
    }

    const [cart, variant] = await Promise.all([
      db.cart.findFirst({
        where: { userId },
        include: { items: true },
      }),
      db.productVariant.findUnique({
        where: { id: variantId },
        select: { id: true, published: true, productId: true, stock: true, price: true },
      }),
    ]);

    let resolvedCart = cart;
    if (!resolvedCart) {
      resolvedCart = await db.cart.create({
        data: {
          userId,
          locale,
          expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
          items: { create: [] },
        },
        include: { items: true },
      });
    }

    if (!variant || !variant.published || variant.productId !== productId) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Variant not found",
      };
    }

    const existingItem = resolvedCart.items.find((item: { variantId: string }) => item.variantId === variantId);

    // Calculate total quantity that will be in cart after adding
    const totalQuantity = existingItem ? existingItem.quantity + quantity : quantity;

    // Check if total quantity exceeds available stock
    if (totalQuantity > variant.stock) {
      logger.warn("Cart: stock limit exceeded", {
        variantId,
        currentInCart: existingItem?.quantity ?? 0,
        requestedQuantity: quantity,
        totalQuantity,
        availableStock: variant.stock,
      });
      throw {
        status: 422,
        type: "https://api.shop.am/problems/validation-error",
        title: "Insufficient stock",
        detail: `No more stock available. Maximum available: ${variant.stock}, already in cart: ${existingItem?.quantity || 0}, requested: ${quantity}`,
      };
    }

    let item;
    if (existingItem) {
      logger.debug("Cart: updating existing item", {
        itemId: existingItem.id,
        oldQuantity: existingItem.quantity,
        newQuantity: totalQuantity,
      });
      item = await db.cartItem.update({
        where: { id: existingItem.id },
        data: {
          quantity: totalQuantity,
        },
      });
      // Summary from current state: other items + this updated item (no extra DB query)
      const otherItems = resolvedCart.items.filter((i: { id: string }) => i.id !== existingItem.id);
      const itemsForSum = [
        ...otherItems.map((i: { quantity: number; priceSnapshot: unknown }) => ({ q: i.quantity, p: Number(i.priceSnapshot) })),
        { q: totalQuantity, p: Number(item.priceSnapshot) },
      ];
      const itemsCount = itemsForSum.reduce((sum, i) => sum + i.q, 0);
      const total = itemsForSum.reduce((sum, i) => sum + i.q * i.p, 0);
      return {
        item: { id: item.id, variantId, quantity: item.quantity, price: Number(item.priceSnapshot) },
        cartSummary: { itemsCount, total },
      };
    } else {
      logger.debug("Cart: creating new item", { variantId, quantity });
      item = await db.cartItem.create({
        data: {
          cartId: resolvedCart.id,
          variantId,
          productId,
          quantity,
          priceSnapshot: variant.price,
        },
      });
      const itemsForSum = [
        ...resolvedCart.items.map((i: { quantity: number; priceSnapshot: unknown }) => ({ q: i.quantity, p: Number(i.priceSnapshot) })),
        { q: quantity, p: Number(variant.price) },
      ];
      const itemsCount = itemsForSum.reduce((sum, i) => sum + i.q, 0);
      const total = itemsForSum.reduce((sum, i) => sum + i.q * i.p, 0);
      return {
        item: { id: item.id, variantId, quantity: item.quantity, price: Number(item.priceSnapshot) },
        cartSummary: { itemsCount, total },
      };
    }
  }

  /**
   * Update cart item
   */
  async updateItem(userId: string, itemId: string, quantity: number) {
    if (!quantity || quantity < 1) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation failed",
        detail: "quantity must be at least 1",
      };
    }

    const cart = await db.cart.findFirst({
      where: {
        userId,
        items: {
          some: {
            id: itemId,
          },
        },
      },
      include: {
        items: {
          where: { id: itemId },
        },
      },
    });

    if (!cart || cart.items.length === 0) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Cart item not found",
      };
    }

    const item = cart.items[0];
    const variant = await db.productVariant.findUnique({
      where: { id: item.variantId },
    });

    if (!variant || variant.stock < quantity) {
      throw {
        status: 422,
        type: "https://api.shop.am/problems/validation-error",
        title: "Insufficient stock",
        detail: `Requested quantity (${quantity}) exceeds available stock (${variant?.stock || 0})`,
      };
    }

    const updatedItem = await db.cartItem.update({
      where: { id: itemId },
      data: { quantity },
    });

    return {
      item: {
        id: updatedItem.id,
        quantity: updatedItem.quantity,
      },
    };
  }

  /**
   * Remove item from cart
   */
  async removeItem(userId: string, itemId: string) {
    const cart = await db.cart.findFirst({
      where: {
        userId,
        items: {
          some: {
            id: itemId,
          },
        },
      },
    });

    if (!cart) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Cart item not found",
      };
    }

    await db.cartItem.delete({
      where: { id: itemId },
    });

    return null;
  }
}

export const cartService = new CartService();

import { db } from "@white-shop/db";
import { Prisma } from "@prisma/client";
import { customAlphabet } from "nanoid";
import type { CheckoutData } from "../types/checkout";
import { logger } from "../utils/logger";
import { adminDeliveryService } from "./supersudo/supersudo-delivery.service";
import { extractMediaUrl } from "../utils/extractMediaUrl";

const orderNumberId = customAlphabet("0123456789ABCDEFGHJKLMNPQRSTUVWXYZ", 10);

function generateOrderNumber(): string {
  const now = new Date();
  const ymd =
    now.getFullYear().toString().slice(-2) +
    String(now.getMonth() + 1).padStart(2, "0") +
    String(now.getDate()).padStart(2, "0");
  return `${ymd}-${orderNumberId()}`;
}
type CartItemWithRelations = Prisma.CartItemGetPayload<{
  include: {
    product: {
      include: {
        translations: true;
      };
    };
    variant: {
      include: {
        options: true;
      };
    };
  };
}>;

type ProductVariantWithProduct = Prisma.ProductVariantGetPayload<{
  include: {
    product: {
      include: {
        translations: true;
      };
    };
    options: true;
  };
}>;

type OrderItemWithVariant = Prisma.OrderItemGetPayload<{
  include: {
    variant: {
      include: {
        options: {
          include: {
            attributeValue: {
              include: {
                translations: true;
                attribute: true;
              };
            };
          };
        };
      };
    };
  };
}>;

class OrdersService {
  /**
   * Create order (checkout)
   */
  async checkout(data: CheckoutData, userId?: string) {
    try {
      const {
        cartId,
        items: guestItems,
        email,
        phone,
        shippingMethod = 'pickup',
        shippingAddress,
        paymentMethod = 'idram',
      } = data;
      // shippingAmount is ignored — computed server-side from shippingMethod and address

      // Validate required fields
      if (!email || !phone) {
        throw {
          status: 400,
          type: "https://api.shop.am/problems/validation-error",
          title: "Validation Error",
          detail: "Email and phone are required",
        };
      }

      // Get cart items - either from user cart or guest items
      let cartItems: Array<{
        variantId: string;
        productId: string;
        quantity: number;
        price: number;
        productTitle: string;
        variantTitle?: string;
        sku: string;
        imageUrl?: string;
      }> = [];

      if (userId && cartId && cartId !== 'guest-cart') {
        // Get items from user's cart
        const cart = await db.cart.findFirst({
          where: { id: cartId, userId },
          include: {
            items: {
              include: {
                variant: {
                  include: {
                    product: {
                      include: {
                        translations: true,
                      },
                    },
                    options: true,
                  },
                },
                product: {
                  include: {
                    translations: true,
                  },
                },
              },
            },
          },
        });

        if (!cart || cart.items.length === 0) {
          throw {
            status: 400,
            type: "https://api.shop.am/problems/validation-error",
            title: "Cart is empty",
            detail: "Cannot checkout with an empty cart",
          };
        }

        // Format cart items
        logger.debug('Processing cart items', { count: cart.items.length });
        
        cartItems = await Promise.all(
          cart.items.map(async (item: CartItemWithRelations) => {
            const product = item.product;
            const variant = item.variant;
            
            if (!variant) {
              logger.error('Cart item missing variant', {
                itemId: item.id,
                variantId: item.variantId,
                productId: item.productId,
              });
              throw {
                status: 404,
                type: "https://api.shop.am/problems/not-found",
                title: "Variant not found",
                detail: `Variant ${item.variantId} not found for cart item`,
              };
            }
            
            logger.debug('Processing cart item', {
              itemId: item.id,
              variantId: variant.id,
              productId: product.id,
              quantity: item.quantity,
              variantStock: variant.stock,
              variantSku: variant.sku,
            });
            
            const translation = product.translations?.[0] || product.translations?.[0];

            // Get variant title from options
            const variantTitle = variant.options
              ?.map((opt) => `${opt.attributeKey || ''}: ${opt.value || ''}`)
              .join(', ') || undefined;

            // Get image URL
            const imageUrl = extractMediaUrl(product.media) ?? undefined;

            // Check stock availability
            if (variant.stock < item.quantity) {
              throw {
                status: 422,
                type: "https://api.shop.am/problems/validation-error",
                title: "Insufficient stock",
                detail: `Product "${translation?.title || 'Unknown'}" - insufficient stock. Available: ${variant.stock}, Requested: ${item.quantity}`,
              };
            }

            // Use current variant price from DB (ignore priceSnapshot to prevent outdated/abused prices)
            const currentPrice = Number(variant.price);
            const cartItem = {
              variantId: variant.id,
              productId: product.id,
              quantity: item.quantity,
              price: currentPrice,
              productTitle: translation?.title || 'Unknown Product',
              variantTitle,
              sku: variant.sku || '',
              imageUrl,
            };
            
            logger.debug('Cart item formatted', {
              variantId: cartItem.variantId,
              productId: cartItem.productId,
              quantity: cartItem.quantity,
              sku: cartItem.sku,
            });
            
            return cartItem;
          })
        );
        
        logger.info('All cart items processed', { count: cartItems.length });
      } else if (guestItems && Array.isArray(guestItems) && guestItems.length > 0) {
        // Validate and collect variant IDs
        const variantIds: string[] = [];
        for (const item of guestItems) {
          if (!item.productId || !item.variantId || !item.quantity) {
            throw {
              status: 400,
              type: "https://api.shop.am/problems/validation-error",
              title: "Validation Error",
              detail: "Each item must have productId, variantId, and quantity",
            };
          }
          variantIds.push(item.variantId);
        }
        const uniqueVariantIds = [...new Set(variantIds)];

        // Batch fetch all variants (one query instead of N)
        const variants = await db.productVariant.findMany({
          where: { id: { in: uniqueVariantIds } },
          include: {
            product: { include: { translations: true } },
            options: true,
          },
        });
        const variantMap = new Map(variants.map((v) => [v.id, v]));

        cartItems = guestItems.map((item: { productId: string; variantId: string; quantity: number }) => {
          const variant = variantMap.get(item.variantId);
          if (!variant || variant.productId !== item.productId) {
            throw {
              status: 404,
              type: "https://api.shop.am/problems/not-found",
              title: "Product variant not found",
              detail: `Variant ${item.variantId} not found for product ${item.productId}`,
            };
          }
          if (variant.stock < item.quantity) {
            throw {
              status: 422,
              type: "https://api.shop.am/problems/validation-error",
              title: "Insufficient stock",
              detail: `Insufficient stock. Available: ${variant.stock}, Requested: ${item.quantity}`,
            };
          }
          const translation = variant.product.translations?.[0] || variant.product.translations?.[0];
          const variantTitle = variant.options
            ?.map((opt: { attributeKey?: string | null; value?: string | null }) => `${opt.attributeKey ?? ""}: ${opt.value ?? ""}`)
            .join(", ") ?? undefined;
          const imageUrl = extractMediaUrl(variant.product.media) ?? undefined;
          return {
            variantId: variant.id,
            productId: variant.product.id,
            quantity: item.quantity,
            price: Number(variant.price),
            productTitle: translation?.title ?? "Unknown Product",
            variantTitle,
            sku: variant.sku ?? "",
            imageUrl,
          };
        });
      } else {
        throw {
          status: 400,
          type: "https://api.shop.am/problems/validation-error",
          title: "Cart is empty",
          detail: "Cannot checkout with an empty cart",
        };
      }

      if (cartItems.length === 0) {
        throw {
          status: 400,
          type: "https://api.shop.am/problems/validation-error",
          title: "Cart is empty",
          detail: "Cannot checkout with an empty cart",
        };
      }

      // Calculate totals
      const subtotal = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
      const discountAmount = 0; // TODO: Implement discount/coupon logic
      // Shipping: computed server-side only (never trust client-provided amount)
      let shippingAmount = 0;
      if (shippingMethod === 'delivery' && shippingAddress?.city?.trim()) {
        const country = (shippingAddress.countryCode ?? 'Armenia').toString();
        shippingAmount = await adminDeliveryService.getDeliveryPrice(
          shippingAddress.city.trim(),
          country
        );
        if (shippingAmount < 0) shippingAmount = 0;
      }
      const taxAmount = 0; // TODO: Calculate tax if needed
      const total = subtotal - discountAmount + shippingAmount + taxAmount;

      // Generate order number
      const orderNumber = generateOrderNumber();

      // Create order with items in a transaction (timeout to avoid hung connections)
      const order = await db.$transaction(
        async (tx: Prisma.TransactionClient) => {
        // Create order
        const newOrder = await tx.order.create({
          data: {
            number: orderNumber,
            userId: userId || null,
            status: 'pending',
            paymentStatus: 'pending',
            fulfillmentStatus: 'unfulfilled',
            subtotal,
            discountAmount,
            shippingAmount,
            taxAmount,
            total,
            currency: 'AMD',
            customerEmail: email,
            customerPhone: phone,
            customerLocale: 'en', // TODO: Get from request
            shippingMethod,
            shippingAddress: shippingAddress ? JSON.parse(JSON.stringify(shippingAddress)) : null,
            billingAddress: shippingAddress ? JSON.parse(JSON.stringify(shippingAddress)) : null,
            items: {
              create: cartItems.map((item) => ({
                variantId: item.variantId,
                productTitle: item.productTitle,
                variantTitle: item.variantTitle,
                sku: item.sku,
                quantity: item.quantity,
                price: item.price,
                total: item.price * item.quantity,
                imageUrl: item.imageUrl,
              })),
            },
            events: {
              create: {
                type: 'order_created',
                data: {
                  source: userId ? 'user' : 'guest',
                  paymentMethod,
                  shippingMethod,
                },
              },
            },
          },
          include: {
            items: true,
          },
        });

        // Update stock atomically: only decrement if stock >= quantity (avoids race condition)
        logger.debug('Updating stock for variants', { count: cartItems.length });
        
        try {
          for (const item of cartItems) {
            if (!item.variantId) {
              logger.error('Missing variantId for item', { item });
              throw {
                status: 400,
                type: "https://api.shop.am/problems/validation-error",
                title: "Validation Error",
                detail: `Missing variantId for item with SKU: ${item.sku}`,
              };
            }

            const quantity = Number(item.quantity);
            const variantId = item.variantId;
            const updated = await tx.$executeRaw(
              Prisma.sql`UPDATE product_variants SET stock = stock - ${quantity} WHERE id = ${variantId} AND stock >= ${quantity}`
            );
            if (updated === 0) {
              const variant = await tx.productVariant.findUnique({
                where: { id: variantId },
                select: { sku: true, stock: true },
              });
              logger.error('Insufficient stock on atomic decrement', {
                variantId,
                sku: variant?.sku,
                currentStock: variant?.stock,
                requested: quantity,
              });
              throw {
                status: 422,
                type: "https://api.shop.am/problems/validation-error",
                title: "Insufficient stock",
                detail: `Insufficient stock for SKU ${variant?.sku ?? variantId}. Available: ${variant?.stock ?? 0}, requested: ${quantity}`,
              };
            }
            logger.debug('Stock decremented', { variantId, quantity });
          }
          logger.info('All variant stocks updated successfully');
        } catch (stockError: unknown) {
          const err = stockError as { status?: number; type?: string };
          if (err.status && err.type) throw stockError;
          logger.error('Error updating stock', { error: stockError });
          throw stockError;
        }

        // Create payment record
        const payment = await tx.payment.create({
          data: {
            orderId: newOrder.id,
            provider: paymentMethod,
            method: paymentMethod,
            amount: total,
            currency: 'AMD',
            status: 'pending',
          },
        });

        // If user cart, delete cart after successful checkout
        if (userId && cartId && cartId !== 'guest-cart') {
          await tx.cart.delete({
            where: { id: cartId },
          });
        }

        return { order: newOrder, payment };
      },
        { timeout: 10000, maxWait: 5000 }
      );

      // Return order and payment info
      return {
        order: {
          id: order.order.id,
          number: order.order.number,
          status: order.order.status,
          paymentStatus: order.order.paymentStatus,
          total: order.order.total,
          currency: order.order.currency,
        },
        payment: {
          provider: order.payment.provider,
          paymentUrl: null, // TODO: Generate payment URL for Idram/ArCa
          expiresAt: null, // TODO: Set expiration if needed
        },
        nextAction: paymentMethod === 'idram' || paymentMethod === 'arca' 
          ? 'redirect_to_payment' 
          : 'view_order',
      };
    } catch (error: unknown) {
      // Type guard for custom error
      const customError = error as { status?: number; type?: string; message?: string; code?: string; name?: string; meta?: unknown; stack?: string };
      
      // If it's already our custom error, re-throw it
      if (customError.status && customError.type) {
        throw error;
      }

      // Log unexpected errors
      logger.error("Checkout error", {
        error: {
          name: customError?.name,
          message: customError?.message,
          code: customError?.code,
          meta: customError?.meta,
          stack: customError?.stack?.substring(0, 500),
        },
      });

      // Handle Prisma errors
      if (customError?.code === 'P2002') {
        throw {
          status: 409,
          type: "https://api.shop.am/problems/conflict",
          title: "Conflict",
          detail: "Order number already exists, please try again",
        };
      }

      // Generic error
      throw {
        status: 500,
        type: "https://api.shop.am/problems/internal-error",
        title: "Internal Server Error",
        detail: customError?.message || "An error occurred during checkout",
      };
    }
  }

  /**
   * Get user orders list (paginated)
   */
  async list(userId: string, options?: { page?: number; limit?: number }) {
    const page = Math.max(1, options?.page ?? 1);
    const limit = Math.min(100, Math.max(1, options?.limit ?? 20));
    const skip = (page - 1) * limit;

    const [orders, total] = await Promise.all([
      db.order.findMany({
        where: { userId },
        include: {
          items: { select: { id: true } },
          payments: { select: { id: true } },
        },
        orderBy: { createdAt: "desc" },
        skip,
        take: limit,
      }),
      db.order.count({ where: { userId } }),
    ]);

    return {
      data: orders.map((order: {
        id: string;
        number: string;
        status: string;
        paymentStatus: string;
        fulfillmentStatus: string;
        total: number;
        subtotal: number;
        discountAmount: number;
        shippingAmount: number;
        taxAmount: number;
        currency: string;
        createdAt: Date;
        items: Array<{ id: string }>;
      }) => ({
        id: order.id,
        number: order.number,
        status: order.status,
        paymentStatus: order.paymentStatus,
        fulfillmentStatus: order.fulfillmentStatus,
        total: order.total,
        subtotal: order.subtotal,
        discountAmount: order.discountAmount,
        shippingAmount: order.shippingAmount,
        taxAmount: order.taxAmount,
        currency: order.currency,
        createdAt: order.createdAt,
        itemsCount: order.items.length,
      })),
      meta: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  /**
   * Get order by number
   */
  async findByNumber(orderNumber: string, userId: string) {
    const order = await db.order.findFirst({
      where: {
        number: orderNumber,
        userId,
      },
      include: {
        items: {
          include: {
            variant: {
              include: {
                options: {
                  include: {
                    attributeValue: {
                      include: {
                        attribute: true,
                        translations: true,
                      },
                    },
                  },
                },
              },
            },
          },
        },
        payments: true,
        events: true,
      },
    });

    if (!order) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Order not found",
        detail: `Order with number '${orderNumber}' not found`,
      };
    }

    // Parse shipping address if it's a JSON string
    let shippingAddress = order.shippingAddress;
    if (typeof shippingAddress === 'string') {
      try {
        shippingAddress = JSON.parse(shippingAddress);
      } catch {
        shippingAddress = null;
      }
    }

    // Debug logging
    logger.info('Order found', {
      orderNumber: order.number,
      itemsCount: order.items.length,
      items: order.items.map((item: OrderItemWithVariant) => ({
        variantId: item.variantId,
        productTitle: item.productTitle,
        variant: item.variant ? {
          id: item.variant.id,
          optionsCount: item.variant.options?.length || 0,
          options: item.variant.options,
        } : null,
      })),
    });

    return {
      id: order.id,
      number: order.number,
      status: order.status,
      paymentStatus: order.paymentStatus,
      fulfillmentStatus: order.fulfillmentStatus,
      items: order.items.map((item: OrderItemWithVariant) => {
        const variantOptions = item.variant?.options?.map((opt) => {
          // Debug logging for each option
          logger.debug('Processing option', {
            attributeKey: opt.attributeKey,
            value: opt.value,
            valueId: opt.valueId,
            hasAttributeValue: !!opt.attributeValue,
            attributeValueData: opt.attributeValue ? {
              value: opt.attributeValue.value,
              attributeKey: opt.attributeValue.attribute.key,
              imageUrl: opt.attributeValue.imageUrl,
              hasTranslations: opt.attributeValue.translations?.length > 0,
            } : null,
          });

          // New format: Use AttributeValue if available
          if (opt.attributeValue) {
            // Get label from translations (prefer current locale, fallback to first available)
            const translations = opt.attributeValue.translations || [];
            const label = translations.length > 0 ? translations[0].label : opt.attributeValue.value;
            
            return {
              attributeKey: opt.attributeValue.attribute.key || undefined,
              value: opt.attributeValue.value || undefined,
              label: label || undefined,
              imageUrl: opt.attributeValue.imageUrl || undefined,
              colors: opt.attributeValue.colors || undefined,
            };
          }
          // Old format: Use attributeKey and value directly
          return {
            attributeKey: opt.attributeKey || undefined,
            value: opt.value || undefined,
          };
        }) || [];

        logger.debug('Item mapping', {
          productTitle: item.productTitle,
          variantId: item.variantId,
          hasVariant: !!item.variant,
          optionsCount: item.variant?.options?.length || 0,
          variantOptions,
        });

        return {
          variantId: item.variantId || '',
          productTitle: item.productTitle,
          variantTitle: item.variantTitle || '',
          sku: item.sku,
          quantity: item.quantity,
          price: Number(item.price),
          total: Number(item.total),
          imageUrl: item.imageUrl || undefined,
          variantOptions,
        };
      }),
      totals: {
        subtotal: Number(order.subtotal),
        discount: Number(order.discountAmount),
        shipping: Number(order.shippingAmount),
        tax: Number(order.taxAmount),
        total: Number(order.total),
        currency: order.currency,
      },
      customer: {
        email: order.customerEmail || undefined,
        phone: order.customerPhone || undefined,
      },
      shippingAddress: shippingAddress,
      shippingMethod: order.shippingMethod || 'pickup',
      trackingNumber: order.trackingNumber || undefined,
      createdAt: order.createdAt.toISOString(),
      updatedAt: order.updatedAt.toISOString(),
    };
  }
}

export const ordersService = new OrdersService();

import { db } from "@white-shop/db";
import { Prisma } from "@prisma/client";
import { adminService } from "./supersudo.service";
import { ProductWithRelations } from "./products-find-query.service";

class ProductsFiltersService {
  /**
   * Get all child category IDs recursively
   */
  private async getAllChildCategoryIds(parentId: string): Promise<string[]> {
    const children = await db.category.findMany({
      where: {
        parentId: parentId,
        published: true,
        deletedAt: null,
      },
      select: { id: true },
    });
    
    let allChildIds = children.map((c: { id: string }) => c.id);
    
    // Recursively get children of children
    for (const child of children) {
      const grandChildren = await this.getAllChildCategoryIds(child.id);
      allChildIds = [...allChildIds, ...grandChildren];
    }
    
    return allChildIds;
  }

  /**
   * Get available filters (colors and sizes)
   */
  async getFilters(filters: {
    category?: string;
    search?: string;
    minPrice?: number;
    maxPrice?: number;
    lang?: string;
  }) {
    try {
      const where: Prisma.ProductWhereInput = {
        published: true,
        deletedAt: null,
      };

      // Add search filter
      if (filters.search && filters.search.trim()) {
        where.OR = [
          {
            translations: {
              some: {
                title: {
                  contains: filters.search.trim(),
                  mode: "insensitive",
                },
              },
            },
          },
          {
            translations: {
              some: {
                subtitle: {
                  contains: filters.search.trim(),
                  mode: "insensitive",
                },
              },
            },
          },
          {
            variants: {
              some: {
                sku: {
                  contains: filters.search.trim(),
                  mode: "insensitive",
                },
              },
            },
          },
        ];
      }

      // Add category filter
      if (filters.category) {
        try {
          const categoryDoc = await db.category.findFirst({
            where: {
              translations: {
                some: {
                  slug: filters.category,
                  locale: filters.lang || "en",
                },
              },
              published: true,
              deletedAt: null,
            },
          });

          if (categoryDoc && categoryDoc.id) {
            // Get all child categories (subcategories) recursively
            const childCategoryIds = await this.getAllChildCategoryIds(categoryDoc.id);
            const allCategoryIds = [categoryDoc.id, ...childCategoryIds];

            // Build OR conditions
            const categoryConditions = allCategoryIds.flatMap((catId: string) => [
              { primaryCategoryId: catId },
              { categoryIds: { has: catId } },
            ]);
            
            if (where.OR) {
              where.AND = [
                { OR: where.OR },
                {
                  OR: categoryConditions,
                },
              ];
              delete where.OR;
            } else {
              where.OR = categoryConditions;
            }
          }
        } catch (categoryError) {
          console.error('❌ [PRODUCTS FILTERS SERVICE] Error fetching category:', categoryError);
          // Continue without category filter if there's an error
        }
      }

      // Get products with variants (capped for filter computation)
      const FILTERS_PRODUCTS_LIMIT = 500;
      let products: ProductWithRelations[] = [];
      try {
        products = (await db.product.findMany({
          where,
          take: FILTERS_PRODUCTS_LIMIT,
          include: {
            brand: {
              include: {
                translations: true,
              },
            },
            variants: {
              where: {
                published: true,
              },
              include: {
                options: {
                  include: {
                    attributeValue: {
                      include: {
                        attribute: true,
                        translations: true,
                      },
                    },
                  },
                },
              },
            },
            productAttributes: {
              include: {
                attribute: {
                  include: {
                    values: {
                      include: {
                        translations: true,
                      },
                    },
                  },
                },
              },
            },
          },
        })) as unknown as ProductWithRelations[];
      } catch (dbError) {
        console.error('❌ [PRODUCTS FILTERS SERVICE] Error fetching products in getFilters:', dbError);
        throw dbError;
      }

      // Ensure products is an array
      if (!products || !Array.isArray(products)) {
        products = [];
      }

    // Filter by price in memory
    if (filters.minPrice || filters.maxPrice) {
      const min = filters.minPrice || 0;
      const max = filters.maxPrice || Infinity;
      products = products.filter((product: ProductWithRelations) => {
        if (!product || !product.variants || !Array.isArray(product.variants)) {
          return false;
        }
        const prices = product.variants.map((v: { price?: number }) => v?.price).filter((p: number | undefined): p is number => p !== undefined);
        if (prices.length === 0) return false;
        const minPrice = Math.min(...prices);
        return minPrice >= min && minPrice <= max;
      });
    }

    // Collect colors and sizes from variants
    // Use Map with lowercase key to merge colors with different cases
    // Store both count, canonical label, imageUrl and colors hex
    const lang = filters.lang || 'en';
    const colorMap = new Map<string, { 
      count: number; 
      label: string; 
      imageUrl?: string | null; 
      colors?: string[] | null;
    }>();
    const sizeMap = new Map<string, number>();
    const brandMap = new Map<string, { id: string; name: string; count: number }>();
    let rangeMin = Infinity;
    let rangeMax = 0;

    type VariantRow = ProductWithRelations["variants"][number];
    type VariantOptionLike = VariantRow["options"][number] & {
      attributeKey?: string | null;
      key?: string | null;
      attribute?: string | null;
      value?: string | null;
      label?: string | null;
    };

    products.forEach((product: ProductWithRelations & { brand?: { id: string; translations?: Array<{ locale: string; name?: string }>; name?: string } | null }) => {
      if (!product || !product.variants || !Array.isArray(product.variants)) {
        return;
      }
      if (product.brand?.id) {
        const name = (product.brand as { translations?: Array<{ locale: string; name?: string }>; name?: string }).translations?.find((t: { locale: string }) => t.locale === lang)?.name || (product.brand as { name?: string }).name || '';
        if (name) {
          const existing = brandMap.get(product.brand.id);
          brandMap.set(product.brand.id, { id: product.brand.id, name, count: (existing?.count || 0) + 1 });
        }
      }
      product.variants.forEach((v: { price?: number }) => {
        if (typeof v?.price === 'number') {
          if (v.price < rangeMin) rangeMin = v.price;
          if (v.price > rangeMax) rangeMax = v.price;
        }
      });
      product.variants.forEach((variant: VariantRow) => {
        if (!variant || !variant.options || !Array.isArray(variant.options)) {
          return;
        }
        variant.options.forEach((option: VariantOptionLike) => {
          if (!option) return;
          
          // Check if it's a color option (support multiple formats)
          const isColor = option.attributeKey === "color" || 
                         option.key === "color" ||
                         option.attribute === "color" ||
                         (option.attributeValue && option.attributeValue.attribute?.key === "color");
          
          if (isColor) {
            let colorValue = "";
            let imageUrl: string | null | undefined = null;
            let colorsHex: string[] | null | undefined = null;
            
            // New format: Use AttributeValue if available
            if (option.attributeValue) {
              const translation = option.attributeValue.translations?.find((t: { locale: string }) => t.locale === lang) || option.attributeValue.translations?.[0];
              colorValue = translation?.label || option.attributeValue.value || "";
              imageUrl = option.attributeValue.imageUrl || null;
              const rawColorsHex = option.attributeValue.colors;
              colorsHex =
                Array.isArray(rawColorsHex) &&
                rawColorsHex.every((c): c is string => typeof c === "string")
                  ? rawColorsHex
                  : null;
            } else if (option.value) {
              // Old format: use value directly
              colorValue = option.value.trim();
            } else if (option.key === "color" || option.attribute === "color") {
              // Fallback: try to get from option itself
              colorValue = option.value || option.label || "";
            }
            
            if (colorValue) {
              const colorKey = colorValue.toLowerCase();
              const existing = colorMap.get(colorKey);
              
              // Prefer capitalized version for label (e.g., "Black" over "black")
              // If both exist, keep the one that starts with uppercase
              const preferredLabel = existing 
                ? (colorValue[0] === colorValue[0].toUpperCase() ? colorValue : existing.label)
                : colorValue;
              
              // Prefer imageUrl and colors from AttributeValue if available
              const finalImageUrl = imageUrl || existing?.imageUrl || null;
              const finalColors = colorsHex || existing?.colors || null;
              
              colorMap.set(colorKey, {
                count: (existing?.count || 0) + 1,
                label: preferredLabel,
                imageUrl: finalImageUrl,
                colors: finalColors,
              });
            }
          } else {
            // Check if it's a size option (support multiple formats)
            const isSize = option.attributeKey === "size" || 
                          option.key === "size" ||
                          option.attribute === "size" ||
                          (option.attributeValue && option.attributeValue.attribute?.key === "size");
            
            if (isSize) {
              let sizeValue = "";
              
              // New format: Use AttributeValue if available
              if (option.attributeValue) {
                const translation = option.attributeValue.translations?.find((t: { locale: string }) => t.locale === lang) || option.attributeValue.translations?.[0];
                sizeValue = translation?.label || option.attributeValue.value || "";
              } else if (option.value) {
                // Old format: use value directly
                sizeValue = option.value.trim();
              } else if (option.key === "size" || option.attribute === "size") {
                // Fallback: try to get from option itself
                sizeValue = option.value || option.label || "";
              }
              
              if (sizeValue) {
                const normalizedSize = sizeValue.trim().toUpperCase();
                sizeMap.set(normalizedSize, (sizeMap.get(normalizedSize) || 0) + 1);
              }
            }
          }
        });
      });
      
      // Also check productAttributes for color attribute values with imageUrl and colors
      if (product.productAttributes && Array.isArray(product.productAttributes)) {
        product.productAttributes.forEach((productAttr) => {
          const pa = productAttr as {
            attribute?: {
              key: string;
              values?: Array<{
                translations?: Array<{ locale: string; label?: string }>;
                value?: string;
                imageUrl?: string | null;
                colors?: string[] | null | unknown;
              }>;
            };
          };
          if (pa.attribute?.key === 'color' && pa.attribute?.values) {
            pa.attribute.values.forEach((attrValue) => {
              const translation = attrValue.translations?.find((t: { locale: string }) => t.locale === lang) || attrValue.translations?.[0];
              const colorValue = translation?.label || attrValue.value || "";
              if (colorValue) {
                const colorKey = colorValue.toLowerCase();
                const existing = colorMap.get(colorKey);
                // Update if we have imageUrl or colors hex and they're not already set
                const rawColors = attrValue.colors;
                const normalizedColors =
                  Array.isArray(rawColors) && rawColors.every((c): c is string => typeof c === "string")
                    ? rawColors
                    : null;
                if (attrValue.imageUrl || normalizedColors) {
                  colorMap.set(colorKey, {
                    count: existing?.count || 0,
                    label: existing?.label || colorValue,
                    imageUrl: attrValue.imageUrl || existing?.imageUrl || null,
                    colors: normalizedColors ?? existing?.colors ?? null,
                  });
                }
              }
            });
          }
        });
      }
    });

    // Convert maps to arrays
    const colors: Array<{ value: string; label: string; count: number; imageUrl?: string | null; colors?: string[] | null }> = Array.from(
      colorMap.entries()
    ).map(([key, data]) => ({
      value: key, // lowercase for filtering
      label: data.label, // canonical label (prefer capitalized)
      count: data.count, // merged count
      imageUrl: data.imageUrl || null,
      colors: data.colors || null,
    }));

    const sizes: Array<{ value: string; count: number }> = Array.from(
      sizeMap.entries()
    ).map(([value, count]: [string, number]) => ({
      value,
      count,
    }));

    // Sort sizes by predefined order
    const SIZE_ORDER = ['XS', 'S', 'M', 'L', 'XL', 'XXL', 'XXXL'];
    sizes.sort((a: { value: string }, b: { value: string }) => {
      const aIndex = SIZE_ORDER.indexOf(a.value);
      const bIndex = SIZE_ORDER.indexOf(b.value);
      if (aIndex !== -1 && bIndex !== -1) return aIndex - bIndex;
      if (aIndex !== -1) return -1;
      if (bIndex !== -1) return 1;
      return a.value.localeCompare(b.value);
    });

      // Sort colors alphabetically
      colors.sort((a: { label: string }, b: { label: string }) => a.label.localeCompare(b.label));

      const brands = Array.from(brandMap.values()).sort((a, b) => a.name.localeCompare(b.name));
      const priceMin = rangeMin === Infinity ? 0 : Math.floor(rangeMin / 1000) * 1000;
      const priceMax = rangeMax === 0 ? 100000 : Math.ceil(rangeMax / 1000) * 1000;
      let stepSize: number | null = null;
      let stepSizePerCurrency: Record<string, number> | null = null;
      try {
        const settings = await adminService.getPriceFilterSettings();
        stepSize = settings.stepSize ?? null;
        if (settings.stepSizePerCurrency) {
          stepSizePerCurrency = {
            USD: settings.stepSizePerCurrency.USD ?? undefined,
            AMD: settings.stepSizePerCurrency.AMD ?? undefined,
            RUB: settings.stepSizePerCurrency.RUB ?? undefined,
            GEL: settings.stepSizePerCurrency.GEL ?? undefined,
          } as Record<string, number>;
        }
      } catch {
        // use defaults
      }

      return {
        colors,
        sizes,
        brands,
        priceRange: { min: priceMin, max: priceMax, stepSize, stepSizePerCurrency },
      };
    } catch (error) {
      console.error('❌ [PRODUCTS FILTERS SERVICE] Error in getFilters:', error);
      return {
        colors: [],
        sizes: [],
        brands: [],
        priceRange: { min: 0, max: 100000, stepSize: null, stepSizePerCurrency: null },
      };
    }
  }

  /**
   * Get price range
   */
  async getPriceRange(filters: { category?: string; lang?: string }) {
    const where: Prisma.ProductWhereInput = {
      published: true,
      deletedAt: null,
    };

    if (filters.category) {
      const categoryDoc = await db.category.findFirst({
        where: {
          translations: {
            some: {
              slug: filters.category,
              locale: filters.lang || "en",
            },
          },
        },
      });

      if (categoryDoc) {
        where.OR = [
          { primaryCategoryId: categoryDoc.id },
          { categoryIds: { has: categoryDoc.id } },
        ];
      }
    }

    const products = await db.product.findMany({
      where,
      include: {
        variants: {
          where: {
            published: true,
          },
        },
      },
    });

    let minPrice = Infinity;
    let maxPrice = 0;

    products.forEach((product: { variants: Array<{ price: number }> }) => {
      if (product.variants.length > 0) {
        const prices = product.variants.map((v: { price: number }) => v.price);
        const productMin = Math.min(...prices);
        const productMax = Math.max(...prices);
        if (productMin < minPrice) minPrice = productMin;
        if (productMax > maxPrice) maxPrice = productMax;
      }
    });

    minPrice = minPrice === Infinity ? 0 : Math.floor(minPrice / 1000) * 1000;
    maxPrice = maxPrice === 0 ? 100000 : Math.ceil(maxPrice / 1000) * 1000;

    // Load price filter settings to provide optional step sizes per currency
    let stepSize: number | null = null;
    let stepSizePerCurrency: {
      USD?: number;
      AMD?: number;
      RUB?: number;
      GEL?: number;
    } | null = null;

    try {
      const settings = await adminService.getPriceFilterSettings();
      stepSize = settings.stepSize ?? null;

      if (settings.stepSizePerCurrency) {
        // stepSizePerCurrency in settings is stored in display currency units.
        // Here we pass them through to the frontend as-is; the slider logic
        // will choose the appropriate value for the active currency.
        stepSizePerCurrency = {
          USD: settings.stepSizePerCurrency.USD ?? undefined,
          AMD: settings.stepSizePerCurrency.AMD ?? undefined,
          RUB: settings.stepSizePerCurrency.RUB ?? undefined,
          GEL: settings.stepSizePerCurrency.GEL ?? undefined,
        };
      }
    } catch (error) {
      console.error('❌ [PRODUCTS FILTERS SERVICE] Error loading price filter settings for price range:', error);
    }

    return {
      min: minPrice,
      max: maxPrice,
      stepSize,
      stepSizePerCurrency,
    };
  }
}

export const productsFiltersService = new ProductsFiltersService();

import { ProductFilters, ProductWithRelations } from "./products-find-query.service";

/**
 * Normalize comma-separated filter values and drop placeholders like "undefined" or "null".
 */
const normalizeFilterList = (
  value?: string,
  transform?: (v: string) => string
): string[] => {
  if (!value || typeof value !== "string") return [];

  const invalidTokens = new Set(["undefined", "null", ""]);
  const items = value
    .split(",")
    .map((v) => v.trim())
    .filter((v) => !invalidTokens.has(v.toLowerCase()));

  if (transform) {
    return items.map(transform);
  }

  return items;
};

class ProductsFindFilterService {
  /**
   * Filter products by price, colors, sizes, brand in memory
   */
  filterProducts(
    products: ProductWithRelations[],
    filters: ProductFilters,
    bestsellerProductIds: string[]
  ): ProductWithRelations[] {
    const { minPrice, maxPrice, colors, sizes, brand } = filters;

    // Filter by price
    if (minPrice || maxPrice) {
      const min = minPrice || 0;
      const max = maxPrice || Infinity;
      products = products.filter((product: ProductWithRelations) => {
        const variants = Array.isArray(product.variants) ? product.variants : [];
        if (variants.length === 0) return false;
        const prices = variants.map((v: { price: number }) => v.price).filter((p: number | undefined) => p !== undefined);
        if (prices.length === 0) return false;
        const minPrice = Math.min(...prices);
        return minPrice >= min && minPrice <= max;
      });
    }

    // Filter by brand(s) - support multiple brands (comma-separated)
    const brandList = normalizeFilterList(brand);
    if (brandList.length > 0) {
      products = products.filter(
        (product: ProductWithRelations) => 
          product.brandId && brandList.includes(product.brandId)
      );
    }

    // Filter by colors and sizes together if both are provided.
    // Skip filtering when only placeholder values (e.g., "undefined") are passed.
    const colorList = normalizeFilterList(colors, (v) => v.toLowerCase());
    const sizeList = normalizeFilterList(sizes, (v) => v.toUpperCase());

    if (colorList.length > 0 || sizeList.length > 0) {
      products = products.filter((product: ProductWithRelations) => {
        const variants = Array.isArray(product.variants) ? product.variants : [];
        
        if (variants.length === 0) {
          return false;
        }
        
        // Find variants that match ALL specified filters
        type VariantRow = ProductWithRelations["variants"][number];
        /** Prisma option row plus legacy attributeKey/value fields */
        type VariantOptionLike = VariantRow["options"][number] & {
          attributeKey?: string | null;
          key?: string | null;
          attribute?: string | null;
          value?: string | null;
          label?: string | null;
        };

        const matchingVariants = variants.filter((variant: VariantRow) => {
          const options = Array.isArray(variant.options) ? variant.options : [];
          
          if (options.length === 0) {
            return false;
          }
          
          // Helper function to get color value from option (support all formats)
          const getColorValue = (opt: VariantOptionLike, lang: string = 'en'): string | null => {
            // New format: Use AttributeValue if available
            if (opt.attributeValue && opt.attributeValue.attribute?.key === "color") {
              const translation = opt.attributeValue.translations?.find((t: { locale: string }) => t.locale === lang) || opt.attributeValue.translations?.[0];
              return (translation?.label || opt.attributeValue.value || "").trim().toLowerCase();
            }
            // Old format: check attributeKey, key, or attribute
            if (opt.attributeKey === "color" || opt.key === "color" || opt.attribute === "color") {
              return (opt.value || opt.label || "").trim().toLowerCase();
            }
            return null;
          };
          
          // Helper function to get size value from option (support all formats)
          const getSizeValue = (opt: VariantOptionLike, lang: string = 'en'): string | null => {
            // New format: Use AttributeValue if available
            if (opt.attributeValue && opt.attributeValue.attribute?.key === "size") {
              const translation = opt.attributeValue.translations?.find((t: { locale: string }) => t.locale === lang) || opt.attributeValue.translations?.[0];
              return (translation?.label || opt.attributeValue.value || "").trim().toUpperCase();
            }
            // Old format: check attributeKey, key, or attribute
            if (opt.attributeKey === "size" || opt.key === "size" || opt.attribute === "size") {
              return (opt.value || opt.label || "").trim().toUpperCase();
            }
            return null;
          };
          
          // Check color match if colors filter is provided
          if (colorList.length > 0) {
            let colorMatched = false;
            for (const opt of options) {
              const variantColorValue = getColorValue(opt, filters.lang || 'en');
              if (variantColorValue && colorList.includes(variantColorValue)) {
                colorMatched = true;
                break;
              }
            }
            if (!colorMatched) {
              return false;
            }
          }
          
          // Check size match if sizes filter is provided
          if (sizeList.length > 0) {
            let sizeMatched = false;
            for (const opt of options) {
              const variantSizeValue = getSizeValue(opt, filters.lang || 'en');
              if (variantSizeValue && sizeList.includes(variantSizeValue)) {
                sizeMatched = true;
                break;
              }
            }
            if (!sizeMatched) {
              return false;
            }
          }
          
          return true;
        });
        
        const hasMatch = matchingVariants.length > 0;
        return hasMatch;
      });
    }

    // Sort
    const { filter, sort = "createdAt" } = filters;
    if (filter === "bestseller" && bestsellerProductIds.length > 0) {
      const rank = new Map<string, number>();
      bestsellerProductIds.forEach((id, index) => rank.set(id, index));
      products.sort((a: ProductWithRelations, b: ProductWithRelations) => {
        const aRank = rank.get(a.id) ?? Number.MAX_SAFE_INTEGER;
        const bRank = rank.get(b.id) ?? Number.MAX_SAFE_INTEGER;
        return aRank - bRank;
      });
    } else if (sort === "price") {
      products.sort((a: ProductWithRelations, b: ProductWithRelations) => {
        const aVariants = Array.isArray(a.variants) ? a.variants : [];
        const bVariants = Array.isArray(b.variants) ? b.variants : [];
        const aPrice = aVariants.length > 0 ? Math.min(...aVariants.map((v: { price: number }) => v.price)) : 0;
        const bPrice = bVariants.length > 0 ? Math.min(...bVariants.map((v: { price: number }) => v.price)) : 0;
        return bPrice - aPrice;
      });
    } else {
      products.sort((a: ProductWithRelations, b: ProductWithRelations) => {
        const aValue = a[sort as keyof typeof a] as Date;
        const bValue = b[sort as keyof typeof b] as Date;
        return new Date(bValue).getTime() - new Date(aValue).getTime();
      });
    }

    return products;
  }
}

export const productsFindFilterService = new ProductsFindFilterService();

import { Prisma } from "@prisma/client";
import { db } from "@white-shop/db";
import { logger } from "../../utils/logger";
import type { ProductFilters } from "./types";
import { getAllChildCategoryIds, findCategoryBySlug } from "./category-utils";

/**
 * Build search filter for where clause
 */
function buildSearchFilter(search: string): Prisma.ProductWhereInput {
  return {
    OR: [
      {
        translations: {
          some: {
            title: {
              contains: search.trim(),
              mode: "insensitive",
            },
          },
        },
      },
      {
        translations: {
          some: {
            subtitle: {
              contains: search.trim(),
              mode: "insensitive",
            },
          },
        },
      },
      {
        variants: {
          some: {
            sku: {
              contains: search.trim(),
              mode: "insensitive",
            },
          },
        },
      },
    ],
  };
}

/**
 * Build category filter for where clause
 */
async function buildCategoryFilter(
  category: string,
  lang: string,
  existingWhere: Prisma.ProductWhereInput
): Promise<Prisma.ProductWhereInput | null> {
  const categoryDoc = await findCategoryBySlug(category, lang);

  if (!categoryDoc) {
    return null; // Category not found - return null to indicate empty result
  }

  // Get all child categories (subcategories) recursively
  const childCategoryIds = await getAllChildCategoryIds(categoryDoc.id);
  const allCategoryIds = [categoryDoc.id, ...childCategoryIds];
  
  logger.debug('Category IDs to include', {
    parent: categoryDoc.id,
    children: childCategoryIds,
    total: allCategoryIds.length
  });
  
  // Build OR conditions for all categories (parent + children)
  const categoryConditions = allCategoryIds.flatMap((catId: string) => [
    { primaryCategoryId: catId },
    { categoryIds: { has: catId } },
  ]);
  
  if (existingWhere.OR) {
    return {
      AND: [
        { OR: existingWhere.OR },
        {
          OR: categoryConditions,
        },
      ],
    };
  }
  
  return {
    OR: categoryConditions,
  };
}

/**
 * Build filter for new, featured, bestseller
 */
async function buildFilterFilter(
  filter: string,
  existingWhere: Prisma.ProductWhereInput
): Promise<{
  where: Prisma.ProductWhereInput;
  bestsellerProductIds: string[];
}> {
  const bestsellerProductIds: string[] = [];

  if (filter === "new") {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    return {
      where: {
        ...existingWhere,
        createdAt: { gte: thirtyDaysAgo },
      },
      bestsellerProductIds,
    };
  }

  if (filter === "featured") {
    return {
      where: {
        ...existingWhere,
        featured: true,
      },
      bestsellerProductIds,
    };
  }

  if (filter === "bestseller") {
    type BestsellerVariant = { variantId: string | null; _sum: { quantity: number | null } };
    const raw = await db.orderItem.groupBy({
      by: ["variantId"],
      _sum: { quantity: true },
      where: {
        variantId: {
          not: null,
        },
      },
      orderBy: {
        _sum: {
          quantity: "desc" as const,
        },
      },
      take: 200,
    });
    const bestsellerVariants: BestsellerVariant[] = raw as BestsellerVariant[];

    const variantIds = bestsellerVariants
      .map((item) => item.variantId)
      .filter((id): id is string => Boolean(id));

    if (variantIds.length > 0) {
      const variantProductMap = await db.productVariant.findMany({
        where: { id: { in: variantIds } },
        select: { id: true, productId: true },
      });

      const variantToProduct = new Map<string, string>();
      variantProductMap.forEach(({ id, productId }: { id: string; productId: string }) => {
        variantToProduct.set(id, productId);
      });

      const productSales = new Map<string, number>();
      bestsellerVariants.forEach((item: BestsellerVariant) => {
        const variantId = item.variantId;
        if (!variantId) return;
        const productId = variantToProduct.get(variantId);
        if (!productId) return;
        const qty = item._sum?.quantity || 0;
        productSales.set(productId, (productSales.get(productId) || 0) + qty);
      });

      bestsellerProductIds.push(
        ...Array.from(productSales.entries())
          .sort((a, b) => (b[1] || 0) - (a[1] || 0))
          .map(([productId]) => productId)
      );

      if (bestsellerProductIds.length > 0) {
        return {
          where: {
            ...existingWhere,
            id: {
              in: bestsellerProductIds,
            },
          },
          bestsellerProductIds,
        };
      }
    }
  }

  return {
    where: existingWhere,
    bestsellerProductIds,
  };
}

/**
 * Build where clause for product query
 */
export async function buildWhereClause(
  filters: ProductFilters
): Promise<{
  where: Prisma.ProductWhereInput | null;
  bestsellerProductIds: string[];
}> {
  const {
    category,
    search,
    filter,
    lang = "en",
  } = filters;

  const bestsellerProductIds: string[] = [];

  // Build base where clause
  let where: Prisma.ProductWhereInput = {
    published: true,
    deletedAt: null,
  };

  // Add search filter
  if (search && search.trim()) {
    const searchFilter = buildSearchFilter(search);
    where = { ...where, ...searchFilter };
  }

  // Add category filter
  if (category) {
    const categoryWhere = await buildCategoryFilter(category, lang, where);
    if (categoryWhere === null) {
      // Category not found - return empty result
      return {
        where: null,
        bestsellerProductIds: [],
      };
    }
    where = { ...where, ...categoryWhere };
  }

  // Add filter for new, featured, bestseller
  const filterResult = await buildFilterFilter(filter || "", where);
  where = filterResult.where;
  bestsellerProductIds.push(...filterResult.bestsellerProductIds);

  return {
    where,
    bestsellerProductIds,
  };
}

import { db } from "@white-shop/db";
import { processImageUrl } from "../utils/image-utils";
import { translations } from "../translations";
import { ProductWithRelations } from "./products-find-query.service";

/**
 * Get "Out of Stock" translation for a given language
 */
const getOutOfStockLabel = (lang: string = "en"): string => {
  const langKey = lang as keyof typeof translations;
  const translation = translations[langKey] || translations.en;
  return translation.stock.outOfStock;
};

class ProductsFindTransformService {
  /**
   * Transform products to response format
   */
  async transformProducts(
    products: ProductWithRelations[],
    lang: string = "en"
  ): Promise<unknown[]> {
    // Get discount settings
    const discountSettings = await db.settings.findMany({
      where: {
        key: {
          in: ["globalDiscount", "categoryDiscounts", "brandDiscounts"],
        },
      },
    });

    const globalDiscount =
      Number(
        discountSettings.find((s: { key: string; value: unknown }) => s.key === "globalDiscount")?.value
      ) || 0;
    
    const categoryDiscountsSetting = discountSettings.find((s: { key: string; value: unknown }) => s.key === "categoryDiscounts");
    const categoryDiscounts = categoryDiscountsSetting ? (categoryDiscountsSetting.value as Record<string, number>) || {} : {};
    
    const brandDiscountsSetting = discountSettings.find((s: { key: string; value: unknown }) => s.key === "brandDiscounts");
    const brandDiscounts = brandDiscountsSetting ? (brandDiscountsSetting.value as Record<string, number>) || {} : {};

    // Format response
    const data = products.map((product: ProductWithRelations) => {
      // Безопасное получение translation с проверкой на существование массива
      const translations = Array.isArray(product.translations) ? product.translations : [];
      const translation = translations.find((t: { locale: string }) => t.locale === lang) || translations[0] || null;
      
      // Безопасное получение brand translation
      const brandTranslations = product.brand && Array.isArray(product.brand.translations)
        ? product.brand.translations
        : [];
      const brandTranslation = brandTranslations.length > 0
        ? brandTranslations.find((t: { locale: string }) => t.locale === lang) || brandTranslations[0]
        : null;
      
      // Безопасное получение variant
      const variants = Array.isArray(product.variants) ? product.variants : [];
      const variant = variants.length > 0
        ? variants.sort((a: { price: number }, b: { price: number }) => a.price - b.price)[0]
        : null;

      // Get all unique colors from ALL variants with imageUrl and colors hex (support both new and old format)
      // IMPORTANT: Only collect colors that actually exist in variants
      // IMPORTANT: Process ALL variants to get ALL colors, not just the first variant
      const colorMap = new Map<string, { value: string; imageUrl?: string | null; colors?: string[] | null }>();
      
      
      // Process all variants to collect all unique colors
      variants.forEach((v) => {
        // First, try to get ALL color options from variant.options (not just the first one)
        const options = Array.isArray(v.options) ? v.options : [];
        const colorOptions = options.filter((opt: ProductWithRelations['variants'][number]['options'][number]) => {
          // Support both new format (AttributeValue) and old format (attributeKey/value)
          if ('attributeValue' in opt && opt.attributeValue) {
            return opt.attributeValue.attribute?.key === "color";
          }
          return opt.attributeKey === "color";
        });
        
        // Process all color options from this variant
        colorOptions.forEach((colorOption: ProductWithRelations['variants'][number]['options'][number]) => {
          let colorValue = "";
          let imageUrl: string | null | undefined = null;
          let colorsHex: string[] | null | undefined = null;
          
          if ('attributeValue' in colorOption && colorOption.attributeValue) {
            // New format: get from translation or value
            const translation = colorOption.attributeValue.translations?.find((t: { locale: string }) => t.locale === lang) || colorOption.attributeValue.translations?.[0];
            colorValue = translation?.label || colorOption.attributeValue.value || "";
            // Get imageUrl and colors from AttributeValue
            imageUrl = colorOption.attributeValue.imageUrl || null;
            const colorsValue = colorOption.attributeValue.colors;
            colorsHex = Array.isArray(colorsValue) && colorsValue.every((c): c is string => typeof c === 'string') ? colorsValue : null;
          } else {
            // Old format: use value directly
            colorValue = colorOption.value || "";
          }
          
          if (colorValue) {
            const normalizedValue = colorValue.trim().toLowerCase();
            // Store color with imageUrl and colors hex if not already stored or if we have better data
            if (!colorMap.has(normalizedValue) || (imageUrl && !colorMap.get(normalizedValue)?.imageUrl)) {
              colorMap.set(normalizedValue, {
                value: colorValue.trim(),
                imageUrl: imageUrl || null,
                colors: colorsHex || null,
              });
            }
          }
        });
        
        // Fallback: check variant.attributes JSONB column if options don't have color
        // This handles cases where colors are stored in JSONB but not in options
        if (colorOptions.length === 0 && v.attributes && typeof v.attributes === 'object' && !Array.isArray(v.attributes) && 'color' in v.attributes) {
          const colorAttr = (v.attributes as { color?: unknown }).color;
          const colorAttributes = Array.isArray(colorAttr) ? colorAttr : colorAttr ? [colorAttr] : [];
          colorAttributes.forEach((colorAttrItem: unknown) => {
            const colorValue = (colorAttrItem && typeof colorAttrItem === 'object' && 'value' in colorAttrItem) 
              ? (colorAttrItem as { value?: unknown }).value 
              : colorAttrItem;
            if (colorValue && typeof colorValue === 'string') {
              const normalizedValue = colorValue.trim().toLowerCase();
              // Only add if not already in colorMap
              if (!colorMap.has(normalizedValue)) {
                colorMap.set(normalizedValue, {
                  value: colorValue.trim(),
                  imageUrl: null,
                  colors: null,
                });
              }
            }
          });
        }
      });
      
      
      // Also check productAttributes for color attribute values with imageUrl and colors
      // IMPORTANT: Only update colors that already exist in variants (already in colorMap)
      // Do not add new colors that don't exist in variants
      const productAttrs = product && 'productAttributes' in product && Array.isArray(product.productAttributes) ? product.productAttributes : [];
      if (productAttrs.length > 0) {
        productAttrs.forEach((productAttr) => {
          const row = productAttr as NonNullable<ProductWithRelations["productAttributes"]>[number] & {
            attribute?: {
              key: string;
              values?: Array<{
                translations?: Array<{ locale: string; label?: string }>;
                value?: string;
                imageUrl?: string | null;
                colors?: string[] | null;
              }>;
            };
          };
          const attr = row.attribute;
          if (attr && typeof attr === 'object' && 'key' in attr && attr.key === 'color' && 'values' in attr && Array.isArray(attr.values)) {
            attr.values.forEach((attrValue: { translations?: Array<{ locale: string; label?: string }>; value?: string; imageUrl?: string | null; colors?: string[] | null }) => {
              const translation = attrValue.translations?.find((t: { locale: string }) => t.locale === lang) || attrValue.translations?.[0];
              const colorValue = translation?.label || attrValue.value || "";
              if (colorValue) {
                const normalizedValue = colorValue.trim().toLowerCase();
                // Only update if color already exists in colorMap (i.e., exists in variants)
                // This ensures we only show colors that actually exist in product variants
                if (colorMap.has(normalizedValue)) {
                  const existing = colorMap.get(normalizedValue);
                  // Update with imageUrl and colors hex from productAttributes if available
                  if (attrValue.imageUrl || attrValue.colors) {
                    colorMap.set(normalizedValue, {
                      value: colorValue.trim(),
                      imageUrl: attrValue.imageUrl || existing?.imageUrl || null,
                      colors: attrValue.colors || existing?.colors || null,
                    });
                  }
                }
              }
            });
          }
        });
      }
      
      const availableColors = Array.from(colorMap.values());

      const originalPrice = variant?.price || 0;
      let finalPrice = originalPrice;
      const productDiscount = product.discountPercent || 0;
      
      // Calculate applied discount with priority: productDiscount > categoryDiscount > brandDiscount > globalDiscount
      let appliedDiscount = 0;
      if (productDiscount > 0) {
        appliedDiscount = productDiscount;
      } else {
        // Check category discounts
        const primaryCategoryId = product.primaryCategoryId;
        if (primaryCategoryId && categoryDiscounts[primaryCategoryId]) {
          appliedDiscount = categoryDiscounts[primaryCategoryId];
        } else {
          // Check brand discounts
          const brandId = product.brandId;
          if (brandId && brandDiscounts[brandId]) {
            appliedDiscount = brandDiscounts[brandId];
          } else if (globalDiscount > 0) {
            appliedDiscount = globalDiscount;
          }
        }
      }

      if (appliedDiscount > 0 && originalPrice > 0) {
        finalPrice = originalPrice * (1 - appliedDiscount / 100);
      }

      // Get categories with translations
      const categories = Array.isArray(product.categories) ? product.categories.map((cat: { id: string; translations?: Array<{ locale: string; slug: string; title: string }> }) => {
        const catTranslations = Array.isArray(cat.translations) ? cat.translations : [];
        const catTranslation = catTranslations.find((t: { locale: string }) => t.locale === lang) || catTranslations[0] || null;
        return {
          id: cat.id,
          slug: catTranslation?.slug || "",
          title: catTranslation?.title || "",
        };
      }) : [];

      return {
        id: product.id,
        slug: translation?.slug || "",
        title: translation?.title || "",
        defaultVariantId: variant?.id ?? null,
        brand: product.brand
          ? {
              id: product.brand.id,
              name: brandTranslation?.name || "",
            }
          : null,
        categories,
        price: finalPrice,
        originalPrice: appliedDiscount > 0 ? originalPrice : variant?.compareAtPrice || null,
        compareAtPrice: variant?.compareAtPrice || null,
        discountPercent: appliedDiscount > 0 ? appliedDiscount : null,
        image: (() => {
          // Use unified image utilities to get first valid main image
          if (!Array.isArray(product.media) || product.media.length === 0) {
            return null;
          }
          
          // Process first image - cast JsonValue to ImageUrlInput
          const firstImage = processImageUrl(product.media[0] as string | null | undefined | { url?: string; src?: string; value?: string });
          return firstImage || null;
        })(),
        inStock: (variant?.stock || 0) > 0,
        labels: (() => {
          // Map existing labels
          const existingLabels = Array.isArray(product.labels) ? product.labels.map((label: { id: string; type: string; value: string; position: string; color: string | null }) => ({
            id: label.id,
            type: label.type,
            value: label.value,
            position: label.position,
            color: label.color,
          })) : [];
          
          // Check if product is out of stock
          const isOutOfStock = (variant?.stock || 0) <= 0;
          
          // If out of stock, add "Out of Stock" label
          if (isOutOfStock) {
            // Check if "Out of Stock" label already exists
            const outOfStockText = getOutOfStockLabel(lang);
            const hasOutOfStockLabel = existingLabels.some(
              (label) => label.value.toLowerCase() === outOfStockText.toLowerCase() ||
                         label.value.toLowerCase().includes('out of stock') ||
                         label.value.toLowerCase().includes('արտադրված') ||
                         label.value.toLowerCase().includes('нет в наличии') ||
                         label.value.toLowerCase().includes('არ არის მარაგში')
            );
            
            if (!hasOutOfStockLabel) {
              // Check if top-left position is available, otherwise use top-right
              const topLeftOccupied = existingLabels.some((l) => l.position === 'top-left');
              const position = topLeftOccupied ? 'top-right' : 'top-left';
              
              existingLabels.push({
                id: `out-of-stock-${product.id}`,
                type: 'text',
                value: outOfStockText,
                position: position as 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right',
                color: '#6B7280', // Gray color for out of stock
              });
              
            }
          }
          
          return existingLabels;
        })(),
        colors: availableColors, // Add available colors array
      };
    });

    return data;
  }
}

export const productsFindTransformService = new ProductsFindTransformService();

import { db } from "@white-shop/db";
import { Prisma } from "@prisma/client";
import { ensureProductReviewsTable } from "../utils/db-ensure";

type ProductReviewWithUser = Prisma.ProductReviewGetPayload<{
  include: {
    user: {
      select: {
        id: true;
        firstName: true;
        lastName: true;
        email: true;
      };
    };
  };
}>;

type ReviewWithRating = { rating: number };

class ReviewsService {
  /**
   * Get all reviews for a product
   * @param productId - Product ID
   * @param options - Query options (published only, sorting, etc.)
   */
  async getProductReviews(productId: string, options?: { publishedOnly?: boolean }) {
    // Ensure table exists before querying
    await ensureProductReviewsTable();
    
    console.log('📝 [REVIEWS SERVICE] Getting reviews for product:', productId);
    
    const where: Prisma.ProductReviewWhereInput = {
      productId,
    };

    // Filter by published status if needed
    if (options?.publishedOnly !== false) {
      where.published = true;
    }

    const reviews = await db.productReview.findMany({
      where,
      include: {
        user: {
          select: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
          },
        },
      },
      orderBy: {
        createdAt: 'desc',
      },
    });

    console.log(`✅ [REVIEWS SERVICE] Found ${reviews.length} reviews for product ${productId}`);

    // Format response to match frontend expectations
    return reviews.map((review: ProductReviewWithUser) => ({
      id: review.id,
      userId: review.userId,
      userName: review.user.firstName && review.user.lastName
        ? `${review.user.firstName} ${review.user.lastName}`
        : review.user.firstName || review.user.lastName || review.user.email || 'Anonymous',
      rating: review.rating,
      comment: review.comment || '',
      createdAt: review.createdAt.toISOString(),
      published: review.published,
    }));
  }

  /**
   * Get user's review for a specific product
   * @param productId - Product ID
   * @param userId - User ID
   * @param includeUnpublished - Whether to include unpublished reviews (default: true)
   */
  async getUserReview(productId: string, userId: string, includeUnpublished: boolean = true) {
    // Ensure table exists before querying
    await ensureProductReviewsTable();
    
    console.log('📝 [REVIEWS SERVICE] Getting user review:', { productId, userId });

    const review = await db.productReview.findUnique({
      where: {
        productId_userId: {
          productId,
          userId,
        },
      },
      include: {
        user: {
          select: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
          },
        },
      },
    });

    if (!review) {
      console.log('📝 [REVIEWS SERVICE] No review found for user');
      return null;
    }

    // If includeUnpublished is false, only return published reviews
    if (!includeUnpublished && !review.published) {
      console.log('📝 [REVIEWS SERVICE] Review exists but is not published');
      return null;
    }

    console.log('✅ [REVIEWS SERVICE] Found user review:', review.id);

    // Format response to match frontend expectations
    return {
      id: review.id,
      userId: review.userId,
      userName: review.user.firstName && review.user.lastName
        ? `${review.user.firstName} ${review.user.lastName}`
        : review.user.firstName || review.user.lastName || review.user.email || 'Anonymous',
      rating: review.rating,
      comment: review.comment || '',
      createdAt: review.createdAt.toISOString(),
      published: review.published,
    };
  }

  /**
   * Get review statistics for a product
   * @param productId - Product ID
   */
  async getProductReviewStats(productId: string) {
    // Ensure table exists before querying
    await ensureProductReviewsTable();
    
    const reviews = await db.productReview.findMany({
      where: {
        productId,
        published: true,
      },
      select: {
        rating: true,
      },
    });

    const total = reviews.length;
    const average = total > 0
      ? reviews.reduce((sum: number, r: ReviewWithRating) => sum + r.rating, 0) / total
      : 0;

    const distribution = [5, 4, 3, 2, 1].map((star) => ({
      star,
      count: reviews.filter((r: ReviewWithRating) => r.rating === star).length,
      percentage: total > 0
        ? (reviews.filter((r: ReviewWithRating) => r.rating === star).length / total) * 100
        : 0,
    }));

    return {
      total,
      average: Number(average.toFixed(1)),
      distribution,
    };
  }

  /**
   * Create a new review for a product
   * @param productId - Product ID
   * @param userId - User ID
   * @param data - Review data (rating, comment)
   */
  async createReview(productId: string, userId: string, data: { rating: number; comment?: string }) {
    // Ensure table exists before creating review
    await ensureProductReviewsTable();
    
    console.log('📝 [REVIEWS SERVICE] Creating review:', { productId, userId, rating: data.rating });

    // Validate rating
    if (!data.rating || data.rating < 1 || data.rating > 5) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation Error",
        detail: "Rating must be between 1 and 5",
      };
    }

    // Check if product exists
    const product = await db.product.findUnique({
      where: { id: productId },
      select: { id: true },
    });

    if (!product) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Product not found",
        detail: `Product with ID ${productId} does not exist`,
      };
    }

    // Check if user already reviewed this product
    const existingReview = await db.productReview.findUnique({
      where: {
        productId_userId: {
          productId,
          userId,
        },
      },
    });

    if (existingReview) {
      throw {
        status: 409,
        type: "https://api.shop.am/problems/conflict",
        title: "Review already exists",
        detail: "You have already reviewed this product. You can update your existing review.",
      };
    }

    // Create review
    const review = await db.productReview.create({
      data: {
        productId,
        userId,
        rating: data.rating,
        comment: data.comment?.trim() || null,
        published: true,
      },
      include: {
        user: {
          select: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
          },
        },
      },
    });

    console.log('✅ [REVIEWS SERVICE] Review created:', review.id);

    // Format response
    return {
      id: review.id,
      userId: review.userId,
      userName: review.user.firstName && review.user.lastName
        ? `${review.user.firstName} ${review.user.lastName}`
        : review.user.firstName || review.user.lastName || review.user.email || 'Anonymous',
      rating: review.rating,
      comment: review.comment || '',
      createdAt: review.createdAt.toISOString(),
      published: review.published,
    };
  }

  /**
   * Update an existing review
   * @param reviewId - Review ID
   * @param userId - User ID (to verify ownership)
   * @param data - Updated review data
   */
  async updateReview(reviewId: string, userId: string, data: { rating?: number; comment?: string }) {
    // Ensure table exists before updating
    await ensureProductReviewsTable();
    
    // Find review and verify ownership
    const review = await db.productReview.findUnique({
      where: { id: reviewId },
    });

    if (!review) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Review not found",
      };
    }

    if (review.userId !== userId) {
      throw {
        status: 403,
        type: "https://api.shop.am/problems/forbidden",
        title: "Forbidden",
        detail: "You can only update your own reviews",
      };
    }

    // Validate rating if provided
    if (data.rating !== undefined && (data.rating < 1 || data.rating > 5)) {
      throw {
        status: 400,
        type: "https://api.shop.am/problems/validation-error",
        title: "Validation Error",
        detail: "Rating must be between 1 and 5",
      };
    }

    // Update review
    const updated = await db.productReview.update({
      where: { id: reviewId },
      data: {
        rating: data.rating,
        comment: data.comment?.trim() || null,
      },
      include: {
        user: {
          select: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
          },
        },
      },
    });

    return {
      id: updated.id,
      userId: updated.userId,
      userName: updated.user.firstName && updated.user.lastName
        ? `${updated.user.firstName} ${updated.user.lastName}`
        : updated.user.firstName || updated.user.lastName || updated.user.email || 'Anonymous',
      rating: updated.rating,
      comment: updated.comment || '',
      createdAt: updated.createdAt.toISOString(),
      published: updated.published,
    };
  }

  /**
   * Delete a review
   * @param reviewId - Review ID
   * @param userId - User ID (to verify ownership)
   */
  async deleteReview(reviewId: string, userId: string) {
    // Ensure table exists before deleting
    await ensureProductReviewsTable();
    
    // Find review and verify ownership
    const review = await db.productReview.findUnique({
      where: { id: reviewId },
    });

    if (!review) {
      throw {
        status: 404,
        type: "https://api.shop.am/problems/not-found",
        title: "Review not found",
      };
    }

    if (review.userId !== userId) {
      throw {
        status: 403,
        type: "https://api.shop.am/problems/forbidden",
        title: "Forbidden",
        detail: "You can only delete your own reviews",
      };
    }

    await db.productReview.delete({
      where: { id: reviewId },
    });

    return { success: true };
  }
}

